INSERT INTO `avis` (`id`, `id_utilisateur`, `id_livre`, `note`, `commentaire`, `date_avis`, `spoiler`) VALUES
(2, 2, 1, 5, 'Un livre magique qui nous plonge dans un univers fantastique incroyable. La chambre des secrets est encore plus mystérieuse que le premier tome, j\'adore !', '2024-11-15 14:23:00', 0),
(3, 3, 1, 4, 'Très bon tome, l\'intrigue est bien ficelée et les personnages attachants. Le basilic m\'a donné des frissons !', '2024-12-03 09:45:00', 0),
(4, 4, 1, 5, 'Je relis cette saga pour la troisième fois et je ne m\'en lasse pas. Rowling est un génie de la narration.', '2025-01-20 18:10:00', 0),
(5, 2, 2, 5, 'Mon tome préféré de toute la saga ! Sirius Black est un personnage absolument fascinant et le retournement final est époustouflant.', '2024-10-08 11:30:00', 0),
(6, 5, 2, 5, 'Le meilleur Harry Potter sans hésitation. L\'introduction des Détraqueurs est géniale, l\'atmosphère est parfaite.', '2024-11-22 16:55:00', 0),
(7, 6, 2, 4, 'Excellent tome, plus sombre et plus mature que les précédents. La révélation sur Lupin et Sirius est incroyable.', '2025-02-14 20:00:00', 0),
(8, 3, 3, 5, 'Le Tournoi des Trois Sorciers est haletant du début à la fin. La mort de Cedric m\'a brisé le cœur la première fois.', '2024-09-30 13:20:00', 0),
(9, 7, 3, 4, 'Un tome plus long mais tellement riche. Les épreuves du tournoi sont spectaculaires et la fin est bouleversante.', '2025-01-05 10:15:00', 0),
(10, 8, 3, 5, 'Impossible de poser ce livre une fois commencé. Le retour de Voldemort donne des frissons !', '2025-03-01 21:30:00', 0),
(11, 4, 4, 4, 'Un tome dense et parfois frustrant avec Harry en colère, mais tellement important pour la saga. Dolores Ombrage est le pire personnage jamais écrit !', '2024-08-17 15:40:00', 0),
(12, 5, 4, 5, 'Ombrage est tellement détestable qu\'on adore la détester. Ce tome est crucial pour comprendre la suite.', '2025-02-28 09:00:00', 0),
(13, 6, 4, 3, 'Bon tome mais trop long par moments. La mort de Sirius est un choc énorme. Je pleure encore.', '2025-03-10 19:45:00', 0),
(14, 2, 5, 5, 'Le tome le plus émouvant de la saga. Les révélations sur le passé de Voldemort sont fascinantes et la fin est dévastatrice.', '2024-07-22 12:00:00', 0),
(15, 7, 5, 5, 'Dumbledore... je ne m\'en remets toujours pas. Un tome magistral qui prépare parfaitement le final.', '2024-12-19 17:30:00', 0),
(16, 8, 5, 4, 'Les cours particuliers avec Dumbledore sont captivants. Snape est décidément un personnage complexe et brillant.', '2025-01-30 14:20:00', 0),
(17, 3, 6, 5, 'Une conclusion parfaite pour cette saga extraordinaire. J\'ai pleuré pendant toute la bataille de Poudlard. Merci J.K. Rowling !', '2024-06-15 23:00:00', 0),
(18, 4, 6, 5, 'Le meilleur final qu\'une saga puisse avoir. Chaque personnage a son moment de gloire. Indescriptible.', '2024-10-31 22:15:00', 0),
(19, 5, 6, 4, 'Épique et émouvant. Quelques longueurs pendant la chasse aux Horcruxes mais la fin vaut chaque page.', '2025-02-07 16:00:00', 0),
(20, 6, 7, 5, 'L\'œuvre fantasy ultime. Tolkien a créé un univers d\'une richesse et d\'une cohérence absolument incroyables. Un monument de la littérature.', '2024-05-20 11:00:00', 0),
(21, 2, 7, 4, 'La mise en place est un peu lente au début mais une fois qu\'on est dans l\'histoire, impossible de s\'arrêter.', '2024-09-12 14:30:00', 0),
(22, 8, 7, 5, 'Je comprends pourquoi ce livre a révolutionné la fantasy. La profondeur du monde créé par Tolkien est sans égal.', '2025-01-15 20:45:00', 0),
(23, 3, 8, 5, 'Gollum est l\'un des personnages les plus complexes et fascinants de toute la littérature. Ce tome est brillant.', '2024-04-08 10:20:00', 0),
(24, 7, 8, 4, 'La bataille du Gouffre de Helm est épique ! Tolkien excelle dans les scènes de bataille et les descriptions.', '2024-11-03 18:00:00', 0),
(25, 4, 9, 5, 'Un final absolument grandiose. La destruction de l\'Anneau et le retour au Comté m\'ont ému aux larmes.', '2024-03-25 21:00:00', 0),
(26, 6, 9, 5, 'Tolkien signe une conclusion épique et poignante. Les adieux sont déchirants. Une saga qui restera pour toujours.', '2024-08-30 19:30:00', 0),
(27, 8, 9, 4, 'Magnifique conclusion, même si certains passages sont très denses. Le voyage aux Havres Gris est sublime.', '2025-02-20 16:15:00', 0),
(28, 5, 10, 5, 'Un conte d\'aventure parfait, plus léger que le Seigneur des Anneaux mais tout aussi magique. Idéal pour découvrir Tolkien.', '2024-02-14 13:45:00', 0),
(29, 2, 10, 5, 'Bilbon est un héros attachant et drôle. L\'énigme entre Bilbon et Gollum est un moment de pure magie littéraire.', '2024-07-04 11:20:00', 0),
(30, 3, 10, 4, 'Un livre qu\'on peut lire à tout âge. L\'aventure est palpitante et l\'univers déjà très riche. Smaug est terrifiant !', '2025-03-05 09:30:00', 0),
(31, 7, 11, 5, 'Le chef-d\'œuvre absolu de la science-fiction. Herbert a créé un univers politique, écologique et mystique d\'une profondeur vertigineuse.', '2024-01-30 20:00:00', 0),
(32, 4, 11, 4, 'Complexe et dense, il faut s\'accrocher au début mais l\'investissement en vaut largement la peine. Paul Atréides est un héros fascinant.', '2024-06-22 15:30:00', 0),
(33, 8, 11, 5, 'Je n\'avais jamais lu de SF avant Dune et ce livre m\'a converti. Une épopée absolument magistrale sur tous les plans.', '2025-01-10 18:45:00', 0),
(34, 2, 15, 5, 'Une des meilleures fables politiques jamais écrites.', '2026-04-03 14:46:40', 0),
(35, 2, 1, 5, 'Un livre absolument magistral ! La révélation finale m\'a complètement soufflée : Tom Jedusor est en réalité le jeune Voldemort, et le journal était un Horcruxe ! Je n\'avais pas vu venir que c\'était Ginny qui écrivait dans le journal sous l\'emprise de la mémoire de Voldemort. La scène finale dans la chambre avec le basilic et Fawkes qui arrive pour sauver Harry est épique. Ron et Harry sont des héros incroyables !', '2025-03-15 14:30:00', 1),
(36, 2, 12, 5, 'Un chef-d\'œuvre absolu de la science-fiction ! Asimov a créé quelque chose d\'unique avec la psychohistoire. La façon dont chaque crise est résolue par la sagesse posthume de Seldon est brillante.', '2025-01-10 14:00:00', 0),
(37, 3, 12, 4, 'Fascinant mais parfois difficile à suivre avec tous les personnages et les sauts temporels. Une fois qu\'on est dedans c\'est impossible de s\'arrêter.', '2025-02-15 16:30:00', 0),
(38, 4, 12, 5, 'La Première Crise est résolue de façon magistrale — Seldon avait tout prévu depuis le début, même les détails en apparence insignifiants. C\'est vertigineux !', '2025-03-01 11:00:00', 1),
(39, 5, 13, 5, 'Un roman d\'une pertinence terrifiante. On reconnaît tellement de choses de notre société actuelle dans ce monde du bonheur forcé. Huxley était vraiment visionnaire.', '2025-01-20 10:00:00', 0),
(40, 6, 13, 4, 'Plus subtil et plus dérangeant que 1984 à mon sens. Le fait que les gens soient heureux de leur servitude est bien plus inquiétant qu\'une tyrannie violente.', '2025-02-28 14:00:00', 0),
(41, 7, 13, 3, 'La fin de John le Sauvage m\'a complètement brisé. Il ne pouvait pas survivre dans ce monde qui n\'avait pas de place pour la vraie humanité. Magnifique et dévastateur.', '2025-03-10 18:00:00', 1),
(42, 2, 15, 5, 'Court, simple en apparence, mais d\'une profondeur politique incroyable. Chaque personnage représente quelque chose de précis dans l\'histoire soviétique. À lire absolument.', '2025-01-05 09:00:00', 0),
(43, 8, 15, 5, 'La scène où les commandements sont modifiés progressivement est glaçante. Orwell montre avec une précision chirurgicale comment une révolution se retourne contre ses idéaux.', '2025-02-10 15:00:00', 0),
(44, 3, 15, 4, 'La mort de Boule de Neige chassé par les chiens de Napoléon représente l\'élimination de Trotski par Staline. Et Boxer, le cheval loyal envoyé à l\'équarrisseur, représente le peuple trahi. Déchirant.', '2025-03-15 20:00:00', 1),
(45, 4, 17, 5, 'L\'un des romans les plus extraordinaires que j\'aie jamais lus. Le mélange de satire soviétique, de fantastique et de récit évangélique est absolument unique. Béhémoth le chat est inoubliable !', '2025-01-15 11:00:00', 0),
(46, 5, 17, 5, 'Boulgakov a écrit ce roman en sachant qu\'il ne serait jamais publié de son vivant. Cette liberté totale se sent dans chaque page. Un acte de résistance littéraire sublime.', '2025-02-20 16:00:00', 0),
(47, 6, 17, 4, 'La scène du bal de Satan où Marguerite vole nue sur un balai au-dessus de Moscou est l\'une des plus belles de toute la littérature. Et la conclusion avec le Maître et Marguerite qui trouvent enfin la paix est bouleversante.', '2025-03-20 19:00:00', 1),
(48, 7, 19, 5, 'Oui c\'est long, oui il y a beaucoup de personnages, mais c\'est l\'une des expériences de lecture les plus riches de ma vie. Tolstoï saisit l\'âme humaine avec une précision stupéfiante.', '2025-01-25 10:00:00', 0),
(49, 8, 19, 4, 'Les scènes de guerre sont d\'un réalisme saisissant, surtout Austerlitz et Borodino. Tolstoï y était, ça se sent dans chaque ligne. Et la mort du prince André m\'a fait pleurer.', '2025-02-05 14:00:00', 0),
(50, 2, 19, 5, 'L\'épilogue philosophique est souvent critiqué mais je le trouve fascinant. Tolstoï démontre que Napoléon n\'a pas vraiment dirigé ses armées — il était emporté par des forces bien plus grandes que lui.', '2025-03-05 11:00:00', 1),
(51, 3, 20, 5, 'Le premier grand roman de la littérature mondiale et il reste d\'une modernité étonnante. Cervantes invente le roman tel qu\'on le connaît : un héros complexe, un narrateur peu fiable, une mise en abyme.', '2025-01-30 09:00:00', 0),
(52, 4, 20, 4, 'Ce qui est magnifique c\'est que Don Quichotte devient de plus en plus touchant au fil du roman. On rit de lui au début, on l\'admire à la fin. Et la mort du héros qui retrouve la raison est profondément triste.', '2025-02-25 15:00:00', 1),
(53, 5, 24, 4, 'Zola dresse un portrait fascinant d\'une femme qui détruit les hommes non par méchanceté mais par indifférence totale. Nana est une force de la nature plus qu\'un personnage calculateur.', '2025-01-12 13:00:00', 0),
(54, 6, 24, 5, 'La scène finale où Nana gît défigurée par la variole pendant que Paris crie à la guerre est l\'une des plus puissantes de toute la littérature française. Zola était un génie de la symbolique.', '2025-02-18 17:00:00', 1),
(55, 7, 25, 5, 'Le roman le plus optimiste de Zola ! La description des grands magasins est d\'une précision et d\'une modernité incroyables. On reconnaît nos centres commerciaux actuels dans chaque page.', '2025-01-08 10:00:00', 0),
(56, 8, 25, 4, 'Denise est un personnage magnifique — douce mais inébranlable dans ses convictions. Et la façon dont elle finit par dompter Mouret sans jamais se compromettre est satisfaisante.', '2025-02-14 16:00:00', 0),
(57, 2, 27, 5, 'Balzac signe avec ce roman une analyse implacable de l\'avarice et de ses ravages. Le père Grandet est l\'un des personnages les plus effrayants de la littérature française — sa monstruosité est d\'autant plus terrifiante qu\'elle est banale.', '2025-01-22 11:00:00', 0),
(58, 3, 27, 4, 'La trahison de Charles qui abandonne Eugénie pour faire une carrière sociale m\'a révolté. Mais Eugénie reste debout, seule et digne. Un roman sur la pureté face à la corruption du monde.', '2025-02-22 15:00:00', 0),
(59, 4, 28, 5, 'La scène de Waterloo vue par Fabrice est l\'une des plus géniales de la littérature — la guerre racontée du point de vue d\'un soldat qui ne comprend rien à ce qui se passe. Tolstoï s\'en est inspiré pour Guerre et Paix.', '2025-01-18 09:00:00', 0),
(60, 5, 28, 4, 'L\'histoire d\'amour entre Fabrice et Clélia à travers les barreaux de la prison est d\'une poésie extraordinaire. Et la fin tragique — Clélia qui meurt peu après avoir cédé à Fabrice — est bouleversante.', '2025-02-12 14:00:00', 1),
(61, 6, 34, 5, 'La mer souterraine avec ses reptiles préhistoriques et ses forêts de champignons géants est l\'une des visions les plus fantastiques de toute la littérature d\'aventure. Verne avait une imagination extraordinaire.', '2025-01-14 10:00:00', 0),
(62, 7, 34, 4, 'Le personnage du professeur Lidenbrock est hilarant dans sa monomanie scientifique. Verne excelle à créer ces savants fous adorables qui entraînent tout le monde dans leurs folies.', '2025-02-16 15:00:00', 0),
(63, 8, 35, 5, 'Ce qui est fascinant c\'est que Verne a imaginé le lancement depuis la Floride, la capsule cylindrique, l\'apesanteur — cent ans avant Apollo 11 ! Sa précision scientifique est stupéfiante.', '2025-01-16 11:00:00', 0),
(64, 2, 35, 4, 'Michel Ardan est un personnage délicieux — l\'aventurier français exubérant qui embarque dans une capsule lunaire comme si c\'était pour prendre le train. Verne a beaucoup d\'humour.', '2025-02-19 16:00:00', 0),
(65, 3, 36, 5, 'La première rencontre entre Holmes et Watson est un moment magique de la littérature. Holmes qui déduit immédiatement qu\'il revient d\'Afghanistan rien qu\'en le regardant — c\'est brillant !', '2025-01-06 09:00:00', 0),
(66, 4, 36, 4, 'La structure du roman est surprenante — on abandonne l\'enquête à mi-parcours pour un flashback en Utah avec les Mormons. C\'est déroutant mais ça donne une profondeur inattendue au crime.', '2025-02-08 14:00:00', 0),
(67, 5, 36, 5, 'Le meurtrier Jefferson Hope se révèle être un homme vengeur dont le crime était presque justifié moralement — il vengeait l\'enlèvement et la mort de sa fiancée par les mormons. Conan Doyle complexifie brillamment la morale.', '2025-03-12 18:00:00', 1),
(68, 6, 37, 5, 'L\'atmosphère des landes du Devonshire dans le brouillard est inoubliable. Conan Doyle crée une tension gothique parfaite. C\'est le meilleur Holmes sans aucun doute.', '2025-01-09 10:00:00', 0),
(69, 7, 37, 5, 'Holmes qui se cache sur la lande pendant que Watson croit enquêter seul — ce twist est génial. Et la révélation que Stapleton est un Baskerville qui voulait hériter du domaine est parfaitement amenée.', '2025-02-11 15:00:00', 1),
(70, 8, 37, 4, 'La scène finale où le chien phosphorescent surgit dans le brouillard est absolument terrifiante même en sachant que c\'est un roman policier rationnel. Conan Doyle maîtrise parfaitement la tension.', '2025-03-18 19:00:00', 0),
(71, 2, 40, 5, 'Christie au sommet de son art ! Le cadre égyptien est splendide et tous les personnages à bord du bateau sont suspects. Un vrai plaisir de lecture de bout en bout.', '2025-01-11 09:00:00', 0),
(72, 3, 40, 4, 'J\'avais deviné une partie du twist mais pas l\'autre. Christie joue brillamment avec nos préjugés pour nous faire suspecter les mauvaises personnes jusqu\'au bout.', '2025-02-17 14:00:00', 0),
(73, 4, 40, 5, 'La révélation que Simon et Linnet ont comploté ensemble leur propre crime pour éliminer Jacqueline et hériter de la fortune est renversante. Et Poirot qui avait tout compris depuis le début, bien sûr !', '2025-03-22 20:00:00', 1),
(74, 5, 42, 5, 'La pièce de théâtre la plus importante de Sartre. Le débat entre Hugo l\'idéaliste et Hoederer le pragmatique résume parfaitement le dilemme de la gauche politique au XXe siècle.', '2025-01-13 10:00:00', 0),
(75, 6, 42, 4, 'Hoederer est l\'un des personnages les plus fascinants de la littérature française. Sa philosophie politique — les mains sales pour garder les idéaux propres — est d\'une cohérence implacable.', '2025-02-23 15:00:00', 0),
(76, 7, 42, 5, 'Hugo tire finalement sur Hoederer non pour des raisons politiques mais parce qu\'il le trouve avec Jessica. Et la fin où il choisit de mourir pour donner un sens politique à son acte est magistrale. Sartre au sommet.', '2025-03-25 18:00:00', 1),
(77, 2, 46, 5, 'Un roman d\'une intelligence et d\'une cruauté absolument fascinantes. La Merteuil est l\'un des personnages féminins les plus complexes et les plus puissants de toute la littérature française.', '2025-01-10 10:00:00', 0),
(78, 3, 46, 4, 'Ce qui est brillant c\'est que les deux manipulateurs finissent par être détruits par leurs propres jeux. La Merteuil défigurée par la variole et Valmont tué en duel — la morale est sauve mais avec une ironie grinçante.', '2025-02-14 15:00:00', 1),
(79, 4, 105, 5, 'Un roman d\'enfance d\'une joie et d\'une liberté incomparables. Tom Sawyer est le gamin universel que tout le monde a été ou rêvé d\'être. Twain capture l\'esprit de l\'enfance avec un génie rare.', '2025-01-15 09:00:00', 0),
(80, 5, 105, 4, 'La scène du badigeonnage de la palissade est un monument d\'humour et de psychologie. Et la découverte du trésor dans la grotte après que Tom a témoigné contre l\'Indien Joe est palpitante.', '2025-02-20 14:00:00', 1),
(81, 6, 95, 5, 'Un témoignage d\'une honnêteté bouleversante. Barbusse montre la guerre telle qu\'elle était vraiment — pas de gloire, pas d\'héroïsme, juste la boue, la mort et la solidarité entre hommes ordinaires.', '2025-01-12 11:00:00', 0),
(82, 7, 95, 5, 'Ce roman a été écrit pendant que la guerre se déroulait encore. Il fallait un courage immense pour publier ça en 1916. Un acte littéraire et politique majeur.', '2025-02-18 16:00:00', 0),
(83, 8, 60, 5, 'Le roman le plus émouvant de Zola. Gervaise est un personnage d\'une humanité extraordinaire — on la voit lutter, espérer, puis sombrer, et on souffre avec elle à chaque page.', '2025-01-08 10:00:00', 0),
(84, 2, 60, 4, 'La scène de la fête chez Gervaise au sommet de sa prospérité, juste avant que tout s\'effondre, est d\'une ironie tragique déchirante. Zola maîtrise parfaitement le retournement de fortune.', '2025-02-10 15:00:00', 0),
(85, 3, 94, 5, 'L\'un des plus grands romans français du XXe siècle. Malraux réussit à faire de la politique révolutionnaire une matière à tragédie grecque. La mort de Katow qui donne son cyanure à ses camarades est sublime.', '2025-01-20 09:00:00', 1),
(86, 4, 94, 4, 'Les personnages sont tous des héros tragiques à leur manière. Kyo qui meurt pour ses idéaux, Tchen le terroriste pur, le vieux Gisors qui fume son opium pour oublier — une galerie de portraits inoubliables.', '2025-02-25 14:00:00', 0),
(87, 5, 141, 4, 'Un roman expérimental déconcertant au début mais d\'une puissance extraordinaire. La voix de Darl, le fils visionnaire, est particulièrement fascinante dans sa façon de percevoir la réalité.', '2025-01-25 11:00:00', 0),
(88, 6, 141, 5, 'Faulkner pousse la technique du monologue intérieur à son extrême. La section de Vardaman — Mon frère est un poisson — est un moment de génie pur dans sa façon de rendre la pensée d\'un enfant traumatisé.', '2025-02-28 16:00:00', 0),
(89, 7, 168, 5, 'Un roman magnifique et révoltant sur l\'ingratitude de la France envers ses soldats. Lemaitre réussit à être à la fois drôle, poétique et profondément émouvant. Les masques d\'Édouard sont une idée géniale.', '2025-01-18 10:00:00', 0),
(90, 8, 168, 4, 'La chute de Pradelle, l\'officier corrompu, est satisfaisante mais amère — on sait que dans la réalité, beaucoup de ces profiteurs de guerre s\'en sont tirés. Un roman qui met en colère, ce qui est une qualité.', '2025-02-22 15:00:00', 0),
(91, 2, 87, 5, 'Une saga familiale d\'une profondeur exceptionnelle. Martin du Gard analyse avec une précision clinique la façon dont deux frères se construisent en opposition à un père autoritaire. Un monument de la littérature française.', '2025-01-22 09:00:00', 0),
(92, 3, 87, 4, 'L\'Été 1914 est un chef-d\'œuvre absolu. La façon dont les socialistes internationalistes réalisent leur impuissance à arrêter la guerre est d\'une tristesse et d\'une lucidité dévastatrices.', '2025-02-26 14:00:00', 1),
(93, 4, 78, 5, 'Le recueil de poésie le plus important de la littérature française. Chaque poème est un bijou ciselé. Spleen IV — Quand le ciel bas et lourd pèse comme un couvercle — est d\'une noirceur et d\'une beauté inégalées.', '2025-01-14 10:00:00', 0),
(94, 5, 78, 5, 'Baudelaire a inventé la modernité poétique. Après Les Fleurs du Mal, la poésie française n\'est plus jamais la même. Son influence sur Rimbaud, Verlaine et tous les symbolistes est immense.', '2025-02-16 15:00:00', 0),
(95, 6, 157, 4, 'Plus difficile que Le Nom de la Rose mais encore plus vertigineux intellectuellement. Eco démontre comment n\'importe quelle série de faits peut être reliée en un complot cohérent si on le veut vraiment.', '2025-01-16 11:00:00', 0),
(96, 7, 157, 5, 'Un roman qui vous fait remettre en question votre propre façon de chercher des connexions dans le monde. La frontière entre la pensée ésotérique et la paranoia est terrifiante de porosité.', '2025-02-19 16:00:00', 0),
(97, 8, 165, 4, 'Joséphine est un personnage attachant et touchant. Sa transformation progressive d\'intellectuelle effacée en femme qui s\'assume est réjouissante à suivre. Un roman populaire mais vraiment bien écrit.', '2025-01-09 09:00:00', 0),
(98, 2, 165, 3, 'Moins fort que Les Yeux Jaunes des Crocodiles à mon goût, mais le personnage d\'Iris, superficielle et jalouse, est parfaitement réussi dans sa médiocrité. Pancol a le sens des personnages féminins complexes.', '2025-02-12 14:00:00', 0),
(99, 3, 80, 5, 'La forme des calligrammes est une révolution visuelle et poétique. Le poème La Cravate et la Montre est à la fois drôle et mélancolique. Apollinaire joue avec le langage comme un artiste visuel joue avec la forme.', '2025-01-11 10:00:00', 0),
(100, 4, 80, 4, 'Les poèmes de guerre sont d\'une beauté étrange et troublante. Apollinaire trouve de la poésie dans les obus et les fusées éclairantes tout en exprimant la nostalgie de l\'amour et de Paris. Un équilibre unique.', '2025-02-15 15:00:00', 0),
(101, 5, 123, 5, 'Gogol réussit en quelques dizaines de pages ce que d\'autres n\'atteignent pas en des centaines. La misère d\'Akaki est à la fois comique et tragique, réaliste et fantastique. Un chef-d\'œuvre de la nouvelle.', '2025-01-13 09:00:00', 0),
(102, 6, 123, 4, 'Le fantôme d\'Akaki qui arrache les manteaux des passants est à la fois une vengeance grotesque et un cri de révolte sociale. Dostoïevski a dit que toute la littérature russe était sortie du Manteau de Gogol.', '2025-02-17 14:00:00', 0),
(103, 7, 71, 4, 'Le roman le plus atypique de Zola dans les Rougon-Macquart. Une sorte de conte médiéval lumineux et mystique, à des années-lumière de Germinal ou de L\'Assommoir. Un côté poétique et onirique vraiment beau.', '2025-01-06 10:00:00', 0),
(104, 8, 71, 3, 'Beau mais un peu trop sage pour moi. La mort d\'Angélique le jour de son mariage, comme si Dieu la rappelait à lui avant que la réalité ne ternisse son idéal, est poétique mais prévisible.', '2025-02-08 15:00:00', 1),
(105, 2, 85, 5, 'Le roman de l\'adolescence par excellence. Cette quête du domaine perdu et de la jeune fille entrevue lors d\'une fête magique capture quelque chose d\'universel dans la nostalgie de l\'enfance et des rêves impossibles.', '2025-01-07 09:00:00', 0),
(106, 3, 85, 4, 'La mort d\'Yvonne de Galais en accouchant, et Meaulnes qui disparaît pour chercher sa fille illégitime, laissant François élever l\'enfant — c\'est d\'une mélancolie absolue. Le bonheur est toujours ailleurs, toujours perdu.', '2025-02-09 14:00:00', 1),
(107, 2, 174, 4, 'Un page-turner absolu ! Brown maîtrise parfaitement l\'art du suspense et des rebondissements. Idéal pour découvrir l\'histoire de l\'art et les symboles de manière ludique.', '2025-01-10 10:00:00', 0),
(108, 3, 174, 3, 'Très divertissant mais historiquement approximatif. Si on le lit comme un thriller et pas comme un documentaire, c\'est un excellent roman populaire.', '2025-02-14 15:00:00', 0),
(109, 4, 174, 4, 'Le twist final avec Leigh Teabing qui est le véritable méchant est bien amené. Et la révélation que Sophie est une descendante directe de Jésus et Marie-Madeleine est vertigineuse même si non historique.', '2025-03-10 18:00:00', 1),
(110, 5, 175, 4, 'Brown dans la grande tradition de ses thrillers. Florence, Venise et Istanbul sont magnifiquement décrites. Et les références à Dante donnent une profondeur culturelle bienvenue.', '2025-01-15 09:00:00', 0),
(111, 6, 175, 3, 'Le twist avec Sienna qui était du côté de Zobrist depuis le début est audacieux. Mais la fin avec le virus déjà disséminé et qui ne tue personne est décevante — Brown n\'ose pas aller jusqu\'au bout.', '2025-02-20 14:00:00', 1),
(112, 7, 176, 4, 'Le meilleur Brown depuis Da Vinci Code à mon avis. Les questions posées sur l\'origine de la vie et le futur de l\'humanité sont fascinantes et la découverte d\'Edmond est scientifiquement plausible.', '2025-01-20 11:00:00', 0),
(113, 8, 176, 3, 'Winston, l\'IA du musée Guggenheim, est le personnage le plus intéressant du roman — et c\'est une machine. Cela dit beaucoup sur l\'avenir que Brown imagine.', '2025-02-25 16:00:00', 0),
(114, 2, 177, 5, 'Un thriller psychologique parfaitement construit. Rachel est un personnage magnifiquement imparfait — on la plaint, on la juge, on la comprend. Sa mémoire lacunaire crée une tension constante.', '2025-01-08 09:00:00', 0),
(115, 3, 177, 4, 'La révélation que Tom, l\'ex-mari de Rachel, est l\'assassin de Megan et qu\'il avait aussi manipulé et maltraité Rachel pendant tout leur mariage est glaçante. Un roman sur les violences invisibles dans le couple.', '2025-02-10 14:00:00', 1),
(116, 4, 178, 5, 'Flynn réussit quelque chose de rarissime : créer deux personnages principaux totalement antipathiques et pourtant absolument fascinants. On ne peut pas s\'arrêter de lire même en détestant tout le monde.', '2025-01-12 10:00:00', 0),
(117, 5, 178, 5, 'Le retournement à mi-roman — quand on comprend qu\'Amy a tout orchestré elle-même — est le meilleur twist que j\'aie lu depuis des années. Flynn est diaboliquement intelligente.', '2025-02-16 15:00:00', 1),
(118, 6, 126, 5, 'Dostoïevski a prédit le totalitarisme révolutionnaire avec une précision stupéfiante cinquante ans avant qu\'il ne se réalise. Stavroguine est l\'un des personnages les plus énigmatiques et fascinants de toute la littérature.', '2025-01-14 11:00:00', 0),
(119, 7, 126, 4, 'Plus difficile que Crime et Châtiment mais encore plus prophétique. La scène où Kirilov se suicide par principe philosophique est d\'une logique absurde et terrifiante.', '2025-02-18 16:00:00', 0),
(120, 8, 49, 4, 'La prose de Chateaubriand est d\'une beauté lyrique incomparable. Les descriptions de la nature américaine sont éblouissantes. Un texte fondateur du romantisme français à lire pour sa beauté formelle.', '2025-01-16 09:00:00', 0),
(121, 2, 49, 3, 'Le sacrifice d\'Atala qui se suicide pour ne pas trahir son vœu est à la fois romantique et frustrant. Mais cette tension entre passion et devoir religieux est au cœur du romantisme.', '2025-02-22 14:00:00', 1),
(122, 3, 114, 5, 'La phrase d\'ouverture est la plus célèbre de la littérature anglaise. Et le sacrifice de Sydney Carton — C\'est une bien plus belle chose que je fais là — est l\'un des moments les plus émouvants du roman victorien.', '2025-01-18 10:00:00', 1),
(123, 4, 114, 4, 'Dickens décrit la Révolution française avec une intensité dramatique extraordinaire. Les scènes de tribunal révolutionnaire et de guillotine sont d\'un réalisme saisissant.', '2025-02-24 15:00:00', 0),
(124, 5, 67, 4, 'Zola dresse un portrait impitoyable de la spéculation immobilière sous Haussmann. La façon dont Saccard exploite les informations confidentielles pour s\'enrichir résonne étrangement avec les scandales immobiliers actuels.', '2025-01-20 09:00:00', 0),
(125, 6, 67, 4, 'La relation incestueuse entre Renée et Maxime est traitée avec une froideur clinique par Zola qui en fait le symbole de la corruption morale totale du Second Empire. Brillant et dérangeant.', '2025-02-26 14:00:00', 1),
(126, 7, 127, 4, 'Moins connu que les autres grands Dostoïevski mais vraiment passionnant. Arkadi est un narrateur attachant dans sa contradiction entre ses ambitions matérialistes et sa profonde sensibilité.', '2025-01-22 11:00:00', 0),
(127, 8, 127, 3, 'Dostoïevski au niveau de sa production habituelle — donc brillant — mais ce n\'est pas son roman le plus accessible. La relation père-fils avec Versilov est néanmoins d\'une profondeur rare.', '2025-02-28 16:00:00', 0),
(128, 2, 83, 5, 'La musicalité de Verlaine est incomparable. Chaque poème sonne comme une mélodie. Clair de lune est l\'un des plus beaux poèmes de la langue française — Votre âme est un paysage choisi.', '2025-01-24 09:00:00', 0),
(129, 3, 83, 4, 'La mélancolie sous-jacente derrière les masques de la fête galante est ce qui rend ces poèmes si touchants. Verlaine dit plus sur la tristesse humaine en vingt lignes que d\'autres en vingt pages.', '2025-02-12 14:00:00', 0),
(130, 4, 52, 4, 'George Sand signe avec Indiana un roman féministe avant l\'heure d\'une modernité étonnante. La critique du mariage comme institution d\'oppression est aussi pertinente aujourd\'hui qu\'en 1832.', '2025-01-26 10:00:00', 0),
(131, 5, 52, 3, 'Raymon de Ramière est un personnage odieux parfaitement réussi — le séducteur égoïste qui se croit irrésistible. Et Ralph, l\'amour silencieux et fidèle, est une belle alternative au héros romantique traditionnel.', '2025-02-15 15:00:00', 0),
(132, 6, 181, 5, 'J\'ai pleuré comme jamais. Green réussit à parler de la mort avec humour et intelligence sans jamais être larmoyant. Hazel et Augustus sont des personnages d\'une vitalité extraordinaire malgré leur condition.', '2025-01-28 09:00:00', 0),
(133, 7, 181, 4, 'La mort d\'Augustus — qu\'on apprend progressivement au lieu d\'un choc brutal — est traitée avec une délicatesse parfaite. Et le pré-funéraire où Hazel lit son éloge pendant qu\'il est encore vivant est bouleversant.', '2025-02-20 14:00:00', 1),
(134, 8, 134, 5, 'Mann démontre avec une logique implacable que la sensibilité artistique et l\'énergie vitale sont incompatibles. Hanno, le petit musicien génial, est condamné par sa propre finesse. Un roman d\'une tristesse magnifique.', '2025-01-30 10:00:00', 0),
(135, 2, 134, 4, 'La scène où Tom Buddenbrook lit Schopenhauer et comprend soudain le néant est extraordinaire. Mann avait vingt-cinq ans quand il a écrit ça — c\'est stupéfiant de maturité.', '2025-02-24 15:00:00', 0),
(136, 3, 77, 4, 'Un roman d\'une richesse visuelle et sensorielle incomparable. Flaubert reconstitue Carthage avec une précision archéologique et une imagination débordante. C\'est de la peinture en mots.', '2025-01-17 09:00:00', 0),
(137, 4, 77, 5, 'La mort de Mâtho torturé en public sous les yeux de Salammbô, qui meurt elle-même aussitôt après, est l\'un des dénouements les plus tragiques et les plus beaux de la littérature française.', '2025-02-21 14:00:00', 1),
(138, 5, 133, 5, 'Le roman le plus ambitieux de Mann. Les joutes philosophiques entre Settembrini et Naphta sont fascinantes — ils incarnent les deux pôles de la pensée européenne qui vont s\'entre-déchirer dans la guerre.', '2025-01-19 10:00:00', 0),
(139, 6, 133, 4, 'La dilatation du temps au Berghof — où des semaines passent en quelques pages et d\'autres pages couvrent une heure — est un tour de force narratif unique. Mann réinvente le roman du temps.', '2025-02-23 15:00:00', 0),
(140, 7, 68, 4, 'Le roman politique le plus précis de Zola. Les mécanismes du clientélisme et de la corruption qu\'il décrit sous le Second Empire sont d\'une modernité frappante. Rien n\'a vraiment changé.', '2025-01-21 09:00:00', 0),
(141, 8, 68, 3, 'Moins romanesque que les autres Zola mais passionnant comme document historique et politique. Rougon est un personnage fascinant dans sa brutalité assumée et son mépris total des idéologies.', '2025-02-27 14:00:00', 0),
(142, 2, 187, 5, 'Martin révolutionne la fantasy en tuant ses héros et en faisant survivre ses méchants. Le monde de Westeros est d\'une richesse et d\'une cohérence qui dépasse tout ce qui a été fait dans le genre depuis Tolkien.', '2025-01-10 10:00:00', 0),
(143, 3, 187, 5, 'La mort d\'Eddard Stark à la fin du premier tome est le moment qui a tout changé — on comprend que personne n\'est à l\'abri et que Martin ne suit aucune règle du genre. Révolutionnaire.', '2025-02-14 15:00:00', 1),
(144, 4, 48, 4, 'Un roman d\'une beauté lyrique incomparable. Les descriptions de l\'île Maurice sont éblouissantes et l\'histoire d\'amour pure entre les deux enfants est d\'une tendresse bouleversante.', '2025-01-15 09:00:00', 0),
(145, 5, 48, 3, 'La mort de Virginie qui refuse d\'être sauvée par pudeur est frustrante mais symboliquement parfaite — elle ne peut survivre hors de son paradis d\'innocence. Un roman sur l\'impossibilité du bonheur dans le monde réel.', '2025-02-20 14:00:00', 1),
(146, 6, 44, 5, 'L\'essai philosophique le plus accessible et le plus bouleversant du XXe siècle. Camus pose la seule vraie question philosophique avec une clarté et une honnêteté rares. Il faut imaginer Sisyphe heureux — cette conclusion change une vie.', '2025-01-20 11:00:00', 0),
(147, 7, 44, 4, 'Camus réfute le suicide et le saut dans la foi avec la même rigueur. La révolte comme seule réponse digne à l\'absurde est une position philosophique d\'une cohérence et d\'un courage remarquables.', '2025-02-25 16:00:00', 0),
(148, 8, 47, 5, 'L\'un des romans d\'amour les plus déchirants de la littérature française. Des Grieux est esclave de Manon et le sait — et pourtant il continue. Prévost a compris avant tout le monde l\'irrationalité absolue de la passion.', '2025-01-08 09:00:00', 0),
(149, 2, 47, 4, 'Manon est un personnage fascinant car elle aime vraiment Des Grieux à sa façon, mais elle ne peut pas résister au confort matériel. Elle n\'est pas cruelle, juste faible — et cette nuance la rend humaine et touchante.', '2025-02-10 14:00:00', 0),
(150, 3, 50, 4, 'René a inventé le héros romantique inadapté que toute la littérature du XIXe siècle va recycler. Ce mal du siècle — trop de sensibilité pour un monde médiocre — reste d\'une pertinence étonnante.', '2025-01-12 10:00:00', 0),
(151, 4, 50, 3, 'Court mais dense. La révélation de l\'amour incestueux d\'Amélie pour son frère est traitée avec une pudeur et une ellipse typiquement classiques. Chateaubriand dit tout en ne disant rien.', '2025-02-16 15:00:00', 1),
(152, 5, 51, 5, 'Le roman le plus honnête jamais écrit sur la lâcheté sentimentale masculine. Adolphe n\'est pas méchant, il est simplement incapable de choisir — et cette incapacité détruit Ellénore aussi sûrement que la cruauté.', '2025-01-14 11:00:00', 0),
(153, 6, 51, 4, 'Constant s\'est autobiographié avec une impitoyable lucidité. La mort d\'Ellénore et la solitude vide d\'Adolphe après — quand il réalise que la liberté qu\'il cherchait ne lui apporte rien — est d\'une tristesse absolue.', '2025-02-18 16:00:00', 1),
(154, 7, 53, 4, 'Un roman champêtre d\'une douceur et d\'une poésie incomparables. George Sand célèbre la sagesse paysanne et la beauté de la nature berrichonne avec un amour sincère. Parfait pour se ressourcer.', '2025-01-16 09:00:00', 0),
(155, 8, 53, 4, 'La nuit passée dans la forêt par Germain, Marie et le petit Pierre est une scène d\'une grâce et d\'une tendresse rares. Sand montre comment l\'amour vrai naît dans la simplicité et l\'entraide.', '2025-02-22 14:00:00', 0),
(156, 2, 54, 4, 'Sand réussit à rendre touchant et naturel un amour qui pourrait paraître choquant — le fils adoptif qui épouse sa mère adoptive. La pureté des sentiments et la langue berrichonne charment complètement.', '2025-01-18 10:00:00', 0),
(157, 3, 54, 3, 'Plus court et plus simple que La Mare au Diable mais d\'une beauté tranquille. François est un personnage attachant dans sa loyauté absolue envers celle qui l\'a sauvé.', '2025-02-24 15:00:00', 0),
(158, 4, 55, 4, 'Un roman méconnu d\'une finesse psychologique extraordinaire. Fromentin — peintre autant qu\'écrivain — décrit les paysages saintongeais et les états d\'âme avec la même précision lumineuse.', '2025-01-20 09:00:00', 0),
(159, 5, 55, 4, 'Le renoncement de Dominique est ce qui fait la grandeur du roman. Choisir la sagesse contre la passion, la vie ordinaire contre la destruction romantique — une leçon rare dans la littérature du XIXe siècle.', '2025-02-26 14:00:00', 0),
(160, 6, 56, 5, 'Maupassant signe avec Bel-Ami la satire la plus acide de la IIIe République. Duroy est odieux et fascinant — on le déteste et on ne peut s\'empêcher d\'admirer son cynisme absolu et son efficacité.', '2025-01-22 11:00:00', 0),
(161, 7, 56, 4, 'La scène finale où Duroy quitte l\'église après son mariage fastueux en regardant déjà vers son prochain objectif politique est d\'un cynisme parfait. Maupassant ne lui accorde même pas un moment de bonheur.', '2025-02-28 16:00:00', 1),
(162, 8, 57, 5, 'Le roman le plus tendre et le plus triste de Maupassant. Jeanne est un personnage d\'une humanité bouleversante — ses illusions s\'effondrent l\'une après l\'autre avec une cruauté douce et inexorable.', '2025-01-24 09:00:00', 0),
(163, 2, 57, 4, 'La dernière phrase du roman — La vie, voyez-vous, ça n\'est jamais si bon ni si mauvais qu\'on croit — est l\'une des plus belles et des plus justes de la littérature française. Maupassant au sommet de sa sensibilité.', '2025-02-12 14:00:00', 0),
(164, 3, 58, 5, 'Un chef-d\'œuvre de concision et de précision psychologique. La jalousie de Pierre qui détruit sa propre famille par sa quête obsessionnelle de la vérité est d\'une vérité humaine absolue.', '2025-01-26 10:00:00', 0),
(165, 4, 58, 4, 'La préface théorique sur le roman est presque aussi intéressante que le roman lui-même. Maupassant y défend une vision du naturalisme psychologique d\'une modernité étonnante.', '2025-02-15 15:00:00', 0),
(166, 5, 59, 5, 'Le premier grand Zola et déjà un chef-d\'œuvre. La description de la culpabilité qui ronge les deux amants après le meurtre est d\'une précision psychologique stupéfiante pour un auteur de vingt-sept ans.', '2025-01-28 09:00:00', 0),
(167, 6, 59, 4, 'La fin où Thérèse et Laurent se suicident ensemble devant Madame Raquin paralysée qui les a vus tout avouer est d\'une noirceur et d\'une symétrie parfaites. Le crime punit les criminels sans intervention extérieure.', '2025-02-20 14:00:00', 1),
(168, 7, 61, 4, 'La satire la plus féroce de Zola contre la bourgeoisie. Derrière les façades respectables, une corruption généralisée. Zola démontre que l\'hypocrisie est le vrai ciment de la société bourgeoise.', '2025-01-30 10:00:00', 0),
(169, 8, 61, 4, 'L\'immeuble comme microcosme social est une idée géniale — chaque étage, chaque appartement révèle une couche de la bourgeoisie parisienne dans toute sa médiocrité et sa lâcheté.', '2025-02-24 15:00:00', 0),
(170, 2, 62, 5, 'L\'un des romans les plus sombres et les plus puissants de Zola. Les pulsions meurtrières de Jacques Lantier sont traitées comme une maladie héréditaire avec une rigueur clinique fascinante et terrifiante.', '2025-01-17 09:00:00', 0),
(171, 3, 62, 4, 'La locomotive comme symbole de la modernité industrielle incontrôlable est brillante. Et la fin — le train sans conducteur filant dans la nuit avec des soldats vers la guerre — est une image prophétique inoubliable.', '2025-02-21 14:00:00', 1),
(172, 4, 63, 4, 'Les descriptions des Halles de Paris — la symphonie des fromages, la mer des poissons, les montagnes de charcuterie — sont parmi les plus sensuelles et les plus belles de toute la littérature française.', '2025-01-19 10:00:00', 0),
(173, 5, 63, 4, 'L\'opposition entre les Maigres et les Gras, entre l\'idéalisme politique et l\'embourgeoisement satisfait, est d\'une pertinence toujours actuelle. Zola décrit la trahison de classe avec une précision impitoyable.', '2025-02-23 15:00:00', 0),
(174, 2, 64, 5, 'Le roman de guerre le plus puissant de Zola. La description de la débâcle de Sedan est d\'une précision documentaire saisissante — on comprend comment une armée entière peut s\'effondrer par incompétence de ses chefs.', '2025-01-10 10:00:00', 0),
(175, 3, 64, 4, 'Jean qui tue Maurice sans le reconnaître pendant la Commune est l\'image la plus déchirante de la guerre civile — les Français qui s\'entre-tuent après avoir été vaincus par les Prussiens. Une tragédie dans la tragédie.', '2025-02-14 15:00:00', 1),
(176, 4, 65, 4, 'Zola règle ses comptes avec le monde de l\'art impressionniste et avec lui-même. Claude Lantier est un portrait douloureux de l\'artiste qui ne peut jamais atteindre son idéal. La fin est bouleversante.', '2025-01-15 09:00:00', 0),
(177, 5, 65, 5, 'La pendaison de Claude devant son tableau inachevé est l\'une des fins les plus tragiques de la littérature française. Zola y dit quelque chose de vrai et de terrible sur le prix de la création artistique.', '2025-02-20 14:00:00', 1),
(178, 6, 66, 4, 'Pauline est le personnage le plus attachant de toute la saga Rougon-Macquart. Sa générosité absolue face à l\'ingratitude de tous ceux qu\'elle aide est à la fois admirable et navrante.', '2025-01-20 11:00:00', 0),
(179, 7, 66, 3, 'Moins dramatique que les autres Zola mais d\'une beauté tranquille. Les descriptions de la mer normande en tempête sont magnifiques. Un roman sur la bonté dans un monde qui ne la mérite pas.', '2025-02-25 16:00:00', 0),
(180, 8, 69, 4, 'Le roman le plus intime et le plus tendre de Zola. Les cinq tableaux de Paris vus de Passy qui ouvrent chaque partie sont de véritables tableaux impressionnistes en prose.', '2025-01-08 09:00:00', 0),
(181, 2, 69, 3, 'La mort de Jeanne, sacrifiée à la faute d\'une nuit de sa mère, est cruelle mais symboliquement cohérente. Zola est impitoyable avec ses personnages même quand il les aime.', '2025-02-10 14:00:00', 1),
(182, 3, 70, 4, 'Une belle conclusion à la saga Rougon-Macquart. Pascal est le personnage le plus sympathique de toute la série — un savant humaniste qui croit en la vie malgré tout ce qu\'il a vu dans sa famille.', '2025-01-12 10:00:00', 0),
(183, 4, 70, 4, 'L\'enfant à naître à la fin du roman, symbole d\'espoir après vingt volumes de noirceur, est une conclusion optimiste que Zola s\'était méritée. Une belle façon de boucler cette immense saga.', '2025-02-16 15:00:00', 1),
(184, 5, 72, 4, 'Le roman le plus brutal de Zola, qui avait scandalisé ses contemporains. La passion pour la terre y est décrite comme une force aussi puissante et aussi destructrice que n\'importe quelle autre obsession humaine.', '2025-01-14 11:00:00', 0),
(185, 6, 72, 5, 'Zola dénonce le mythe romantique du bon paysan en harmonie avec la nature. La réalité qu\'il dépeint est d\'une violence et d\'une âpreté absolues — et probablement bien plus proche de la vérité.', '2025-02-18 16:00:00', 0),
(186, 7, 73, 5, 'La description de la Bourse en pleine fièvre spéculative est d\'une précision et d\'une énergie extraordinaires. Zola a clairement fait un travail documentaire colossal pour comprendre les mécanismes financiers.', '2025-01-16 09:00:00', 0),
(187, 8, 73, 4, 'Saccard est fascinant dans sa capacité à rebondir et à croire à ses propres chimères. Et Gundermann, le banquier qui l\'écrase froidement, est un portrait d\'une puissance tranquille terrifiante.', '2025-02-22 14:00:00', 0),
(188, 2, 64, 5, 'Le roman de guerre le plus puissant de Zola. La description de la débâcle de Sedan est d\'une précision documentaire saisissante — on comprend comment une armée entière peut s\'effondrer par incompétence de ses chefs.', '2025-01-10 10:00:00', 0),
(189, 3, 64, 4, 'Jean qui tue Maurice sans le reconnaître pendant la Commune est l\'image la plus déchirante de la guerre civile — les Français qui s\'entre-tuent après avoir été vaincus par les Prussiens. Une tragédie dans la tragédie.', '2025-02-14 15:00:00', 1),
(190, 4, 65, 4, 'Zola règle ses comptes avec le monde de l\'art impressionniste et avec lui-même. Claude Lantier est un portrait douloureux de l\'artiste qui ne peut jamais atteindre son idéal. La fin est bouleversante.', '2025-01-15 09:00:00', 0),
(191, 5, 65, 5, 'La pendaison de Claude devant son tableau inachevé est l\'une des fins les plus tragiques de la littérature française. Zola y dit quelque chose de vrai et de terrible sur le prix de la création artistique.', '2025-02-20 14:00:00', 1),
(192, 6, 66, 4, 'Pauline est le personnage le plus attachant de toute la saga Rougon-Macquart. Sa générosité absolue face à l\'ingratitude de tous ceux qu\'elle aide est à la fois admirable et navrante.', '2025-01-20 11:00:00', 0),
(193, 7, 66, 3, 'Moins dramatique que les autres Zola mais d\'une beauté tranquille. Les descriptions de la mer normande en tempête sont magnifiques. Un roman sur la bonté dans un monde qui ne la mérite pas.', '2025-02-25 16:00:00', 0),
(194, 8, 69, 4, 'Le roman le plus intime et le plus tendre de Zola. Les cinq tableaux de Paris vus de Passy qui ouvrent chaque partie sont de véritables tableaux impressionnistes en prose.', '2025-01-08 09:00:00', 0),
(195, 2, 69, 3, 'La mort de Jeanne, sacrifiée à la faute d\'une nuit de sa mère, est cruelle mais symboliquement cohérente. Zola est impitoyable avec ses personnages même quand il les aime.', '2025-02-10 14:00:00', 1),
(196, 3, 70, 4, 'Une belle conclusion à la saga Rougon-Macquart. Pascal est le personnage le plus sympathique de toute la série — un savant humaniste qui croit en la vie malgré tout ce qu\'il a vu dans sa famille.', '2025-01-12 10:00:00', 0),
(197, 4, 70, 4, 'L\'enfant à naître à la fin du roman, symbole d\'espoir après vingt volumes de noirceur, est une conclusion optimiste que Zola s\'était méritée. Une belle façon de boucler cette immense saga.', '2025-02-16 15:00:00', 1),
(198, 5, 72, 4, 'Le roman le plus brutal de Zola, qui avait scandalisé ses contemporains. La passion pour la terre y est décrite comme une force aussi puissante et aussi destructrice que n\'importe quelle autre obsession humaine.', '2025-01-14 11:00:00', 0),
(199, 6, 72, 5, 'Zola dénonce le mythe romantique du bon paysan en harmonie avec la nature. La réalité qu\'il dépeint est d\'une violence et d\'une âpreté absolues — et probablement bien plus proche de la vérité.', '2025-02-18 16:00:00', 0),
(200, 7, 73, 5, 'La description de la Bourse en pleine fièvre spéculative est d\'une précision et d\'une énergie extraordinaires. Zola a clairement fait un travail documentaire colossal pour comprendre les mécanismes financiers.', '2025-01-16 09:00:00', 0),
(201, 8, 73, 4, 'Saccard est fascinant dans sa capacité à rebondir et à croire à ses propres chimères. Et Gundermann, le banquier qui l\'écrase froidement, est un portrait d\'une puissance tranquille terrifiante.', '2025-02-22 14:00:00', 0),
(202, 2, 75, 4, 'Le roman le plus drôle et le plus désespérant de Flaubert. Bouvard et Pécuchet sont à la fois ridicules et touchants dans leur enthousiasme perpétuellement déçu. Une satire du savoir humain d\'une acuité absolue.', '2025-01-18 10:00:00', 0),
(203, 3, 75, 4, 'Flaubert a passé dix ans à documenter ce roman inachevé. L\'encyclopédie de la bêtise humaine qu\'il voulait y constituer est un projet à la fois comique et profondément sérieux sur les limites de la connaissance.', '2025-02-24 15:00:00', 0),
(204, 4, 76, 5, 'Le roman le plus honnête sur la médiocrité de l\'existence. Flaubert ne juge pas Frédéric, il l\'observe avec une pitié ironique. Et la visite finale de Madame Arnoux, vieillie, est d\'une mélancolie absolue.', '2025-01-20 09:00:00', 0),
(205, 5, 76, 4, 'La révolution de 1848 traverse le roman comme un bruit de fond — Frédéric y participe distraitement, trop occupé par ses amours. Flaubert dresse un portrait impitoyable d\'une génération qui a raté l\'histoire.', '2025-02-26 14:00:00', 0),
(206, 6, 79, 5, 'La suppression de toute ponctuation est un geste poétique radical qui donne aux poèmes une fluidité et une ambiguïté extraordinaires. Le Pont Mirabeau est l\'un des plus beaux poèmes d\'amour de la langue française.', '2025-01-22 11:00:00', 0),
(207, 7, 79, 4, 'Zone est une révolution poétique totale — Paris moderne, Christ aviateur, tour Eiffel, hangars d\'aéroport mêlés à des souvenirs d\'enfance catholique. Apollinaire invente la poésie du XXe siècle dans ce seul poème.', '2025-02-28 16:00:00', 0),
(208, 8, 81, 5, 'Des textes d\'une modernité et d\'une puissance stupéfiantes écrits par un adolescent de dix-huit ans. Rimbaud a tout inventé et tout brûlé avant d\'avoir vingt ans. Une météorite dans l\'histoire de la poésie.', '2025-01-24 09:00:00', 0),
(209, 2, 81, 4, 'Génie est le texte le plus prophétique des Illuminations — une vision d\'un être supérieur qui transforme le monde. Rimbaud se prenait pour ce génie ou le cherchait désespérément.', '2025-02-12 14:00:00', 0),
(210, 3, 82, 5, 'Le texte le plus honnête et le plus violent de toute la poésie française. Rimbaud se juge, se condamne et se libère en même temps. L\'adieu final à la littérature est d\'une lucidité et d\'un courage absolus.', '2025-01-26 10:00:00', 0),
(211, 4, 82, 4, 'Nuit de l\'Enfer et Délires — avec l\'Époux Infernal qui représente Verlaine — sont des textes d\'une violence psychologique et d\'une beauté formelle renversantes. Rimbaud règle ses comptes avec tout le monde, y compris lui-même.', '2025-02-15 15:00:00', 1),
(212, 5, 84, 5, 'Il pleure dans mon cœur est le poème le plus musical de la langue française. Verlaine atteint ici quelque chose d\'unique — la poésie comme pure sensation, sans message, sans intrigue, juste l\'émotion à l\'état pur.', '2025-01-28 09:00:00', 0),
(213, 6, 84, 4, 'Ces poèmes écrits en prison ou en fuite avec Rimbaud portent la trace d\'une vie chaotique et passionnée. Et pourtant leur forme est d\'une délicatesse et d\'une légèreté incomparables. Verlaine est unique.', '2025-02-20 14:00:00', 0),
(214, 7, 86, 3, 'Un roman de Romain Rolland moins connu que Jean-Christophe mais qui témoigne de son humanisme sincère. Colombe est un personnage attachant dans sa combativité face à l\'injustice.', '2025-01-30 10:00:00', 0),
(215, 8, 86, 3, 'Intéressant pour découvrir la France du XVIIIe siècle vue par un auteur pacifiste du XXe siècle. Rolland idéalise peut-être un peu mais c\'est fait avec une sincérité désarmante.', '2025-02-24 15:00:00', 0),
(216, 2, 88, 5, 'L\'expérience de lecture la plus extraordinaire de ma vie. La phrase de Proust — longue, sinueuse, qui revient sur elle-même — mime exactement le fonctionnement de la mémoire. Un chef-d\'œuvre absolu.', '2025-01-10 09:00:00', 0),
(217, 3, 88, 4, 'La scène de la madeleine est l\'une des plus célèbres de la littérature mondiale mais ce n\'est que la porte d\'entrée d\'un univers d\'une richesse infinie. Proust est intimidant mais la récompense est immense.', '2025-02-14 14:00:00', 0),
(218, 4, 89, 5, 'Radiguet avait vingt ans quand il a publié ce roman d\'une maturité et d\'une froideur sidérantes. La liaison entre l\'adolescent et Marthe est racontée sans romantisme ni remords — juste la vérité crue des sentiments.', '2025-01-15 10:00:00', 0);
INSERT INTO `avis` (`id`, `id_utilisateur`, `id_livre`, `note`, `commentaire`, `date_avis`, `spoiler`) VALUES
(219, 5, 89, 4, 'La mort de Marthe en couches, seule, abandonnée par son mari au front et par son amant adolescent, est d\'une cruauté parfaite. Radiguet ne cherche pas à émouvoir — il constate. C\'est encore plus dévastateur.', '2025-02-20 15:00:00', 1),
(220, 6, 90, 5, 'Un univers poétique totalement original — claustrophobique, fascinant, malsain. Cocteau crée quelque chose d\'unique avec cette chambre d\'enfants qui devient un monde complet et autosuffisant.', '2025-01-20 11:00:00', 0),
(221, 7, 90, 4, 'La jalousie d\'Élisabeth pour son frère, qu\'elle ne s\'avoue même pas, est le moteur secret de tout le roman. Cocteau explore l\'inceste symbolique avec une élégance et une pudeur parfaites.', '2025-02-25 16:00:00', 1),
(222, 8, 91, 5, 'Une révolution littéraire totale. Céline fait entrer l\'argot et la langue parlée dans la grande littérature avec une virtuosité stupéfiante. Et son regard sur la guerre, la colonisation et le capitalisme est d\'une lucidité corrosive.', '2025-01-08 09:00:00', 0),
(223, 2, 91, 4, 'Bardamu est l\'anti-héros parfait — lâche, cynique, désabusé — mais d\'une honnêteté absolue sur la condition humaine. Céline dit ce que tout le monde pense et personne n\'ose écrire.', '2025-02-10 14:00:00', 0),
(224, 3, 92, 4, 'Encore plus stylistiquement radical que le Voyage. L\'enfance de Ferdinand est un enfer de petitesse et d\'humiliation raconté avec une énergie stylistique explosive. Céline au sommet de son art.', '2025-01-12 10:00:00', 0),
(225, 4, 92, 4, 'Courtial des Pereires est l\'un des personnages les plus extraordinaires de la littérature française — un génie raté et pathétique qui finit par se faire sauter la cervelle. Céline a le génie des personnages grotesques et touchants.', '2025-02-16 15:00:00', 0),
(226, 5, 93, 5, 'Malraux écrit depuis l\'intérieur du conflit et ça se sent dans chaque page. La complexité politique des républicains espagnols — leurs désaccords fraternels autant que leur unité face au fascisme — est rendue avec une honnêteté rare.', '2025-01-14 11:00:00', 0),
(227, 6, 93, 4, 'La descente de la montagne avec les aviateurs blessés portés par les paysans est l\'une des scènes les plus belles de la littérature de guerre. La fraternité humaine face à la mort, sans discours.', '2025-02-18 16:00:00', 0),
(228, 7, 96, 5, 'Avec Le Feu de Barbusse, le grand témoignage de la Grande Guerre. Dorgelès écrit avec une tendresse et une pudeur que Barbusse n\'a pas — il aime ses soldats et ça se sent à chaque ligne.', '2025-01-16 09:00:00', 0),
(229, 8, 96, 4, 'Le titre — les croix de bois des tombes improvisées — dit tout sur la vision de Dorgelès. Pas de gloire, pas d\'héroïsme, juste des hommes ordinaires qui meurent ordinairement pour des raisons qu\'ils ne comprennent pas.', '2025-02-22 14:00:00', 0),
(230, 2, 99, 5, 'La prose dépouillée d\'Hemingway atteint ici une perfection absolue. Chaque phrase est d\'une précision et d\'une économie admirables. Et la mort de Catherine à la fin est d\'autant plus dévastatrice qu\'elle est racontée sans pathos.', '2025-01-18 10:00:00', 0),
(231, 3, 99, 4, 'La retraite de Caporetto est une scène de guerre d\'un réalisme saisissant. Hemingway montre la guerre pour ce qu\'elle est — un chaos absurde où les gens meurent par accident et par incompétence.', '2025-02-24 15:00:00', 0),
(232, 4, 100, 5, 'Le roman le plus ambitieux d\'Hemingway. Les quatre-vingt heures de Robert Jordan condensent une vie entière. Et sa mort finale — blessé, seul, attendant les fascistes pour couvrir la fuite de ses camarades — est d\'une noblesse absolue.', '2025-01-20 09:00:00', 1),
(233, 5, 100, 4, 'Pilar est l\'un des personnages féminins les plus puissants de la littérature américaine. Sa lucidité, sa force et sa loyauté contrastent magnifiquement avec le romantisme de Maria et le cynisme de Pablo.', '2025-02-26 14:00:00', 0),
(234, 6, 106, 5, 'Hemingway avait raison — toute la littérature américaine vient de ce livre. Twain invente le roman américain moderne avec sa prose directe, son humour et sa profondeur morale cachée sous une apparence de simplicité.', '2025-01-22 11:00:00', 0),
(235, 7, 106, 5, 'Le dilemme de Huck — aider Jim à s\'évader est un péché selon sa société mais c\'est la chose juste — est le moment moral le plus fort de la littérature américaine du XIXe siècle. Je vais aller en enfer dit-il. Et il aide Jim quand même.', '2025-02-28 16:00:00', 1);
INSERT INTO `liste_lecture` (`id`, `id_utilisateur`, `id_livre`, `statut`, `date_ajout`) VALUES
(3, 2, 1, 'lu', '2026-04-03 14:40:07'),
(4, 3, 1, 'lu', '2026-04-05 11:47:13'),
