INSERT INTO `livres` (`id`, `titre`, `auteur`, `genre`, `description`, `annee`, `image`, `date_ajout`) VALUES
(1, 'Harry Potter et la chambre des secrets', 'J.K. Rowling', 'Fantasy', 'Harry Potter retourne à Poudlard pour sa deuxième année d\'études. Mais dès son arrivée, un elfe de maison nommé Dobby tente de l\'empêcher d\'y retourner, prétendant que sa vie est en danger. Bientôt, des élèves sont retrouvés pétrifiés dans les couloirs du château, et des messages menaçants apparaissent sur les murs : la Chambre des Secrets a été ouverte. Harry entend une voix mystérieuse dans les murs et est soupçonné d\'être l\'Héritier de Serpentard. Avec Ron et Hermione, il mène l\'enquête dans les profondeurs du château. Un tome plus sombre et plus mystérieux que le premier, qui approfondit l\'histoire des fondateurs de Poudlard et révèle des informations cruciales sur le passé de Voldemort.', 1998, 'https://covers.openlibrary.org/b/title/Harry%20Potter%20et%20la%20chambre%20des%20secrets-L.jpg', '2026-04-02 13:52:41'),
(2, 'Harry Potter et le prisonnier d\'Azkaban', 'J.K. Rowling', 'Fantasy', 'Harry Potter entre en troisième année à Poudlard sous haute tension : Sirius Black, un dangereux criminel supposément fidèle de Voldemort, vient de s\'échapper de la forteresse imprenable d\'Azkaban. Des Détraqueurs, gardiens d\'Azkaban, sont postés autour de l\'école pour protéger les élèves. Harry apprend à les repousser grâce au professeur Lupin, son nouveau professeur de Défense contre les Forces du Mal. Mais Sirius Black semble avoir pour seul objectif de retrouver Harry. La vérité sur cette nuit où ses parents ont été tués sera bien plus complexe et bouleversante que tout ce qu\'il imaginait. Le tome considéré par beaucoup comme le meilleur de la saga, avec son intrigue temporelle magistrale et ses révélations fracassantes.', 1999, 'https://covers.openlibrary.org/b/title/Harry%20Potter%20et%20le%20prisonnier%20d\'Azkaban-L.jpg', '2026-04-02 13:52:41'),
(3, 'Harry Potter et la coupe de feu', 'J.K. Rowling', 'Fantasy', 'Harry Potter a quatorze ans quand son nom sort mystérieusement de la Coupe de Feu, le désignant comme quatrième champion du Tournoi des Trois Sorciers, une dangereuse compétition magique entre trois grandes écoles. Malgré son jeune âge et sans avoir posé sa candidature, il est contraint de participer à trois épreuves terrifiantes : affronter un dragon, plonger dans les profondeurs d\'un lac et naviguer dans un labyrinthe géant. Mais derrière ce tournoi se cache un complot bien plus sinistre. La fin du livre marque un tournant définitif dans la saga avec le retour de Voldemort dans sa forme physique. Un tome charnière, plus long et plus sombre, qui signe la fin de l\'innocence dans l\'univers de Harry Potter.', 2000, 'https://covers.openlibrary.org/b/title/Harry%20Potter%20et%20la%20coupe%20de%20feu-L.jpg', '2026-04-02 13:52:41'),
(4, 'Harry Potter et l\'ordre du phénix', 'J.K. Rowling', 'Fantasy', 'Harry Potter a quinze ans et revient à Poudlard après un été traumatisant. Le ministère de la Magie nie le retour de Voldemort et envoie Dolores Ombrage comme professeur de Défense, qui interdit tout enseignement pratique. Face à cette censure, Harry, Ron et Hermione fondent l\'Armée de Dumbledore, un groupe d\'élèves qui s\'entraînent en secret. Harry est hanté par des visions qui semblent venir de l\'esprit de Voldemort. La bataille au Ministère de la Magie sera dévastatrice. Le tome le plus long et émotionnellement le plus intense de la saga, avec la perte d\'un être cher qui marquera Harry et les lecteurs à jamais.', 2003, 'https://covers.openlibrary.org/b/title/Harry%20Potter%20et%20l\'ordre%20du%20phénix-L.jpg', '2026-04-02 13:52:41'),
(5, 'Harry Potter et le prince de sang-mêlé', 'J.K. Rowling', 'Fantasy', 'Harry Potter entre en sixième année à Poudlard dans un monde de plus en plus dangereux, où Voldemort sème la terreur ouvertement. Dumbledore prend Harry sous son aile pour des cours particuliers et l\'emmène explorer les souvenirs du passé de Voldemort, révélant le secret des Horcruxes — des objets dans lesquels il a caché des fragments de son âme pour se rendre immortel. En parallèle, Harry découvre un mystérieux manuel de potions annoté par le Prince de Sang-Mêlé. Les révélations sur Drago Malefoy et les événements de la fin du livre bouleverseront l\'univers de Poudlard pour toujours. Un tome de transition magistral qui prépare le terrain pour la conclusion épique de la saga.', 2005, 'https://covers.openlibrary.org/b/title/Harry%20Potter%20et%20le%20prince%20de%20sang-mêlé-L.jpg', '2026-04-02 13:52:41'),
(6, 'Harry Potter et les reliques de la mort', 'J.K. Rowling', 'Fantasy', 'Dans ce septième et dernier tome, Harry, Ron et Hermione renoncent à retourner à Poudlard pour partir à la chasse aux Horcruxes, les fragments d\'âme de Voldemort qu\'il faut détruire pour le rendre mortel. Seuls, sans l\'aide de Dumbledore, ils traversent une période d\'errance, de doutes et de tensions. La vérité sur Dumbledore, sur les Reliques de la Mort et sur le destin de Harry lui-même se révèle progressivement. La bataille finale de Poudlard rassemble tous les personnages de la saga pour un affrontement épique et dévastateur. Une conclusion à la hauteur de la saga : émotionnelle, courageuse et profondément satisfaisante. Un livre qui a marqué toute une génération.', 2007, 'https://covers.openlibrary.org/b/title/Harry%20Potter%20et%20les%20reliques%20de%20la%20mort-L.jpg', '2026-04-02 13:52:41'),
(7, 'Le Seigneur des Anneaux : La Communauté de l\'Anneau', 'J.R.R. Tolkien', 'Fantasy', 'Frodon Sacquet, un hobbit tranquille du Comté, hérite d\'un anneau magique de son oncle Bilbon. Mais le magicien Gandalf lui révèle que cet anneau est en réalité l\'Anneau Unique, forgé par le Seigneur des Ténèbres Sauron pour dominer tous les peuples de la Terre du Milieu. Pour le détruire, Frodon doit le porter jusqu\'à la Montagne du Destin en Mordor, le territoire même de Sauron. Une Communauté de neuf compagnons — hobbits, humains, un elfe, un nain et un magicien — se forme pour l\'accompagner. Le voyage commence, semé d\'embûches et de trahisons. Premier tome d\'une trilogie qui a révolutionné la fantasy mondiale et reste à ce jour l\'œuvre de référence du genre.', 1954, 'https://covers.openlibrary.org/b/title/Le%20Seigneur%20des%20Anneaux%20:%20La%20Communauté%20de%20l\'Anneau-L.jpg', '2026-04-02 13:52:41'),
(8, 'Le Seigneur des Anneaux : Les Deux Tours', 'J.R.R. Tolkien', 'Fantasy', 'Après la dissolution de la Communauté, les compagnons se séparent et affrontent chacun leur propre destin. Frodon et Sam poursuivent seuls leur route vers le Mordor, guidés par la créature traîtresse Gollum. Merry et Pippin, capturés par les Orques, se retrouvent dans la forêt de Fangorn où ils rencontrent les Ents. Aragorn, Legolas et Gimli parcourent les plaines du Rohan. La bataille du Gouffre de Helm oppose les forces de Saroumane à celles du roi Théoden. Un tome de transition intense qui développe les personnages secondaires et construit vers le grand affrontement final.', 1954, 'https://covers.openlibrary.org/b/title/Le%20Seigneur%20des%20Anneaux%20:%20Les%20Deux%20Tours-L.jpg', '2026-04-02 13:52:41'),
(9, 'Le Seigneur des Anneaux : Le Retour du Roi', 'J.R.R. Tolkien', 'Fantasy', 'La guerre pour la Terre du Milieu atteint son paroxysme. Les armées de l\'Ouest s\'unissent pour marcher vers les Portes Noires du Mordor dans une ultime diversion, pendant que Frodon et Sam, épuisés et trahis par Gollum, gravissent les pentes de la Montagne du Destin. La bataille des Champs du Pelennor est l\'une des plus grandes scènes épiques de la littérature. Le destin de toute la Terre du Milieu repose sur les épaules d\'un petit hobbit épuisé, incapable de résister encore longtemps au pouvoir corrupteur de l\'Anneau. Une conclusion grandiose et émouvante à l\'une des plus grandes épopées jamais écrites.', 1955, 'https://covers.openlibrary.org/b/title/Le%20Seigneur%20des%20Anneaux%20:%20Le%20Retour%20du%20Roi-L.jpg', '2026-04-02 13:52:41'),
(10, 'Le Hobbit', 'J.R.R. Tolkien', 'Fantasy', 'Bilbon Sacquet, un hobbit respectueux des conventions qui n\'aspire qu\'au confort de son foyer de Cul-de-Sac, voit sa vie bouleversée quand le magicien Gandalf et treize nains déboulonnent chez lui un soir. Il se retrouve embarqué comme cambrioleur dans une expédition vers la Montagne Solitaire pour récupérer le trésor du roi nain Thorïn, gardé par le terrible dragon Smaug. En chemin, il traverse la Forêt Noire, rencontre les elfes de Fondcombe, les créatures des Gobelines et découvre, dans les profondeurs d\'une montagne, une créature nommée Gollum et un anneau d\'or magique. Un récit d\'aventure initiatique plein d\'humour, de magie et de sagesse, prélude au Seigneur des Anneaux.', 1937, 'https://covers.openlibrary.org/b/title/Le%20Hobbit-L.jpg', '2026-04-02 13:52:41'),
(11, 'Dune', 'Frank Herbert', 'Science-Fiction', 'Sur la planète désertique Arrakis, surnommée Dune, se trouve la seule source de l\'Épice Mélange, la substance la plus précieuse de l\'univers, indispensable au voyage spatial et à la prolongation de la vie. Quand la noble maison Atréides reçoit la gestion d\'Arrakis, le jeune Paul Atréides découvre un monde hostile et ses habitants secrets, les Fremen. Trahi par ses ennemis, Paul et sa mère Jessica fuient dans le désert et rejoignent les Fremen, chez qui Paul développe des capacités prophétiques extraordinaires. Il devient Muad\'Dib, le messie attendu d\'un peuple qui va renverser l\'ordre galactique. Un roman politique, écologique et mystique d\'une profondeur et d\'une richesse incomparables.', 1965, 'https://covers.openlibrary.org/b/title/Dune-L.jpg', '2026-04-02 13:52:41'),
(12, 'Fondation', 'Isaac Asimov', 'Science-Fiction', 'Hari Seldon, mathématicien génial de l\'Empire Galactique, développe la psychohistoire, une science capable de prédire l\'avenir des civilisations à grande échelle. Ses calculs révèlent une vérité terrifiante : l\'Empire, qui règne sur des millions de planètes depuis des millénaires, est condamné à s\'effondrer dans les cinq cents prochaines années, plongeant la galaxie dans trente mille ans de barbarie et de chaos. Pour réduire cette période à mille ans seulement, Seldon fonde la Fondation, un groupe de savants chargés de préserver et de transmettre tout le savoir humain. Après la mort de Seldon, la Fondation doit faire face seule à des crises successives, chacune prévue et résolue par le génie posthume de son fondateur à travers des messages enregistrés. Un roman de science-fiction politique d\'une intelligence rare, qui explore les mécanismes du pouvoir, de la religion et du commerce comme outils de domination et de survie civilisationnelle.', 1951, 'https://covers.openlibrary.org/b/title/Fondation-L.jpg', '2026-04-02 13:52:41'),
(13, 'Le Meilleur des Mondes', 'Aldous Huxley', 'Dystopie', 'Dans un futur lointain, l\'humanité a atteint la stabilité parfaite grâce au conditionnement génétique et psychologique dès la conception. Les êtres humains sont produits en série dans des centres d\'incubation, classés en castes de l\'alpha au epsilon, chacune conditionnée pour aimer son rôle social. La consommation est une vertu, la solitude un vice, et le soma — une drogue du bonheur sans effets secondaires — permet d\'éviter toute souffrance. Bernard Marx, un alpha légèrement déviant, emmène Lenina en voyage dans une Réserve de Sauvages où vivent encore des humains selon les anciennes traditions. Il en ramène John, un jeune homme élevé selon les valeurs de Shakespeare, qui va se heurter violemment à cette civilisation du bonheur artificiel. Huxley pose une question dérangeante et toujours actuelle : préférons-nous la liberté avec ses souffrances, ou le bonheur avec ses chaînes ?', 1932, 'https://covers.openlibrary.org/b/title/Le%20Meilleur%20des%20Mondes-L.jpg', '2026-04-02 13:52:41'),
(14, 'Fahrenheit 451', 'Ray Bradbury', 'Dystopie', 'Dans une Angleterre futuriste où les livres sont interdits et brûlés par des pompiers spéciaux, Guy Montag est l\'un de ces pompiers pyromanes. Sa rencontre avec Clarisse, une jeune femme libre et curieuse, le pousse à remettre en question sa vie et le monde dans lequel il vit. Il commence à cacher et lire des livres, s\'engageant dans une rébellion dangereuse contre un système qui préfère le divertissement à la réflexion. Un roman prophétique sur la censure et l\'abrutissement des masses.', 1953, 'https://covers.openlibrary.org/b/title/Fahrenheit%20451-L.jpg', '2026-04-02 13:52:41'),
(15, 'La Ferme des animaux', 'George Orwell', 'Dystopie', 'Dans une ferme anglaise, les animaux se révoltent contre leur fermier Mr Jones, alcoolique et négligent, sous l\'impulsion des cochons, les plus intelligents d\'entre eux. Ils chassent l\'homme et établissent une République animale fondée sur sept commandements, dont le plus célèbre : Tous les animaux sont égaux. Les cochons, menés par Napoléon et Boule de Neige, prennent naturellement les rênes du pouvoir. Mais peu à peu, Napoléon, aidé de ses chiens-gardes du corps, élimine ses rivaux, réécrit l\'histoire et modifie les commandements au profit des cochons. Le commandement final devient : Tous les animaux sont égaux, mais certains sont plus égaux que d\'autres. Allégorie politique transparente visant le stalinisme soviétique, La Ferme des Animaux est une fable d\'une précision glaçante sur la corruption du pouvoir révolutionnaire et la trahison des idéaux.', 1945, 'https://covers.openlibrary.org/b/title/La%20Ferme%20des%20animaux-L.jpg', '2026-04-02 13:52:41'),
(16, 'Crime et Châtiment', 'Fiodor Dostoïevski', 'Roman', 'Dans les rues de Saint-Pétersbourg au XIXe siècle, Raskolnikov développe une théorie philosophique dangereuse : certains hommes extraordinaires, comme Napoléon, sont au-dessus des lois morales ordinaires et peuvent commettre des crimes pour servir un but supérieur. Pour se prouver qu\'il est l\'un de ces hommes supérieurs, il assassine une vieille usurière et sa sœur innocente. Mais au lieu de la liberté espérée, il sombre dans un enfer psychologique. L\'inspecteur Porphyre joue avec lui comme un chat avec une souris. Sa rencontre avec Sonia, prostituée profondément croyante, va lentement le conduire vers la confession et la rédemption. Un roman magistral sur la culpabilité et la nature humaine.', 1866, 'https://covers.openlibrary.org/b/title/Crime%20et%20Châtiment-L.jpg', '2026-04-02 13:52:41'),
(17, 'Le Maître et Marguerite', 'Mikhaïl Boulgakov', 'Roman', 'Dans le Moscou des années 1930, sous Staline, le diable en personne — accompagné de sa suite démoniaque dont le mystérieux chat noir Béhémoth — débarque sous les traits du professeur Woland et sème la terreur et le chaos parmi les apparatchiks soviétiques, les directeurs de théâtre et les bureaucrates corrompus. En parallèle, un roman dans le roman raconte la rencontre entre Ponce Pilate et Yeshoua Ha-Nozri — le Christ — à Jérusalem, et le dilemme moral qui conduit à la crucifixion. Un troisième fil narratif suit le Maître, un écrivain dont le roman sur Pilate a été rejeté et brûlé, et Marguerite, sa maîtresse passionnée qui conclura un pacte avec le diable pour le sauver. Chef-d\'œuvre de la littérature russe censuré pendant des décennies, Le Maître et Marguerite est une satire féroce du totalitarisme soviétique mêlée de fantastique, d\'amour absolu et de questions métaphysiques profondes.', 1967, 'https://covers.openlibrary.org/b/title/Le%20Maître%20et%20Marguerite-L.jpg', '2026-04-02 13:52:41'),
(18, 'Anna Karénine', 'Léon Tolstoï', 'Roman', 'Anna Karénine, belle et intelligente épouse d\'un haut fonctionnaire de Saint-Pétersbourg, rencontre le séduisant comte Vronski lors d\'un voyage en train. Une passion irrésistible naît entre eux. Malgré son amour pour son fils, Anna quitte son mari pour vivre avec Vronski, s\'attirant le rejet de la bonne société russe. Rongée par la jalousie et l\'angoisse d\'être abandonnée, leur relation se dégrade progressivement. En parallèle, le roman suit Lévine, un propriétaire terrien philosophe qui cherche le sens de la vie à travers le travail de la terre, l\'amour et la foi. Deux histoires en miroir sur le bonheur, la liberté, la société et les contradictions de l\'âme humaine, considéré par beaucoup comme le plus grand roman jamais écrit.', 1877, 'https://covers.openlibrary.org/b/title/Anna%20Karénine-L.jpg', '2026-04-02 13:52:41'),
(19, 'Guerre et Paix', 'Léon Tolstoï', 'Roman historique', 'Guerre et Paix suit cinq familles aristocratiques russes — les Bolkonski, les Rostov, les Bezoukhov, les Kouraguine et les Drubetzkoï — à travers les guerres napoléoniennes de 1805 à 1812, culminant avec l\'invasion de la Russie et l\'incendie de Moscou. Le prince André Bolkonski cherche la gloire militaire avant de trouver la paix intérieure. Pierre Bezoukhov, héritier maladroit et idéaliste, traverse une crise spirituelle profonde. La jeune Natacha Rostova incarne la joie de vivre et la passion. Tolstoï entremêle ces destinées individuelles avec une réflexion philosophique sur le rôle des individus dans l\'histoire, contestant la vision héroïque de Napoléon et affirmant que les grandes forces historiques échappent au contrôle des hommes. Une fresque monumentale de plus de mille cinq cents pages, considérée comme l\'un des plus grands romans jamais écrits, d\'une richesse psychologique et historique inégalée.', 1869, 'https://covers.openlibrary.org/b/title/Guerre%20et%20Paix-L.jpg', '2026-04-02 13:52:41'),
(20, 'Don Quichotte', 'Miguel de Cervantes', 'Roman', 'Alonso Quijano, un gentilhomme campagnard de la Manche d\'une cinquantaine d\'années, a tellement lu de romans de chevalerie qu\'il perd la raison et se prend pour un chevalier errant. Il se rebaptise Don Quichotte de la Manche, revêt une vieille armure rouillée, enfourche son cheval efflanqué Rossinante et part à l\'aventure pour défendre les opprimés et servir sa dame imaginaire Dulcinée du Toboso. Il convainc un paysan voisin, le bon Sancho Panza, de l\'accompagner comme écuyer en lui promettant le gouvernement d\'une île. Leurs aventures délirants — les moulins à vent pris pour des géants, les moutons pour des armées — confrontent sans cesse l\'idéalisme fou de Don Quichotte à la réalité prosaïque de Sancho. Publié en deux parties en 1605 et 1615, Don Quichotte est considéré comme le premier roman moderne et l\'une des œuvres les plus importantes de la littérature mondiale.', 1605, 'https://covers.openlibrary.org/b/title/Don%20Quichotte-L.jpg', '2026-04-02 13:52:41'),
(21, 'Madame Bovary', 'Gustave Flaubert', 'Roman', 'Emma Rouault, fille d\'un riche fermier normand élevée dans un couvent, épouse Charles Bovary, un médecin de campagne sans ambition et sans imagination. Nourrie de romans romantiques et de rêves de passion, elle s\'ennuie profondément dans sa vie provinciale et cherche à en sortir. Elle se lance dans deux aventures amoureuses successives avec Rodolphe, un séducteur cynique, puis Léon, un jeune clerc de notaire. Pour entretenir ses illusions de luxe et de grandeur, elle s\'endette secrètement jusqu\'à la ruine. Flaubert signe avec ce roman un chef-d\'œuvre du réalisme qui analyse avec une précision chirurgicale le désenchantement, les illusions perdues et la condition des femmes au XIXe siècle.', 1857, 'https://covers.openlibrary.org/b/title/Madame%20Bovary-L.jpg', '2026-04-02 13:52:41'),
(22, 'Le Rouge et le Noir', 'Stendhal', 'Roman', 'Julien Sorel, fils d\'un charpentier de province, est un jeune homme ambitieux et intelligent qui admire Napoléon mais vit sous la Restauration où seule l\'Église offre des possibilités d\'ascension sociale aux roturiers. Engagé comme précepteur chez les Rênal, il séduit Madame de Rênal par calcul avant de tomber véritablement amoureux d\'elle. Monté à Paris comme secrétaire du marquis de La Mole, il conquiert aussi le cœur de Mathilde, la fille de son employeur. Mais ses origines modestes et ses ambitions démesurées le conduiront à sa perte. Un roman d\'apprentissage et d\'analyse psychologique brillante sur l\'ambition, l\'hypocrisie sociale et la quête d\'identité dans la France post-napoléonienne.', 1830, 'https://covers.openlibrary.org/b/title/Le%20Rouge%20et%20le%20Noir-L.jpg', '2026-04-02 13:52:41'),
(23, 'Germinal', 'Émile Zola', 'Roman', 'Étienne Lantier arrive à Montsou, dans le nord de la France, et trouve du travail dans la mine de charbon. Il découvre les conditions de vie et de travail épouvantables des mineurs : salaires de misère, accidents mortels, enfants qui travaillent dès l\'âge de dix ans, familles entières qui crèvent de faim. Révolté par cette injustice, il lit des théories socialistes et organise peu à peu une grève. La confrontation entre les mineurs affamés et les propriétaires de la mine soutenus par l\'armée sera violente et tragique. Zola signe avec Germinal son roman le plus puissant, une fresque sociale d\'une force extraordinaire sur la lutte des classes et la condition ouvrière au XIXe siècle.', 1885, 'https://covers.openlibrary.org/b/title/Germinal-L.jpg', '2026-04-02 13:52:41'),
(24, 'Nana', 'Émile Zola', 'Roman', 'Nana, de son vrai prénom Anna Coupeau, est la fille de Gervaise et de Coupeau dont on a suivi la déchéance dans L\'Assommoir. Devenue actrice de théâtre sans vrai talent mais d\'une beauté et d\'un charme irrésistibles, elle fait une entrée fracassante sur la scène parisienne. Elle devient rapidement la grande courtisane du Second Empire, entretenue par des hommes riches et titrés qu\'elle ruine les uns après les autres avec une indifférence totale. Le comte Muffat, chambellan de l\'Impératrice et homme profondément religieux, tombe sous son emprise et se dégrade jusqu\'à ramper devant elle. Nana dépense des fortunes, accumule les amants et les dettes, et finit par mourir seule de la variole dans une chambre d\'hôtel, défigurée, tandis que la foule crie Guerre ! Guerre ! dans la rue — le début de la guerre de 1870. Zola fait de Nana le symbole de la décomposition du Second Empire.', 1880, 'https://covers.openlibrary.org/b/title/Nana-L.jpg', '2026-04-02 13:52:41'),
(25, 'Au Bonheur des Dames', 'Émile Zola', 'Roman', 'Octave Mouret, le séducteur bourgeois de Pot-Bouille, est devenu le génie du commerce moderne. Il a transformé un petit magasin de nouveautés en un immense grand magasin parisien, Le Bonheur des Dames, véritable cathédrale du commerce moderne. Sa stratégie est révolutionnaire : prix bas, vente à perte sur certains articles pour attirer les foules, retours acceptés, publicité massive. Denise Baudu, une jeune provinciale arrivée à Paris avec ses deux frères, entre comme vendeuse au magasin malgré l\'opposition de son oncle, petit drapier voisin ruiné par la concurrence. Mouret, qui manipule les femmes avec mépris, tombe amoureux de la douce et déterminée Denise. Zola analyse avec précision la naissance de la société de consommation moderne, la destruction du petit commerce par les grandes surfaces et la condition des employés de commerce au XIXe siècle.', 1883, 'https://covers.openlibrary.org/b/title/Au%20Bonheur%20des%20Dames-L.jpg', '2026-04-02 13:52:41'),
(26, 'Le Père Goriot', 'Honoré de Balzac', 'Roman', 'Le père Goriot, ancien vermicellier enrichi dans le commerce des pâtes, a tout sacrifié pour ses deux filles Anastasie et Delphine qu\'il adore aveuglément. Installé dans la pension Vauquer à Paris après avoir dilapidé toute sa fortune pour payer les dettes et les caprices de ses filles ingrates, il est méprisé par tous les pensionnaires. Eugène de Rastignac, jeune étudiant en droit ambitieux qui cherche à percer dans la société parisienne, observe avec horreur et fascination ce sacrifice paternel sans limites. Balzac dresse un portrait impitoyable de la société parisienne sous la Restauration, dominée par l\'argent, l\'ambition et l\'ingratitude.', 1835, 'https://covers.openlibrary.org/b/title/Le%20Père%20Goriot-L.jpg', '2026-04-02 13:52:41'),
(27, 'Eugénie Grandet', 'Honoré de Balzac', 'Roman', 'Eugénie Grandet vit à Saumur avec son père Félix Grandet, tonnelier enrichi devenu l\'homme le plus riche de la région, mais d\'une avarice maladive et tyrannique. Sa vie monotone est bouleversée par l\'arrivée de son cousin Charles Grandet, un jeune Parisien élégant et frivole. Eugénie tombe éperdument amoureuse de lui et lui donne toutes ses économies pour l\'aider après la ruine et le suicide de son père. Charles part aux Indes chercher fortune en promettant de revenir l\'épouser. Mais il revient riche, corrompu par l\'argent et les ambitions sociales, et abandonne Eugénie pour épouser une femme de la noblesse. Eugénie, héritière de la fortune colossale de son père décédé, reste seule, fidèle à un amour trahi, consacrant sa richesse à des œuvres charitables. Balzac signe un roman poignant sur l\'avarice, le sacrifice et la corruption de l\'âme par l\'argent.', 1833, 'https://covers.openlibrary.org/b/title/Eugénie%20Grandet-L.jpg', '2026-04-02 13:52:41'),
(28, 'La Chartreuse de Parme', 'Stendhal', 'Roman', 'Fabrice del Dongo, jeune aristocrate milanais idéaliste et passionné, est le neveu de la Sanseverina, une femme remarquable qui l\'adore. Il fuit en France pour rejoindre Napoléon à Waterloo mais ne comprend pas grand chose à la bataille confuse qu\'il traverse. Revenu en Italie sous la domination autrichienne, il entre dans les ordres tout en vivant d\'aventures amoureuses et politiques. Emprisonné dans la tour Farnèse de Parme, il tombe amoureux de Clélia Conti, la fille du gouverneur de la prison. La Sanseverina et le comte Mosca manœuvrent dans les intrigues de la cour de Parme pour le libérer. Stendhal crée avec ce roman une œuvre d\'une vitalité et d\'une liberté extraordinaires, mêlant ironie et passion, politique et amour, dans une Italie baroque et corrompue. L\'un des romans français les plus aimés pour son énergie et sa légèreté.', 1839, 'https://covers.openlibrary.org/b/title/La%20Chartreuse%20de%20Parme-L.jpg', '2026-04-02 13:52:41'),
(29, 'Notre-Dame de Paris', 'Victor Hugo', 'Roman historique', 'En 1482, Paris est dominée par la cathédrale Notre-Dame de Paris dont le sonneur de cloches est Quasimodo, un être difforme et sourd rejeté par tous. Il vénère secrètement la belle Esméralda, une danseuse gitane qui charme tout Paris avec sa grâce et sa chèvre Djali. L\'archidiacre Frollo, torturé par une passion coupable pour Esméralda, la fait enlever par Quasimodo. Sauvée par le capitaine Phœbus dont elle tombe amoureuse, Esméralda est accusée de sorcellerie et condamnée à mort. Quasimodo, découvrant la véritable nature de Frollo, accomplit un acte ultime de justice. Un roman historique sur la beauté, la laideur, le fanatisme et la compassion.', 1831, 'https://covers.openlibrary.org/b/title/Notre-Dame%20de%20Paris-L.jpg', '2026-04-02 13:52:41'),
(30, 'Le Comte de Monte-Cristo', 'Alexandre Dumas', 'Roman', 'Le jeune Santiago, après avoir été emprisonné injustement, s\'évade du château d\'If avec l\'aide de l\'abbé Faria. Devenu le richissime comte de Monte-Cristo, il orchestre pendant des années une vengeance minutieuse contre Fernand Mondego qui a épousé sa fiancée Mercédès, Danglars qui l\'a dénoncé par jalousie, et Villefort le procureur qui l\'a condamné par intérêt personnel. Déguisé sous différentes identités à Paris, il s\'infiltre dans la haute société et détruit méthodiquement ses ennemis en utilisant leurs propres vices contre eux. Une saga romanesque magistrale sur la justice, la vengeance et les limites du droit humain de punir.', 1844, 'https://covers.openlibrary.org/b/title/Le%20Comte%20de%20Monte-Cristo-L.jpg', '2026-04-02 13:52:41'),
(31, 'Les Trois Mousquetaires', 'Alexandre Dumas', 'Roman', 'D\'Artagnan, jeune Gascon de dix-huit ans plein d\'ardeur et d\'ambition, monte à Paris pour rejoindre les mousquetaires du roi. Il se lie rapidement d\'amitié avec Athos, Porthos et Aramis, trois mousquetaires aux caractères très différents mais unis par la devise : Un pour tous, tous pour un. Ensemble, ils affrontent le cardinal de Richelieu et son agent, la mystérieuse et dangereuse Milady de Winter, pour défendre l\'honneur de la reine Anne d\'Autriche. Une aventure palpitante pleine de duels, d\'intrigues politiques et d\'amours contrariées dans le Paris du XVIIe siècle. Le roman de cape et d\'épée par excellence.', 1844, 'https://covers.openlibrary.org/b/title/Les%20Trois%20Mousquetaires-L.jpg', '2026-04-02 13:52:41'),
(32, 'Vingt Mille Lieues sous les Mers', 'Jules Verne', 'Science-Fiction', 'Le professeur Aronnax, naturaliste au Muséum de Paris, est embarqué dans une expédition pour identifier un mystérieux monstre marin qui terrorise les mers du monde entier. Après avoir été jeté par-dessus bord lors d\'une collision, il découvre que le monstre est en réalité le Nautilus, un sous-marin extraordinaire commandé par le mystérieux capitaine Nemo, génie solitaire qui a renoncé à la société humaine. Prisonnier à bord, Aronnax explore avec émerveillement les fonds marins, les épaves, les forêts de corail et les cités englouties. Verne imagine avec une précision stupéfiante des technologies qui n\'existeront que des décennies plus tard.', 1870, 'https://covers.openlibrary.org/b/title/Vingt%20Mille%20Lieues%20sous%20les%20Mers-L.jpg', '2026-04-02 13:52:41'),
(33, 'Le Tour du Monde en Quatre-Vingts Jours', 'Jules Verne', 'Aventure', 'Phileas Fogg, gentleman anglais excentrique et méthodique, parie avec ses amis du Reform Club la somme de vingt mille livres sterling qu\'il peut faire le tour du monde en quatre-vingts jours exactement. Accompagné de son nouveau valet français Passepartout, il part le soir même de Londres. De Paris à Suez, de Bombay à Calcutta, de Singapour à Yokohama, de San Francisco à New York, le voyage est semé d\'obstacles imprévus. L\'inspecteur Fix, convaincu que Fogg est un cambrioleur en fuite, le pourchasse tout autour du globe. Un roman d\'aventures trépidant qui célèbre le progrès technique du XIXe siècle et l\'esprit d\'aventure.', 1872, 'https://covers.openlibrary.org/b/title/Le%20Tour%20du%20Monde%20en%20Quatre-Vingts%20Jours-L.jpg', '2026-04-02 13:52:41'),
(34, 'Voyage au Centre de la Terre', 'Jules Verne', 'Aventure', 'Le professeur Otto Lidenbrock, géologue passionné et impétueux, déchiffre un vieux parchemin islandais du XVIe siècle indiquant qu\'un passage vers le centre de la Terre existe à travers le cratère du volcan Sneffels en Islande. Accompagné de son neveu Axel — le narrateur — et du guide islandais Hans, il s\'enfonce dans les profondeurs de la Terre. Ils traversent des galeries immenses, découvrent une mer souterraine sur laquelle ils naviguent, rencontrent des forêts de champignons géants et des créatures préhistoriques. L\'aventure les conduira jusqu\'à un geyser volcanique qui les expulsera violemment à la surface en Italie. Jules Verne imagine avec une précision scientifique remarquable pour son époque un monde souterrain fascinant et peuplé de merveilles. Un roman d\'aventure fondateur qui a inspiré des générations de lecteurs et d\'écrivains.', 1864, 'https://covers.openlibrary.org/b/title/Voyage%20au%20Centre%20de%20la%20Terre-L.jpg', '2026-04-02 13:52:41'),
(35, 'De la Terre à la Lune', 'Jules Verne', 'Science-Fiction', 'Le Gun Club de Baltimore, association d\'anciens artilleurs américains désœuvrés depuis la fin de la guerre de Sécession, décide de réaliser la plus grande expérience balistique de l\'histoire : envoyer un boulet habité sur la Lune. Impey Barbicane, président du club, propose de construire la Columbiad, un canon géant de deux cents mètres de long. L\'aventurier Michel Ardan, un Français excentrique, propose d\'embarquer dans le projectile avec Barbicane et son rival Nicholl. Verne décrit avec une précision étonnante le voyage spatial — la capsule cylindro-conique, le lancement depuis la Floride, l\'apesanteur — anticipant de cent ans les missions Apollo. Le roman se termine en suspense, sans que les voyageurs n\'atteignent la Lune. La suite est racontée dans Autour de la Lune. Une œuvre visionnaire qui a fasciné les ingénieurs de la NASA.', 1865, 'https://covers.openlibrary.org/b/title/De%20la%20Terre%20à%20la%20Lune-L.jpg', '2026-04-02 13:52:41'),
(36, 'Sherlock Holmes : Une étude en rouge', 'Arthur Conan Doyle', 'Policier', 'Le docteur John Watson, rentrant d\'Afghanistan où il a été blessé, cherche à partager un logement à Londres et est présenté à Sherlock Holmes, un homme singulier qui se présente comme consultant en détective. Ils s\'installent ensemble au 221B Baker Street. Holmes est bientôt contacté par la police qui a découvert le cadavre d\'un homme bien habillé dans une maison abandonnée de Brixton, avec le mot RACHE écrit en lettres de sang sur le mur. La victime est un Américain, Enoch Drebber. Holmes mène l\'enquête avec une logique déductive époustouflante, reconstituant le passé du criminel à partir d\'indices imperceptibles. L\'histoire bascule vers l\'Utah des mormons en 1847 pour raconter les origines du crime. La première apparition de Sherlock Holmes dans la littérature, qui a donné naissance au personnage fictif le plus célèbre de l\'histoire.', 1887, 'https://covers.openlibrary.org/b/title/Sherlock%20Holmes%20:%20Une%20étude%20en%20rouge-L.jpg', '2026-04-02 13:52:41'),
(37, 'Sherlock Holmes : Le Chien des Baskerville', 'Arthur Conan Doyle', 'Policier', 'Sir Henry Baskerville vient d\'hériter du domaine familial dans les landes du Devonshire après la mort mystérieuse de son oncle Sir Charles, retrouvé mort de peur près d\'une immense empreinte de patte de chien. La famille Baskerville est maudite depuis le XVIIe siècle par un chien démoniaque, châtiment divin pour les crimes du diabolique Hugo Baskerville. Sherlock Holmes, trop occupé à Londres, envoie Watson accompagner Sir Henry dans les landes sinistres et brumeuses. Watson observe les voisins suspects, les bagnards évadés et l\'énigmatique Stapleton. Holmes arrive au dernier moment pour dénouer l\'intrigue dans un finale haletant sur la lande dans le brouillard. Le roman policier gothique par excellence, mêlant atmosphère de terreur, mystère surnaturel et déduction rationnelle. Considéré comme la meilleure aventure de Sherlock Holmes.', 1902, 'https://covers.openlibrary.org/b/title/Sherlock%20Holmes%20:%20Le%20Chien%20des%20Baskerville-L.jpg', '2026-04-02 13:52:41'),
(38, 'Et puis il n\'en resta plus aucun', 'Agatha Christie', 'Policier', 'Dix inconnus reçoivent des invitations mystérieuses pour séjourner sur l\'île du Nègre, une île isolée au large des côtes anglaises. À peine arrivés, une voix enregistrée les accuse chacun d\'un meurtre pour lequel ils n\'ont jamais été jugés. Le soir même, l\'un d\'eux meurt. Puis un autre. Les meurtres se succèdent selon la comptine des Dix Petits Nègres affichée dans chaque chambre. Les survivants, incapables de s\'échapper de l\'île, réalisent que le meurtrier est forcément parmi eux. Un roman policier parfait, au suspense haletant et au dénouement inattendu, considéré comme le roman policier le plus vendu de tous les temps.', 1939, 'https://covers.openlibrary.org/b/title/Et%20puis%20il%20n\'en%20resta%20plus%20aucun-L.jpg', '2026-04-02 13:52:41'),
(39, 'Le Meurtre de Roger Ackroyd', 'Agatha Christie', 'Policier', 'Hercule Poirot, le célèbre détective belge aux petites cellules grises, se retire dans le village anglais de King\'s Abbot après sa retraite. Lorsque Roger Ackroyd, un riche industriel, est retrouvé assassiné dans son bureau verrouillé de l\'intérieur le soir même où il avait reçu une lettre révélant l\'identité du meurtrier de sa maîtresse, Poirot est contraint de reprendre du service. Il interroge méthodiquement chaque habitant du village, tous suspects potentiels. Le dénouement est l\'un des plus audacieux et controversés de toute l\'histoire du roman policier, Agatha Christie prenant un risque narratif sans précédent qui a choqué et fasciné les lecteurs.', 1926, 'https://covers.openlibrary.org/b/title/Le%20Meurtre%20de%20Roger%20Ackroyd-L.jpg', '2026-04-02 13:52:41'),
(40, 'Mort sur le Nil', 'Agatha Christie', 'Policier', 'Hercule Poirot, en croisière sur le Nil à bord du Karnak, se retrouve mêlé à une affaire de meurtre qui semblait impossible. Linnet Ridgeway, une jeune femme riche et belle, vient d\'épouser Simon Doyle en volant à son amie Jacqueline de Bellefort son fiancé. Jacqueline les suit dans leur voyage de noces jusqu\'en Égypte, les harcelant de sa présence. Mais lorsque Linnet est retrouvée morte d\'une balle dans la tête au cours de la nuit, Jacqueline a un alibi parfait. Poirot doit démêler un écheveau d\'histoires personnelles, de jalousies et de secrets parmi les passagers du bateau, tous suspects potentiels. Christie démontre une fois de plus son génie de la construction narrative avec un dénouement brillant et inattendu. Un roman policier solaire et élégant dans le cadre splendide de l\'Égypte antique.', 1937, 'https://covers.openlibrary.org/b/title/Mort%20sur%20le%20Nil-L.jpg', '2026-04-02 13:52:41'),
(41, 'La Nausée', 'Jean-Paul Sartre', 'Roman', 'Antoine Roquentin, historien solitaire qui travaille sur la biographie d\'un aventurier du XVIIIe siècle dans la ville fictive de Bouville, commence à ressentir une étrange et envahissante sensation de malaise face aux objets qui l\'entourent. Une racine d\'arbre dans un jardin public déclenche en lui une révélation fondamentale : l\'existence est contingente, sans raison ni justification, profondément absurde. Les êtres humains qui l\'entourent, les Salauds, se mentent à eux-mêmes en croyant que leur existence est nécessaire et justifiée. Premier roman de Sartre, La Nausée est le manifeste littéraire de l\'existentialisme, une plongée vertigineuse dans la conscience d\'un homme qui découvre l\'absurdité fondamentale de l\'être.', 1938, 'https://covers.openlibrary.org/b/title/La%20Nausée-L.jpg', '2026-04-02 13:52:41'),
(42, 'Les Mains Sales', 'Jean-Paul Sartre', 'Roman', 'Hugo Barine, dit Hoederer, est un leader communiste charismatique et pragmatique qui accepte de former une coalition avec des partis bourgeois pour préparer l\'après-guerre dans un pays d\'Europe de l\'Est fictif, Illyrie. Le Parti, jugeant cette stratégie traîtresse, décide de l\'assassiner et envoie le jeune idéaliste Hugo, accompagné de sa femme Jessica, comme secrétaire auprès de Hoederer — en réalité pour le tuer. Mais au contact de Hoederer, Hugo est fasciné par sa force et sa lucidité politique. Il hésite, tergiversé, tandis que Jessica flirte avec Hoederer. Hugo finira par tirer, mais pour de mauvaises raisons. Des années plus tard, sorti de prison, Hugo doit décider si son acte était politique ou passionnel. Sartre pose à travers cette pièce des questions fondamentales sur la morale politique, la fin et les moyens, et la responsabilité de l\'intellectuel engagé.', 1948, 'https://covers.openlibrary.org/b/title/Les%20Mains%20Sales-L.jpg', '2026-04-02 13:52:41'),
(43, 'La Peste', 'Albert Camus', 'Roman', 'La ville d\'Oran, sur la côte algérienne, est frappée par une épidémie de peste bubonique qui la coupe du reste du monde. Le docteur Rieux, personnage central du roman, reste en ville pour soigner les malades avec ses collègues, dont le journaliste Rambert qui cherche désespérément à rejoindre sa femme à Paris, et Tarrou, un homme mystérieux qui organise des équipes de volontaires sanitaires. Face à la mort omniprésente, chaque personnage révèle sa vraie nature. Camus utilise l\'épidémie comme métaphore de l\'occupation nazie et plus universellement de tout mal collectif. Un roman sur la solidarité humaine, le courage ordinaire et l\'absurde condition humaine face à la mort.', 1947, 'https://covers.openlibrary.org/b/title/La%20Peste-L.jpg', '2026-04-02 13:52:41'),
(44, 'Le Mythe de Sisyphe', 'Albert Camus', 'Philosophie', 'Le Mythe de Sisyphe est l\'essai philosophique fondateur d\'Albert Camus sur l\'absurde, publié en 1942 en même temps que L\'Étranger. Camus part d\'une question radicale : pourquoi ne pas se suicider si la vie n\'a pas de sens ? Il développe la notion d\'absurde — la confrontation entre le besoin humain de clarté et de sens et le silence irrationnel du monde. Face à l\'absurde, trois réponses sont possibles : le suicide physique, le suicide philosophique qui consiste à se réfugier dans la foi ou l\'idéologie, et la révolte — continuer à vivre en maintenant la tension absurde. Sisyphe, condamné par les dieux à pousser éternellement son rocher jusqu\'au sommet avant de le voir redescendre, est le héros absurde par excellence. Il faut imaginer Sisyphe heureux, conclut Camus. Un texte court et dense qui a bouleversé la philosophie du XXe siècle.', 1942, 'https://covers.openlibrary.org/b/title/Le%20Mythe%20de%20Sisyphe-L.jpg', '2026-04-02 13:52:41'),
(45, 'Candide', 'Voltaire', 'Roman', 'Candide, jeune homme naïf élevé dans le château du baron Thunder-ten-tronckh en Westphalie, a été formé par le philosophe Pangloss à croire que tout va pour le mieux dans le meilleur des mondes possibles. Chassé du château pour avoir embrassé la belle Cunégonde, il traverse l\'Europe, l\'Amérique du Sud et le Proche-Orient en subissant une série de catastrophes : guerres, inquisition, tremblements de terre, esclavage, naufrages. Chaque épreuve met à mal l\'optimisme béat de Pangloss. Conte philosophique mordant et satirique, Candide est une critique virulente de l\'optimisme leibnizien, de la guerre, de l\'Église, de l\'esclavage et des illusions métaphysiques.', 1759, 'https://covers.openlibrary.org/b/title/Candide-L.jpg', '2026-04-02 13:52:41'),
(46, 'Les Liaisons Dangereuses', 'Pierre Choderlos de Laclos', 'Roman', 'La marquise de Merteuil et le vicomte de Valmont, deux aristocrates libertins de l\'Ancien Régime, utilisent la séduction comme arme de pouvoir et de vengeance. La Merteuil demande à Valmont de séduire et de déshonorer Cécile de Volanges, une jeune ingénue fraîchement sortie du couvent, pour se venger de son ancien amant qui l\'épouse. Mais Valmont a un défi plus stimulant : conquérir la vertueuse et dévote présidente de Tourvel, dont la résistance l\'obsède. À travers un échange de lettres brillantes et cruelles, les deux complices manœuvrent leurs victimes comme des marionnettes. Mais leurs jeux dangereux finissent par se retourner contre eux. Roman épistolaire d\'une sophistication et d\'une perversité remarquables, Les Liaisons Dangereuses est une analyse implacable de la manipulation, du pouvoir et de la destruction dans une société aristocratique condamnée.', 1782, 'https://covers.openlibrary.org/b/title/Les%20Liaisons%20Dangereuses-L.jpg', '2026-04-02 13:52:41'),
(47, 'Manon Lescaut', 'Abbé Prévost', 'Roman', 'Le chevalier Des Grieux, jeune homme de bonne famille se destinant à l\'Église, rencontre par hasard Manon Lescaut à Amiens alors qu\'elle est conduite vers un couvent. Il tombe immédiatement et éperdument amoureux de cette jeune femme d\'une beauté et d\'un charme irrésistibles. Il l\'enlève et ils s\'enfuient à Paris pour vivre leur amour. Mais Manon, qui aime sincèrement Des Grieux, ne peut résister à son goût du luxe et de la facilité — elle accepte les cadeaux de riches protecteurs tout en revenant toujours vers Des Grieux. Leur relation est une succession de ruptures, de réconciliations, de trahisons et de pardons. Ils sombrent progressivement dans la déchéance, la prison et finalement la déportation en Louisiane où Manon mourra dans les bras de Des Grieux. Un roman d\'amour fatal et absolu, fondateur du romantisme français, sur l\'esclavage de la passion.', 1731, 'https://covers.openlibrary.org/b/title/Manon%20Lescaut-L.jpg', '2026-04-02 13:52:41'),
(48, 'Paul et Virginie', 'Bernardin de Saint-Pierre', 'Roman', 'Sur l\'île de France — l\'actuelle île Maurice — deux enfants, Paul et Virginie, grandissent ensemble dans une nature paradisiaque sous la garde de leurs mères, deux femmes qui ont fui la société française corrompue. Elevés dans l\'innocence, la simplicité et l\'amour de la nature, ils tombent naturellement amoureux l\'un de l\'autre avec une pureté absolue. Mais la famille de Virginie en France, une tante riche et sans enfants, réclame sa nièce pour l\'éduquer selon les règles de la bonne société. Virginie part malgré elle. Deux ans plus tard, elle revient par bateau mais un ouragan s\'abat sur le navire au large de l\'île. Paul la voit depuis la plage. Elle refuse qu\'un matelot la sauve en la déshabillant pour nager — et se noie pudiquement. Bernardin de Saint-Pierre signe un roman sentimental d\'une beauté lyrique sur l\'innocence, la nature et la corruption de la civilisation.', 1788, 'https://covers.openlibrary.org/b/title/Paul%20et%20Virginie-L.jpg', '2026-04-02 13:52:41'),
(49, 'Atala', 'François-René de Chateaubriand', 'Roman', 'Chactas, un jeune Natchez de Louisiane, a été capturé par les Muscogulges, tribu ennemie, et est condamné à mort. Il est sauvé par Atala, une jeune chrétienne mi-indienne mi-espagnole d\'une beauté extraordinaire qui fuit avec lui dans les forêts sauvages de l\'Amérique du Nord. Ils tombent éperdument amoureux l\'un de l\'autre mais Atala est liée par un vœu de chasteté fait à sa mère mourante. Ne pouvant résister à sa passion et ne pouvant non plus trahir son vœu, elle choisit de s\'empoisonner plutôt que de céder. Le vieux père Aubry les accueille dans sa mission et enterre Atala chrétiennement. Chateaubriand décrit avec une prose lyrique et éblouissante les paysages sauvages de l\'Amérique, créant le mythe du bon sauvage romantique. Un texte fondateur du romantisme français, d\'une beauté formelle incomparable.', 1801, 'https://covers.openlibrary.org/b/title/Atala-L.jpg', '2026-04-02 13:52:41'),
(50, 'René', 'François-René de Chateaubriand', 'Roman', 'René est le frère d\'Atala, le héros mélancolique de Chateaubriand qui a donné son nom à tout un type romantique. Réfugié en Louisiane parmi les Natchez après avoir fui une Europe qui l\'écœure, René raconte sa vie à Chactas et au père Souël. Élevé dans un château isolé, il a développé un mal mystérieux, une mélancolie sans objet qu\'il nomme le vague des passions — trop d\'imagination, trop de sensibilité pour un monde médiocre et décevant. Sa sœur Amélie, la seule personne qu\'il aime vraiment, entre soudainement dans les ordres. René apprend horrifié qu\'elle fuyait un amour coupable pour son frère. Il reçoit cette révélation comme un coup fatal et s\'exile à jamais. Court roman autobiographique, René a créé le mal du siècle romantique et le type du héros byronien, inadapté sublime qui souffre de sa propre supériorité dans un monde trop petit pour lui.', 1802, 'https://covers.openlibrary.org/b/title/René-L.jpg', '2026-04-02 13:52:41'),
(51, 'Adolphe', 'Benjamin Constant', 'Roman', 'Adolphe, jeune homme de vingt-deux ans, fils d\'un ministre d\'État distant et froid, cherche à s\'affirmer dans la vie sans savoir vraiment ce qu\'il veut. Par désœuvrement et vanité, il entreprend la conquête d\'Ellénore, maîtresse du comte de P*** et mère de ses deux enfants. Il y met toute son ardeur de jeune homme et finit par la convaincre de le suivre, ruinant ainsi sa situation et sa réputation. Mais une fois qu\'il l\'a conquise, son amour s\'étiole. Trop faible pour la quitter franchement, trop honnête pour simuler un amour qu\'il ne ressent plus, trop lâche pour affronter sa douleur à elle, il la maintient dans une relation qui la détruit progressivement. Ellénore meurt de chagrin et de maladie. Adolphe se retrouve seul, libre enfin, et découvre que cette liberté est vide. Roman psychologique d\'une précision clinique, Adolphe analyse la lâcheté sentimentale avec une lucidité sans pitié.', 1816, 'https://covers.openlibrary.org/b/title/Adolphe-L.jpg', '2026-04-02 13:52:41'),
(52, 'Indiana', 'George Sand', 'Roman', 'Indiana est une jeune créole de l\'île Bourbon mariée au colonel Delmare, un homme rude et autoritaire qui la traite comme sa propriété. Elle tombe amoureuse de Raymon de Ramière, un séducteur aristocratique égoïste qui la manipule et l\'abandonne quand elle n\'est plus utile à ses ambitions sociales. Son cousin Ralph, un homme taiseux et apparemment froid, l\'aime en secret depuis toujours avec une constance et une profondeur que personne ne devine. Indiana, après avoir tout perdu — son amour, sa réputation, son pays — finit par trouver le bonheur avec Ralph dans une retraite à l\'île Bourbon. Premier roman de George Sand publié en 1832, Indiana est une déclaration de guerre contre le mariage comme institution d\'oppression des femmes et une revendication du droit au bonheur et à la liberté pour les femmes. Un texte fondateur du féminisme littéraire français.', 1832, 'https://covers.openlibrary.org/b/title/Indiana-L.jpg', '2026-04-02 13:52:41'),
(53, 'La Mare au Diable', 'George Sand', 'Roman', 'Germain, un jeune veuf paysan du Berry qui a perdu sa femme en couches, doit se remarier pour que ses enfants aient une mère. Son beau-père lui conseille une veuve dans un village voisin et lui demande d\'emmener la petite Marie, une jeune bergère de seize ans, qui va travailler dans la région. Ils se perdent dans la campagne berrichonne, s\'abritent pour la nuit dans la forêt avec le petit Pierre, le fils cadet de Germain qui a voulu suivre son père. Dans ce bivouac nocturne, Germain découvre peu à peu les qualités de la jeune Marie et s\'aperçoit qu\'il l\'aime. Il ira rencontrer la veuve, découvrira qu\'elle ne lui convient pas, et reviendra demander la main de Marie à ses parents. George Sand signe avec ce court roman champêtre une œuvre d\'une douceur et d\'une poésie incomparables, célébrant la sagesse paysanne et la beauté de la nature berrichonne.', 1846, 'https://covers.openlibrary.org/b/title/La%20Mare%20au%20Diable-L.jpg', '2026-04-02 13:52:41');
INSERT INTO `livres` (`id`, `titre`, `auteur`, `genre`, `description`, `annee`, `image`, `date_ajout`) VALUES
(54, 'François le Champi', 'George Sand', 'Roman', 'François est un champi — un enfant trouvé, abandonné dans les champs — recueilli par Madeleine Blanchet, une meunière au grand cœur, et son mari brutal et ivrogne. L\'enfant grandit dans la ferme, maltraité par le mari mais aimé en secret par Madeleine qui l\'élève avec tendresse. Quand le mari meurt et que Madeleine se retrouve veuve endettée, François, devenu un grand jeune homme travailleur et honnête, revient pour la sauver de la ruine. Leur amour réciproque, longtemps inavoué par pudeur et par les convenances sociales — une mère adoptive n\'épouse pas son fils champi — finit par triompher de tous les obstacles. George Sand tisse un roman champêtre d\'une grande douceur sur la fidélité, la reconnaissance et l\'amour pur qui transcende les différences sociales et les conventions. La langue et les paysages du Berry sont célébrés avec un amour profond.', 1850, 'https://covers.openlibrary.org/b/title/François%20le%20Champi-L.jpg', '2026-04-02 13:52:41'),
(55, 'Dominique', 'Eugène Fromentin', 'Roman', 'Dominique de Bray, un gentleman campagnard retiré dans son domaine, raconte à un visiteur l\'histoire de sa jeunesse et de son unique grande passion. Adolescent timide et rêveur dans sa province du Saintonge, il tombe amoureux de Madeleine, une jeune femme légèrement plus âgée qui épousera un autre. Dominique la retrouve à Paris où il tente une carrière littéraire et entre dans la société. Leur amour platonique et impossible se développe dans les contraintes de sa situation de femme mariée. Un soir, Madeleine avoue qu\'elle l\'aime mais refuse de trahir son mari. Dominique, comprenant que sa passion est sans issue et destructrice pour tous deux, prend la décision courageuse de rompre définitivement et de se retirer à la campagne. Fromentin signe un roman de l\'amour impossible et du renoncement d\'une délicatesse psychologique rare, écrit dans une prose classique et lumineuse.', 1863, 'https://covers.openlibrary.org/b/title/Dominique-L.jpg', '2026-04-02 13:52:41'),
(56, 'Bel-Ami', 'Guy de Maupassant', 'Roman', 'Georges Duroy arrive à Paris sans argent et sans relations, venu de sa Normandie natale avec pour seul bagage une belle gueule et un aplomb remarquable. Une rencontre avec un ancien camarade de régiment lui permet d\'entrer au journal La Vie Française. Mauvais journaliste mais séducteur irrésistible, il comprend vite que les femmes sont le vrai moteur de l\'ascension sociale. Il séduit et épouse successivement Madeleine Forestier, journaliste brillante qui écrit ses articles, puis la fille du directeur du journal. À travers ces femmes et leurs relations, il s\'élève dans la société politique et financière de la IIIe République corrompue. Maupassant décrit avec une ironie cinglante les mécanismes de la réussite sociale dans une société où la presse, l\'argent et la politique sont intimement liés. Bel-Ami est une satire féroce de l\'opportunisme et de la corruption de la Belle Époque.', 1885, 'https://covers.openlibrary.org/b/title/Bel-Ami-L.jpg', '2026-04-02 13:52:41'),
(57, 'Une Vie', 'Guy de Maupassant', 'Roman', 'Jeanne Le Perthuis des Vauds, fille de nobles normands, sort du couvent à dix-sept ans pleine d\'illusions romantiques sur l\'amour et la vie. Elle épouse Julien de Lamare, un jeune homme de bonne famille, et s\'installe avec lui dans le manoir des Peuples en Normandie. Très vite les désillusions s\'accumulent : Julien est avare, froid et infidèle — il trompe Jeanne avec la bonne Rosalie, puis avec la comtesse de Fourville. Leur fils Paul grandit et part manger toute la fortune familiale à Paris dans des plaisirs et des dettes. Jeanne vieillit seule, appauvrie, s\'accrochant à ses souvenirs et à l\'espoir du retour de son fils. Une vie est le roman le plus sombre et le plus tendre de Maupassant, une méditation mélancolique sur l\'écrasement des rêves d\'une femme par la médiocrité du monde réel et la cruauté de ceux qu\'elle aime.', 1883, 'https://covers.openlibrary.org/b/title/Une%20Vie-L.jpg', '2026-04-02 13:52:41'),
(58, 'Pierre et Jean', 'Guy de Maupassant', 'Roman', 'Pierre et Jean Roland sont deux frères aux caractères opposés qui vivent avec leurs parents à Le Havre. Jean, le cadet doux et facile, apprend qu\'il hérite de la fortune d\'un ami de la famille, Maréchal. Pierre, l\'aîné, médecin raté et jaloux du bonheur de son frère, commence à soupçonner que Maréchal était l\'amant de sa mère et donc le père biologique de Jean. Sa jalousie le pousse à des investigations qui confirment ses soupçons. Il torture sa mère de ses allusions avant de fuir en s\'embarquant comme médecin sur un paquebot transatlantique. Maupassant préface ce court roman d\'un essai théorique sur le roman naturaliste, défendant la vérité psychologique contre l\'intrigue romanesque. Pierre et Jean est un modèle de concision et de profondeur psychologique, une étude impitoyable de la jalousie fraternelle et de la culpabilité maternelle.', 1888, 'https://covers.openlibrary.org/b/title/Pierre%20et%20Jean-L.jpg', '2026-04-02 13:52:41'),
(59, 'Thérèse Raquin', 'Émile Zola', 'Roman', 'Thérèse Raquin, orpheline élevée sans amour par sa tante Madame Raquin, épouse son cousin Camille, un homme chétif et sans intérêt. Ils s\'installent à Paris dans une boutique sombre du passage du Pont-Neuf. Thérèse, nature passionnée étouffée par une vie grise, tombe éperdument amoureuse de Laurent, un ami de Camille, grand et sensuel. Les deux amants poussent Camille à la noyade lors d\'une partie de barque sur la Seine. Après un an de séparation imposée par les convenances, ils se marient. Mais au lieu du bonheur espéré, ils sont hantés par le spectre de Camille — Laurent voit son visage dans tous ses tableaux, Thérèse dans tous ses rêves. La culpabilité les dresse l\'un contre l\'autre dans une haine mortelle. Ils finissent par se suicider ensemble devant Madame Raquin paralysée qui les a vus tout avouer. Premier grand roman de Zola, une étude clinique de la culpabilité et du déterminisme physiologique.', 1867, 'https://covers.openlibrary.org/b/title/Thérèse%20Raquin-L.jpg', '2026-04-02 13:52:41'),
(60, 'L\'Assommoir', 'Émile Zola', 'Roman', 'Gervaise Macquart arrive à Paris depuis la Provence avec son amant Lantier et leurs deux fils. Abandonnée par Lantier qui la quitte pour sa sœur, elle survit courageusement, épouse le zingueur Coupeau et ouvre sa propre blanchisserie. Pendant quelques années, elle connaît la prospérité et le bonheur. Mais Coupeau, blessé dans une chute de toit, sombre dans l\'alcoolisme, entraîne Gervaise dans sa déchéance. Lantier revient s\'installer chez eux. Gervaise perd sa blanchisserie, devient à son tour alcoolique et meurt de misère dans un réduit sous l\'escalier. Zola dépeint avec une précision documentaire et une compassion profonde la déchéance d\'une femme courageuse broyée par la misère, l\'alcool et la société. L\'Assommoir, le cabaret qui vend l\'alcool qui tue, devient le symbole d\'un destin social impitoyable.', 1877, 'https://covers.openlibrary.org/b/title/L\'Assommoir-L.jpg', '2026-04-02 13:52:41'),
(61, 'Pot-Bouille', 'Émile Zola', 'Roman', 'Octave Mouret, le jeune provincial séduisant de La Conquête de Plassans, débarque à Paris et s\'installe dans un immeuble bourgeois de la rue de Choiseul. Il travaille dans un magasin de nouveautés tout en séduisant méthodiquement les femmes de l\'immeuble. Zola décrit avec une précision féroce l\'hypocrisie de la bourgeoisie parisienne sous le Second Empire : en façade, la respectabilité, la vertu et les valeurs familiales ; en coulisses, l\'adultère généralisé, la cupidité, les avortements et les bassesses de toutes sortes. Chaque appartement de l\'immeuble cache sa laideur morale. La concierge Madame Gourd observe tout et se tait. Pot-Bouille est l\'anti-chambre du Bonheur des Dames — Mouret se forme ici avant de devenir le génie du commerce. Un roman satirique d\'une noirceur absolue sur la comédie sociale bourgeoise.', 1882, 'https://covers.openlibrary.org/b/title/Pot-Bouille-L.jpg', '2026-04-02 13:52:41'),
(62, 'La Bête Humaine', 'Émile Zola', 'Roman', 'Jacques Lantier, conducteur de locomotive sur la ligne Paris-Le Havre, est le fils de Gervaise Macquart de L\'Assommoir. Il souffre d\'une tare héréditaire terrifiante : des pulsions meurtrières irrépressibles envers les femmes, surtout lors de ses désirs amoureux. Il aime Séverine, la femme de son chef de gare Roubaud, avec qui il vit une passion intense. Mais quand il est sur le point de la posséder pleinement, l\'envie de la tuer le saisit. Roubaud a lui-même tué le tuteur de Séverine par jalousie. Les deux hommes sont liés par ce crime et cette femme. Jacques finit par tuer Séverine dans un accès de folie meurtrière. Il meurt dans un accident ferroviaire en luttant avec son chauffeur Pecqueux. Le train sans conducteur file dans la nuit chargé de soldats partant pour la guerre de 1870. Une métaphore saisissante de la société française lancée vers sa propre destruction.', 1890, 'https://covers.openlibrary.org/b/title/La%20Bête%20Humaine-L.jpg', '2026-04-02 13:52:41'),
(63, 'Le Ventre de Paris', 'Émile Zola', 'Roman', 'Florent, évadé du bagne de Cayenne où il avait été déporté injustement après les événements de décembre 1851, revient clandestinement à Paris et retrouve son demi-frère Quenu, charcutier prospère aux Halles. Il se cache parmi les marchands et obtient un poste d\'inspecteur aux Halles. Zola décrit avec une précision et une sensualité extraordinaires le monde des Halles de Paris — l\'immense marché couvert construit par Baltard — et la profusion de nourriture qui y règne, créant une poésie de la charcuterie, du poisson, des fromages et des légumes. Florent, le maigre, le déporté politique et idéaliste, s\'oppose aux Gras, les bourgeois repus et satisfaits représentés par les marchands des Halles. Sa belle-sœur Lisa le dénoncera finalement à la police. Zola oppose la politique romantique et affamée à l\'embourgeoisement satisfait de la France du Second Empire.', 1873, 'https://covers.openlibrary.org/b/title/Le%20Ventre%20de%20Paris-L.jpg', '2026-04-02 13:52:41'),
(64, 'La Débâcle', 'Émile Zola', 'Roman historique', 'La Débâcle raconte la guerre franco-prussienne de 1870 et la défaite de Sedan à travers les yeux de deux soldats du 106e régiment d\'infanterie : Jean Macquart, le caporal paysan solide et bon, et Maurice Levasseur, le jeune bourgeois idéaliste et nerveux. Zola décrit avec une précision documentaire terrifiante la désorganisation totale de l\'armée française, les généraux incompétents, les soldats sans nourriture ni munitions, la capitulation humiliante de Napoléon III. Après la défaite, Maurice rejoint les communards de Paris pendant la Commune de 1871. Jean, devenu soldat versaillais, se retrouve à combattre son ancien camarade dans les rues de Paris en flammes et le tue sans le reconnaître. La guerre civile fracasse les amitiés comme elle fracasse la France. Zola signe avec ce roman une fresque de guerre d\'un réalisme et d\'une puissance émotionnelle rares, réquisitoire contre la folie militariste et la trahison des élites.', 1892, 'https://covers.openlibrary.org/b/title/La%20Débâcle-L.jpg', '2026-04-02 13:52:41'),
(65, 'L\'Œuvre', 'Émile Zola', 'Roman', 'Claude Lantier, peintre génial et torturé, héritier de la névrose artistique des Rougon-Macquart, est le portrait en creux de Cézanne et de Zola lui-même. Il aspire à créer le tableau définitif qui capturerait Paris et la vie moderne, mais ses ambitions dépassent toujours ses moyens. Son grand tableau, une allégorie de Paris avec une femme nue au premier plan, est refusé au Salon, raillé par la foule. Sa compagne Christine l\'aime mais ne peut lutter contre sa rivale : la peinture. Leur fils Jacques-Louis, un enfant maladif, meurt. Claude continue de peindre, obsédé par son tableau impossible. Un matin, Christine le retrouve pendu devant sa toile inachevée, le regard fixé sur son œuvre ratée. Zola explore à travers Claude le déchirement de l\'artiste entre son idéal et ses limites, et pose une question douloureuse sur le prix de la création artistique. Un roman autobiographique qui brouilla durablement son amitié avec Cézanne.', 1886, 'https://covers.openlibrary.org/b/title/L\'Œuvre-L.jpg', '2026-04-02 13:52:41'),
(66, 'La Joie de Vivre', 'Émile Zola', 'Roman', 'Pauline Quenu, la cousine généreuse et solaire de Claude Lantier, hérite d\'une petite fortune à la mort de ses parents charcutiers. Recueillie par les Chanteau à Bonneville, un village normand battu par les tempêtes, elle s\'intègre à cette famille dysfonctionnelle avec une générosité sans limites. Elle aime Lazare Chanteau, le fils de la maison, un jeune homme brillant mais velléitaire qui accumule les projets avortés — il sera musicien, puis médecin, puis industriel. Elle lui sacrifie sa fortune pour ses projets, puis le voit épouser une autre femme. Elle soigne tout le monde, le père goutteux, la mère avare, les malades du village, sans jamais rien demander en retour. Hantée par la peur de la mort — qu\'elle surmonte par l\'action et le don de soi — elle reste seule et heureuse dans son dévouement. Zola crée avec Pauline l\'antithèse de ses héroïnes habituelles : une sainte laïque qui trouve sa joie dans l\'abnégation.', 1884, 'https://covers.openlibrary.org/b/title/La%20Joie%20de%20Vivre-L.jpg', '2026-04-02 13:52:41'),
(67, 'La Curée', 'Émile Zola', 'Roman', 'Aristide Saccard, le spéculateur sans scrupules de la saga des Rougon-Macquart, tire profit avec une avidité féroce de la transformation haussmannienne de Paris sous le Second Empire. Nommé dans la commission qui décide des expropriations, il apprend à l\'avance quels quartiers seront détruits et rachète les immeubles pour les revendre à prix d\'or à la Ville de Paris. Il marie son fils Maxime, jeune homme corrompu et veule, avec la belle Renée, une riche héritière qui sert de couverture à ses spéculations. Mais Renée tombe amoureuse de son beau-fils Maxime dans une relation incestueuse qui la dévore. Zola décrit avec une précision sociologique la folie spéculative du Second Empire, la corruption politique et morale d\'une classe sociale qui transforme l\'argent en seule valeur. Un roman-symbole de la décomposition d\'une société.', 1872, 'https://covers.openlibrary.org/b/title/La%20Curée-L.jpg', '2026-04-02 13:52:41'),
(68, 'Son Excellence Eugène Rougon', 'Émile Zola', 'Roman', 'Eugène Rougon est le fils aîné de Pierre et Félicité Rougon, qui a su tirer parti du coup d\'État de 1851 pour s\'élever dans la politique impériale. Devenu ministre de l\'Intérieur sous Napoléon III, il est un homme de pouvoir autoritaire et habile qui méprise les idéologies et ne croit qu\'en la force. Sa bande de fidèles — une clientèle d\'ambitieux et de parasites — le soutient en espérant profiter de son ascension. Sa rivale Clorinde Balbi, une aventurière italienne d\'une beauté et d\'une intelligence redoutables, joue avec lui un jeu de séduction et de pouvoir complexe. Rougon chute, remonte, rechute au gré des intrigues de cour. Zola dépeint avec une précision documentaire remarquable les coulisses du pouvoir impérial, les mécanismes du clientélisme politique et la corruption inhérente aux régimes autoritaires. Un roman politique d\'une acuité toujours actuelle.', 1876, 'https://covers.openlibrary.org/b/title/Son%20Excellence%20Eugène%20Rougon-L.jpg', '2026-04-02 13:52:41'),
(69, 'Une Page d\'Amour', 'Émile Zola', 'Roman', 'Hélène Grandjean, veuve d\'un fonctionnaire, vit à Paris avec sa fille Jeanne, une enfant maladive et passionnément attachée à sa mère. Le docteur Henri Deberle, appelé en urgence pour soigner Jeanne, tombe amoureux d\'Hélène et elle de lui, malgré sa propre vertu et le mariage de Deberle. Leur passion se développe discrètement, dans la contrainte des convenances sociales. Jeanne, avec l\'intuition des enfants, pressent l\'amour de sa mère pour un autre et en souffre. La nuit où Hélène cède à sa passion et passe la nuit avec Deberle, Jeanne, seule et fiévreuse, sort dans le froid et contracte la pneumonie dont elle mourra. La culpabilité d\'Hélène est immense. Elle finira par épouser un homme sans amour pour se punir. Zola peint Paris vue des hauteurs de Passy avec une beauté impressionniste, faisant de la ville le vrai personnage du roman, reflet des états d\'âme de l\'héroïne.', 1878, 'https://covers.openlibrary.org/b/title/Une%20Page%20d\'Amour-L.jpg', '2026-04-02 13:52:41'),
(70, 'Le Docteur Pascal', 'Émile Zola', 'Roman', 'Le docteur Pascal Rougon, fils de Pierre et Félicité, a consacré sa vie à étudier l\'hérédité de sa propre famille, les Rougon-Macquart, en constituant un dossier scientifique monumental. Il croit en la science et au progrès comme seules religions valables. Sa nièce Clotilde, de trente ans sa cadette, vit avec lui à Plassans et devient sa secrétaire, puis sa maîtresse dans une passion réciproque et assumée malgré le scandale. La mère de Pascal, la vieille Félicité, complice du Second Empire, veut détruire ses dossiers compromettants pour la famille. Pascal résiste jusqu\'à sa mort d\'une crise cardiaque, laissant Clotilde enceinte de son enfant. L\'enfant à naître représente l\'espoir et la vie qui continue malgré tout. Zola conclut avec ce roman-testament sa grande saga familiale en une sorte d\'hymne à la vie, à la science et à l\'amour, compensant le pessimisme des volumes précédents.', 1893, 'https://covers.openlibrary.org/b/title/Le%20Docteur%20Pascal-L.jpg', '2026-04-02 13:52:41'),
(71, 'Le Rêve', 'Émile Zola', 'Roman', 'Angélique est une orpheline recueillie à huit ans par Hubert et Hubertine Chambon, brodeurs pour la cathédrale de Beaumont. Élevée dans l\'ombre de la cathédrale gothique, au milieu des broderies d\'or et des légendes de saints, elle développe une nature mystique et rêveuse. Elle grandit en lisant La Légende Dorée et en brodant des ornements liturgiques, vivant dans une sorte de grâce permanente. Elle tombe amoureuse de Félicien, un jeune homme mystérieux dont elle ignore qu\'il est le fils du puissant évêque Monseigneur d\'Hautecoeur, qui s\'oppose à leur union. Angélique doit choisir entre son amour terrestre et sa vocation spirituelle. Le Roman le plus court et le plus lumineux de Zola dans la série des Rougon-Macquart, une sorte de conte médiéval baigné de lumière dorée et de mysticisme, à l\'opposé du naturalisme sombre habituellement associé à l\'auteur.', 1888, 'https://covers.openlibrary.org/b/title/Le%20Rêve-L.jpg', '2026-04-02 13:52:41'),
(72, 'La Terre', 'Émile Zola', 'Roman', 'Dans la Beauce, le grenier à blé de la France, la famille Fouan possède depuis des générations une terre qu\'elle a arrachée à la misère et à la glèbe. Le vieux Fouan, trop âgé pour labourer, partage sa terre entre ses trois enfants : Hyacinthe dit Jésus-Christ, l\'ivrogne libertaire, Fanny la bourgeoise avare, et Buteau, le paysan brutal et possessif. Mais la terre donnée, le père n\'est plus rien. Ses enfants l\'exploitent, le malmènent, le spolient. Buteau convoite la femme de son frère, Lise, et viole sa belle-sœur Françoise. Les conflits pour la terre tournent au meurtre. Zola peint avec une brutalité et une crudité qui scandalisèrent ses contemporains la paysannerie française dans toute sa réalité — la passion de la terre qui dépasse tout sentiment humain, l\'avarice, la sexualité animale et la violence ordinaire d\'une vie entière consacrée à gratter un sol ingrat.', 1887, 'https://covers.openlibrary.org/b/title/La%20Terre-L.jpg', '2026-04-02 13:52:41'),
(73, 'L\'Argent', 'Émile Zola', 'Roman', 'Aristide Saccard, le spéculateur génial des Rougon-Macquart, revient après ses déboires de La Curée avec un projet grandiose : fonder la Banque Universelle pour financer la reconquête catholique du Proche-Orient et la création d\'un empire économique français en Méditerranée. Il s\'associe avec l\'abbé de Villecourt et attire des milliers d\'actionnaires modestes qui croient en lui. L\'action monte, monte, dans une spirale spéculative folle. Saccard falsifie les comptes et rachète ses propres actions pour maintenir le cours. En face de lui, Gundermann, le banquier juif alsacien, attend patiemment en vendant à découvert. L\'effondrement est inévitable et brutal : des milliers de petits épargnants ruinés, une prison pour Saccard. Zola décrit avec une précision technique et dramatique la mécanique de la spéculation boursière, ses victimes innocentes et ses prédateurs cyniques. Un roman d\'une actualité permanente sur la finance et ses dérives.', 1891, 'https://covers.openlibrary.org/b/title/L\'Argent-L.jpg', '2026-04-02 13:52:41'),
(74, 'Le Ventre de Paris', 'Émile Zola', 'Roman', 'Florent, évadé du bagne de Cayenne où il avait été déporté injustement après les événements de décembre 1851, revient clandestinement à Paris et retrouve son demi-frère Quenu, charcutier prospère aux Halles. Il se cache parmi les marchands et obtient un poste d\'inspecteur aux Halles. Zola décrit avec une précision et une sensualité extraordinaires le monde des Halles de Paris — l\'immense marché couvert construit par Baltard — et la profusion de nourriture qui y règne, créant une poésie de la charcuterie, du poisson, des fromages et des légumes. Florent, le maigre, le déporté politique et idéaliste, s\'oppose aux Gras, les bourgeois repus et satisfaits représentés par les marchands des Halles. Sa belle-sœur Lisa le dénoncera finalement à la police. Zola oppose la politique romantique et affamée à l\'embourgeoisement satisfait de la France du Second Empire.', 1873, 'https://covers.openlibrary.org/b/title/Le%20Ventre%20de%20Paris-L.jpg', '2026-04-02 13:52:41'),
(75, 'Bouvard et Pécuchet', 'Gustave Flaubert', 'Roman', 'Bouvard et Pécuchet se rencontrent par hasard sur un banc parisien et découvrent qu\'ils sont tous deux copistes. Une amitié immédiate se noue. Quand Bouvard hérite d\'une fortune inattendue, ils achètent une ferme en Normandie et décident de se consacrer à toutes les sciences et les arts : l\'agriculture, la chimie, l\'anatomie, la médecine, l\'archéologie, la littérature, la politique, la philosophie, la pédagogie, la religion. Dans chaque domaine, ils s\'enthousiasment, échouent lamentablement et passent à autre chose. Leur enthousiasme naïf se heurte à la complexité du réel et à la stupidité des doctrines. Flaubert, mort en 1880 avant d\'achever le roman, voulait terminer par un immense sottisier rassemblant toutes les idées reçues de son époque. Roman-encyclopédie et roman-satire à la fois, Bouvard et Pécuchet est une critique radicale du savoir humain et de la bêtise universelle, y compris celle des savants.', 1881, 'https://covers.openlibrary.org/b/title/Bouvard%20et%20Pécuchet-L.jpg', '2026-04-02 13:52:41'),
(76, 'L\'Éducation Sentimentale', 'Gustave Flaubert', 'Roman', 'Frédéric Moreau, jeune homme de province ambitieux qui monte à Paris faire son droit, aperçoit sur un bateau la belle Madame Arnoux, femme d\'un marchand d\'art, et en tombe éperdument amoureux pour la vie entière. Il gravite autour d\'elle pendant vingt ans sans jamais vraiment conquérir son amour — par timidité, par respect, par peur de briser quelque chose d\'idéal. Autour de lui, Paris connaît les révolutions de 1848 et le coup d\'État de 1851 qu\'il traverse comme en rêve, plus préoccupé par ses amours que par la politique. Il a des maîtresses — la financière Madame Dambreuse, la courtisane Rosanette — mais n\'oublie jamais Madame Arnoux. À la fin, vieux, elle lui rend visite une dernière fois et lui offre sa chevelure blanche. Flaubert signe le roman le plus désenchanté de la littérature française, portrait d\'une génération qui a raté sa vie en rêvant au lieu de vivre.', 1869, 'https://covers.openlibrary.org/b/title/L\'Éducation%20Sentimentale-L.jpg', '2026-04-02 13:52:41'),
(77, 'Salammbô', 'Gustave Flaubert', 'Roman historique', 'Salammbô, fille d\'Hamilcar Barca, le grand général carthaginois, est une jeune prêtresse de la déesse Tanit d\'une beauté mystique et envoûtante. Après la première guerre punique, les mercenaires de Carthage se révoltent car la ville refuse de les payer. Le chef des révoltés, le Libyen Mâtho, aperçoit Salammbô lors d\'un festin et en tombe éperdument amoureux d\'une passion dévorante et sacrilège. Il s\'introduit dans le temple de Tanit et vole le voile sacré de la déesse — le zaïmph — symbole de la puissance de Carthage. Salammbô doit récupérer le voile sacré en se rendant seule dans le camp des mercenaires auprès de Mâtho. Flaubert reconstitue avec une érudition et un luxe de détails extraordinaires la Carthage antique, ses rituels, ses guerres et sa cruauté. Un roman historique d\'une beauté visuelle et stylistique éblouissante.', 1862, 'https://covers.openlibrary.org/b/title/Salammbô-L.jpg', '2026-04-02 13:52:41'),
(78, 'Les Fleurs du Mal', 'Charles Baudelaire', 'Poésie', 'Les Fleurs du Mal est le recueil poétique majeur de Charles Baudelaire, publié en 1857 et immédiatement condamné pour outrage aux bonnes mœurs. Il est organisé en sections : Spleen et Idéal, Tableaux Parisiens, Le Vin, Fleurs du Mal, Révolte et La Mort. Baudelaire y explore la beauté dans la laideur et le péché, la quête de l\'idéal dans un monde dominé par le spleen et l\'ennui. Sa muse Jeanne Duval, femme noire créole, inspire les poèmes les plus sensuels et les plus sombres. La ville de Paris moderne, avec ses prostituées, ses cadavres et ses foules solitaires, devient matière à poésie. Baudelaire invente la modernité poétique : la beauté n\'est plus dans la nature idéalisée mais dans la réalité urbaine et dans la tension entre l\'aspiration à l\'idéal et la chute dans le gouffre. Une révolution esthétique fondatrice de toute la poésie moderne.', 1857, 'https://covers.openlibrary.org/b/title/Les%20Fleurs%20du%20Mal-L.jpg', '2026-04-02 13:52:41'),
(79, 'Alcools', 'Guillaume Apollinaire', 'Poésie', 'Alcools est le premier et le plus célèbre recueil poétique d\'Apollinaire, publié en 1913 sans ponctuation. Il rassemble des poèmes écrits entre 1898 et 1913, mêlant tradition lyrique et modernité avant-gardiste. Le poème d\'ouverture, Zone, est une déambulation dans le Paris moderne — les hangars d\'aviation, les affiches publicitaires, la foule cosmopolite — mêlée à des souvenirs d\'enfance et de voyages. Le Pont Mirabeau, poème d\'amour mélancolique dédié à la peintre Marie Laurencin, est devenu l\'un des plus célèbres de la langue française. La Chanson du Mal-Aimé est une longue plainte amoureuse d\'une richesse extraordinaire. Apollinaire mêle mythologie, folklore rhénan, souvenirs de Prague et de Londres, amours malheureuses et émerveillement devant la modernité. Alcools marque la charnière entre le symbolisme finissant et l\'avant-garde cubiste, inventant une nouvelle façon de faire de la poésie.', 1913, 'https://covers.openlibrary.org/b/title/Alcools-L.jpg', '2026-04-02 13:52:41'),
(80, 'Calligrammes', 'Guillaume Apollinaire', 'Poésie', 'Calligrammes est le second recueil poétique majeur d\'Apollinaire, publié en 1918 peu avant sa mort. Il rassemble des poèmes écrits pendant la Première Guerre mondiale, dont beaucoup depuis les tranchées où le poète servait comme artilleur. Apollinaire y invente les calligrammes : des poèmes dont les mots sont disposés sur la page pour former visuellement l\'image du sujet traité — une cravate, un jet d\'eau, la pluie, un cheval. La typographie devient art visuel. Les poèmes de guerre alternent entre la beauté étrange des fusées éclairantes et des obus, la nostalgie de l\'amour et la camaraderie des soldats. Le recueil est dédié à sa compagne Lou et à Madeleine. Apollinaire réconcilie l\'avant-garde formelle avec la tradition lyrique, créant des poèmes d\'une modernité et d\'une émotion uniques. Un jalon essentiel de la poésie du XXe siècle.', 1918, 'https://covers.openlibrary.org/b/title/Calligrammes-L.jpg', '2026-04-02 13:52:41'),
(81, 'Les Illuminations', 'Arthur Rimbaud', 'Poésie', 'Les Illuminations est un recueil de prose poétique et de vers libres de Rimbaud, écrit entre 1872 et 1875 — les années de sa vie errante avec Verlaine à Londres et en Belgique, puis seul en Allemagne et en Italie. Publié sans l\'accord de Rimbaud par Verlaine en 1886, alors que le poète avait depuis longtemps abandonné la littérature pour le commerce en Afrique. Les textes sont des visions hallucinatoires, des illuminations au sens mystique — des éclairs de réalité transfigurée. Rimbaud y construit des univers fantastiques et incohérents selon la logique ordinaire mais dotés d\'une cohérence poétique et sensorielle propre. Marine, Départ, Villes, Génie, Démocratie — chaque texte est une explosion créatrice qui invente un langage nouveau. Les Illuminations ont influencé tous les mouvements poétiques du XXe siècle — surréalisme, lettrisme, Beat Generation — et restent parmi les textes les plus audacieux jamais écrits.', 1886, 'https://covers.openlibrary.org/b/title/Les%20Illuminations-L.jpg', '2026-04-02 13:52:41'),
(82, 'Une Saison en Enfer', 'Arthur Rimbaud', 'Poésie', 'Une Saison en Enfer est le seul livre publié et assumé par Rimbaud de son vivant, en 1873, à dix-neuf ans. C\'est un règlement de comptes radical avec sa propre vie, sa poésie et ses illusions. Divisé en neuf sections, le texte est une confession délirante et lucide à la fois : Rimbaud y règle ses comptes avec son aventure poétique — la voyance, l\'alchimie du verbe, la dérèglement de tous les sens — avec la relation tumultueuse et violente avec Verlaine, avec le christianisme de son enfance, avec l\'Europe et l\'Occident. Il s\'y condamne et s\'y absout alternativement dans un mouvement de fièvre et d\'ironie. Après avoir fait imprimer le livre à ses frais, Rimbaud abandonne définitivement la littérature pour partir commercer en Afrique. Une Saison en Enfer est peut-être le texte autobiographique le plus intense de la littérature française, un cri de rupture et de renaissance.', 1873, 'https://covers.openlibrary.org/b/title/Une%20Saison%20en%20Enfer-L.jpg', '2026-04-02 13:52:41'),
(83, 'Fêtes Galantes', 'Paul Verlaine', 'Poésie', 'Fêtes Galantes est le premier recueil poétique important de Paul Verlaine, publié en 1869. Il s\'inspire des tableaux de Watteau et de Fragonard représentant des fêtes galantes : des aristocrates en costumes de théâtre se promenant dans des parcs enchantés, jouant de la musique et faisant la cour. Verlaine transpose ces scènes picturales en poèmes d\'une musicalité et d\'une mélancolie subtiles. Les personnages — Colombines, Arlequins, Pierrots — jouent à l\'amour dans un décor de théâtre, mais derrière les masques et les rires perce une tristesse profonde et une conscience aiguë de la fugacité des plaisirs. Le recueil est traversé par une ironie douce et une nostalgie pour un monde de grâce et d\'élégance qui n\'a jamais vraiment existé. Un joyau de la poésie symboliste française, d\'une légèreté apparente qui cache une profondeur mélancolique.', 1869, 'https://covers.openlibrary.org/b/title/Fêtes%20Galantes-L.jpg', '2026-04-02 13:52:41'),
(84, 'Romances sans Paroles', 'Paul Verlaine', 'Poésie', 'Romances sans Paroles est le troisième recueil de Verlaine, écrit en 1872-1873 en grande partie pendant sa vie errante avec Rimbaud à Londres et en Belgique. Publié en 1874 alors que Verlaine était en prison pour avoir blessé Rimbaud d\'un coup de revolver à Bruxelles. Le titre annonce le programme : des poèmes qui cherchent à atteindre la condition de la musique, à suggérer plutôt qu\'à affirmer, à émouvoir sans expliquer. La section Ariettes Oubliées commence par Il pleure dans mon cœur, l\'un des poèmes les plus musicaux de la langue française. Les Paysages Belges et Aquarelles dessinent des décors nordiques brumeux et mélancoliques. Verlaine y atteint le sommet de son art impressionniste — des poèmes qui fonctionnent comme des tableaux de Monet, par touches, par vibrations, par atmosphères. Un jalon essentiel de la poésie symboliste.', 1874, 'https://covers.openlibrary.org/b/title/Romances%20sans%20Paroles-L.jpg', '2026-04-02 13:52:41'),
(85, 'Le Grand Meaulnes', 'Alain-Fournier', 'Roman', 'Augustin Meaulnes, dix-sept ans, arrive comme pensionnaire chez le père Seurel, instituteur dans un village de la Sologne. Le narrateur, François Seurel, fils de l\'instituteur, est immédiatement fasciné par cet adolescent mystérieux et magnétique. Un jour, Meaulnes s\'échappe et se perd dans la campagne. Il découvre par hasard un domaine mystérieux où se déroule une fête étrange et enchanteresse pour célébrer les fiançailles d\'un jeune homme : là il rencontre la belle Yvonne de Galais et en tombe éperdument amoureux. Revenu au village, il ne cesse de chercher ce domaine perdu et cette jeune fille. Mais le monde enchanté de l\'enfance et l\'amour absolu sont-ils compatibles avec la réalité de la vie adulte ? Roman de l\'adolescence par excellence, Le Grand Meaulnes est une méditation mélancolique sur le paradis perdu de l\'enfance, la quête de l\'idéal et l\'impossibilité de ressaisir un bonheur entrevu.', 1913, 'https://covers.openlibrary.org/b/title/Le%20Grand%20Meaulnes-L.jpg', '2026-04-02 13:52:41'),
(86, 'Colombe Blanchet', 'Romain Rolland', 'Roman', 'Colombe Blanchet est une jeune femme courageuse et déterminée qui vit dans la France du XVIIIe siècle. Orpheline de mère, elle grandit aux côtés de son père, un aubergiste simple et bon. Quand des événements dramatiques bouleversent sa vie tranquille, elle doit faire preuve d\'une force de caractère et d\'une intelligence remarquables pour se défendre et défendre ceux qu\'elle aime dans une société où les femmes n\'ont que peu de droits et de recours. Romain Rolland peint avec tendresse et précision la vie provinciale française du siècle des Lumières, les injustices sociales et la résistance individuelle face à l\'arbitraire des puissants. Un roman moins connu de l\'auteur de Jean-Christophe mais qui témoigne de son humanisme profond et de sa foi dans la capacité des êtres ordinaires à surmonter l\'adversité par leur dignité et leur courage.', 1920, 'https://covers.openlibrary.org/b/title/Colombe%20Blanchet-L.jpg', '2026-04-02 13:52:41'),
(87, 'Les Thibault', 'Roger Martin du Gard', 'Roman', 'Les Thibault est une fresque romanesque en huit volumes suivant deux frères de la bourgeoisie catholique parisienne du début du XXe siècle jusqu\'à la Première Guerre mondiale. Antoine Thibault, l\'aîné, est médecin, positiviste et dévoué à ses malades. Jacques, le cadet, est un révolté passionné qui s\'engage dans le socialisme révolutionnaire international. Leur père Oscar, bourgeois autoritaire et dévot, les opprime chacun à leur manière. La saga couvre vingt ans d\'histoire européenne, des tensions sociales de la Belle Époque à l\'engrenage fatal de l\'été 1914. Le dernier volume, L\'Été 1914, est un chef-d\'œuvre de la littérature pacifiste montrant l\'impuissance des socialistes internationalistes face au déclenchement de la guerre. Roger Martin du Gard reçut le Prix Nobel de littérature en 1937 pour cette œuvre monumentale.', 1922, 'https://covers.openlibrary.org/b/title/Les%20Thibault-L.jpg', '2026-04-02 13:52:41'),
(88, 'À la Recherche du Temps Perdu', 'Marcel Proust', 'Roman', 'À la Recherche du Temps Perdu est l\'œuvre monumentale de Marcel Proust, publiée en sept volumes de 1913 à 1927. Le narrateur, Marcel, entreprend de retrouver le temps perdu de son enfance et de sa jeunesse à travers le mécanisme de la mémoire involontaire — la célèbre madeleine trempée dans le tilleul qui ressuscite soudainement Combray tout entier. La saga suit Marcel de son enfance bourgeoise à Combray, à travers les salons parisiens de la Belle Époque — chez les Guermantes, chez les Verdurin — l\'affaire Dreyfus, l\'amour douloureux pour Albertine, les ravages du temps sur les visages et les amitiés. Proust invente une prose à la syntaxe longue et sinueuse qui mime le fonctionnement même de la pensée et de la mémoire. La Recherche est moins un roman qu\'une cathédrale de mots, une réflexion totale sur le temps, l\'amour, la jalousie, l\'art et la mort. L\'œuvre la plus importante de la littérature française du XXe siècle.', 1913, 'https://covers.openlibrary.org/b/title/À%20la%20Recherche%20du%20Temps%20Perdu-L.jpg', '2026-04-02 13:52:41'),
(89, 'Le Diable au Corps', 'Raymond Radiguet', 'Roman', 'Pendant la Première Guerre mondiale, un adolescent de seize ans raconte sa passion amoureuse pour Marthe, une jeune femme de vingt-deux ans dont le mari est au front. Il la rencontre dans la région de son pensionnat, la séduit et entretient une liaison secrète avec elle. Pendant que les soldats meurent dans les tranchées, ces deux-là vivent leur amour dans les maisons de campagne vides. Marthe tombe enceinte. Quand son mari revient en permission, elle lui fait croire que l\'enfant est de lui. L\'adolescent, bouleversé, accepte de disparaître de sa vie. L\'enfant naît mais meurt. Le mari, envoyé sur le front, est tué. Marthe finit par succomber à son tour. Radiguet, qui avait quatorze ans pendant la guerre, écrit à vingt ans ce roman avec une maturité et une froideur clinique stupéfiantes. Le scandale fut immense — l\'immoralité de l\'arrière pendant que les hommes mouraient au front était insupportable à entendre.', 1923, 'https://covers.openlibrary.org/b/title/Le%20Diable%20au%20Corps-L.jpg', '2026-04-02 13:52:41'),
(90, 'Les Enfants Terribles', 'Jean Cocteau', 'Roman', 'Paul et Élisabeth, frère et sœur, vivent dans leur chambre d\'enfants comme dans un monde à part, gouverné par leurs propres règles, leurs jeux et leurs trésors secrets. Paul est blessé par une boule de neige lancée par Dargelos, le beau garçon cruel dont il est fasciné. Convalescent, il reste enfermé dans la chambre avec Élisabeth qui ne va plus à l\'école pour le soigner. Ils grandissent dans cet isolement, incapables de vivre normalement dans le monde extérieur. Élisabeth, jalouse de l\'emprise que d\'autres pourraient avoir sur son frère, sabote ses relations amoureuses. Quand Paul épouse Agatha, Élisabeth fait en sorte qu\'Agatha épouse leur ami Gérard. La chambre est leur seul univers et leur prison. Le poison — déjà dans la boule de neige — sera la solution finale. Cocteau crée un univers poétique et claustrophobique unique, portrait fascinant d\'un amour fraternel qui tourne à la folie dans la clôture.', 1929, 'https://covers.openlibrary.org/b/title/Les%20Enfants%20Terribles-L.jpg', '2026-04-02 13:52:41'),
(91, 'Voyage au Bout de la Nuit', 'Louis-Ferdinand Céline', 'Roman', 'Ferdinand Bardamu, alter ego de Céline, traverse le XXe siècle dans ses horreurs et ses misères. Il commence par la Grande Guerre — dont il décrit l\'absurdité meurtrière avec un cynisme et une terreur bruts, sans héroïsme ni patriotisme. Il part en Afrique coloniale, découvre l\'exploitation et la bêtise de la colonisation. Aux États-Unis, il travaille à la chaîne chez Ford à Detroit — aliénation industrielle totale. Revenu en France, il devient médecin dans une banlieue pauvre de Paris où la misère est absolue. Partout il rencontre la lâcheté humaine, l\'imbécillité des puissants et la résignation des pauvres. Son ami Robinson le précède dans tous les voyages comme un double sombre. Céline invente un style révolutionnaire — le langage parlé, l\'argot, les points de suspension, le rythme syncopé — qui fait entrer la voix du peuple dans la grande littérature. Un choc stylistique et moral sans précédent.', 1932, 'https://covers.openlibrary.org/b/title/Voyage%20au%20Bout%20de%20la%20Nuit-L.jpg', '2026-04-02 13:52:41'),
(92, 'Mort à Crédit', 'Louis-Ferdinand Céline', 'Roman', 'Mort à Crédit est le deuxième grand roman de Céline, encore plus autobiographique que le Voyage. Ferdinand raconte son enfance et son adolescence dans le Paris populaire du début du XXe siècle : son père employé dans une compagnie d\'assurances, sa mère marchande de dentelles, leur logement étrique passage Choiseul. Une enfance de petits bourgeois pauvres et anxieux, d\'humiliations et de privations. Ferdinand est renvoyé de partout, échoue dans tout ce qu\'il entreprend, s\'engage dans une vie d\'errance. Il travaille pour un inventeur génial et fou, Courtial des Pereires, qui finit par se suicider. Le style de Céline atteint ici son paroxysme — phrases qui s\'emballent, virgules qui remplacent toute ponctuation, langage oral porté à son incandescence maximale. Un roman sur l\'enfance malheureuse et la médiocrité de la condition humaine, d\'une noirceur absolue tempérée par une énergie stylistique unique.', 1936, 'https://covers.openlibrary.org/b/title/Mort%20à%20Crédit-L.jpg', '2026-04-02 13:52:41'),
(93, 'L\'Espoir', 'André Malraux', 'Roman', 'L\'Espoir raconte les premiers mois de la guerre civile espagnole en 1936, depuis le soulèvement franquiste de juillet jusqu\'aux premiers mois de 1937. Malraux, qui a lui-même participé au conflit aux côtés des républicains en organisant une escadrille aérienne, donne à voir la guerre de l\'intérieur, dans toute sa complexité et ses contradictions. Des personnages de toutes nationalités et de toutes tendances politiques — anarchistes catalans, communistes, socialistes, républicains modérés — tentent de s\'unir face au fascisme tout en s\'opposant sur les moyens et les buts. Magnin, l\'officier de l\'aviation républicaine, Garcia le policier philosophe, Hernandez le capitaine idéaliste — chacun incarne une façon d\'espérer et de se battre. La scène des paysans portant sur leurs épaules les aviateurs blessés descendant la montagne est l\'une des plus belles de la littérature de guerre. Un roman sur la fraternité et les limites de l\'idéal face à la réalité militaire.', 1937, 'https://covers.openlibrary.org/b/title/L\'Espoir-L.jpg', '2026-04-02 13:52:41'),
(94, 'La Condition Humaine', 'André Malraux', 'Roman', 'Shanghai, 1927. La révolution communiste est en marche. Kyo Gisors, franco-japonais et militant communiste, organise avec ses camarades l\'insurrection ouvrière de Shanghai pour prendre le pouvoir avant l\'arrivée des troupes de Tchang Kaï-chek. Mais la direction internationale du Parti, sur ordre de Moscou, leur ordonne de rendre leurs armes aux nationalistes — les livrant ainsi à la mort. Kyo, son père le vieux philosophe Gisors, le Russe Katow, le trafiquant d\'armes Ferral et le terroriste solitaire Tchen incarnent chacun une façon différente de donner sens à leur vie face à la mort imminente. Malraux, qui avait participé aux événements révolutionnaires chinois, écrit un roman d\'action intense et d\'une profondeur philosophique rare sur la fraternité, la dignité humaine et le sacrifice. Prix Goncourt 1933.', 1933, 'https://covers.openlibrary.org/b/title/La%20Condition%20Humaine-L.jpg', '2026-04-02 13:52:41'),
(95, 'Le Feu', 'Henri Barbusse', 'Roman', 'Henri Barbusse, ancien combattant de la Première Guerre mondiale, publie en 1916 ce témoignage brut et direct sur la vie quotidienne d\'une escouade de soldats français dans les tranchées. Contrairement à la propagande officielle qui célèbre l\'héroïsme guerrier, Barbusse décrit la boue omniprésente, les poux, les rats, les cadavres en décomposition, la fatigue extrême et l\'absurdité des ordres. Ses personnages ne sont pas des héros mais des hommes ordinaires, ouvriers et paysans, qui survivent heure par heure dans un enfer de feu et de boue. Le roman se termine sur une vision apocalyptique du champ de bataille inondé et une lueur d\'espoir révolutionnaire. Prix Goncourt 1916, Le Feu fut un choc littéraire et politique majeur, premier grand témoignage pacifiste sur la guerre des tranchées, publié alors que la guerre faisait encore rage.', 1916, 'https://covers.openlibrary.org/b/title/Le%20Feu-L.jpg', '2026-04-02 13:52:41'),
(96, 'Les Croix de Bois', 'Roland Dorgelès', 'Roman', 'Les Croix de Bois est le témoignage de Roland Dorgelès sur la Première Guerre mondiale, publié en 1919 et finaliste du Prix Goncourt. Dorgelès, soldat pendant toute la durée de la guerre, suit la vie quotidienne d\'une escouade de soldats français dans les tranchées du front occidental. Contrairement à la propagande héroïque, il décrit la boue, le froid, la peur, les poux, les cadavres décomposés dans le no man\'s land, l\'alcool pour tenir, les permissions trop courtes et trop lointaines. Ses personnages — le vieux soldat Gilbert, le bon Sulphart, le jeune Bréval — sont des hommes ordinaires qui souffrent et meurent ordinairement. Le titre désigne les croix de bois qui marquent les tombes improvisées sur le front. Roman de la camaraderie et de l\'horreur ordinaire de la guerre des tranchées, Les Croix de Bois est avec Le Feu de Barbusse le grand témoignage pacifiste de la Grande Guerre, d\'une sincérité et d\'une pudeur admirables.', 1919, 'https://covers.openlibrary.org/b/title/Les%20Croix%20de%20Bois-L.jpg', '2026-04-02 13:52:41'),
(97, 'À l\'Ouest Rien de Nouveau', 'Erich Maria Remarque', 'Roman', 'Paul Bäumer a dix-neuf ans quand il s\'engage dans l\'armée allemande pendant la Première Guerre mondiale, entraîné par l\'enthousiasme patriotique insufflé par son professeur. Dans les tranchées, il découvre une réalité radicalement différente : la boue, les rats, les obus, les gaz, la mort omniprésente et absurde de ses camarades. Les jeunes soldats sont coupés de leur génération, incapables de se projeter dans un avenir civil. Remarque, lui-même ancien combattant, témoigne avec une sobriété bouleversante de l\'horreur de la guerre et du traumatisme psychologique des soldats. Publié en 1929, le roman fut brûlé par les nazis en 1933. Un témoignage pacifiste d\'une force émotionnelle inoubliable.', 1929, 'https://covers.openlibrary.org/b/title/À%20l\'Ouest%20Rien%20de%20Nouveau-L.jpg', '2026-04-02 13:52:41'),
(98, 'Le Vieil Homme et la Mer', 'Ernest Hemingway', 'Roman', 'Santiago, un vieux pêcheur cubain qui n\'a pas pris de poisson depuis quatre-vingt-quatre jours, part seul en mer dans son petit esquif. Loin des côtes, il accroche un immense marlin, le plus grand poisson qu\'il ait jamais vu. S\'engage alors une lutte épique de trois jours et trois nuits entre le vieil homme et le poisson gigantesque. Santiago, épuisé mais têtu, refuse d\'abandonner malgré la douleur et l\'isolement. Quand il ramène enfin le marlin attaché à son bateau, les requins le dévorent progressivement. Il rentre au port avec seulement la carcasse. Un roman court et intense sur la dignité humaine, le courage face à l\'adversité et la beauté tragique de la lutte contre la nature.', 1952, 'https://covers.openlibrary.org/b/title/Le%20Vieil%20Homme%20et%20la%20Mer-L.jpg', '2026-04-02 13:52:41'),
(99, 'L\'Adieu aux Armes', 'Ernest Hemingway', 'Roman', 'Frederic Henry, lieutenant américain servant comme ambulancier dans l\'armée italienne pendant la Première Guerre mondiale, tombe amoureux de Catherine Barkley, une infirmière anglaise dont le fiancé vient d\'être tué au front. Leur liaison commence comme un jeu mais devient un amour profond et absolu. Blessé à Caporetto, Frederic est soigné par Catherine à Milan. Ils vivent quelques mois de bonheur relatif avant que Frederic ne soit renvoyé au front. Après la désastreuse retraite de Caporetto, accusé injustement d\'espionnage, il déserte et s\'enfuit avec Catherine en Suisse en barque sur le lac Majeur. Ils vivent heureux dans les montagnes suisses jusqu\'à l\'accouchement. Catherine meurt en donnant naissance à un enfant mort-né. Hemingway raconte l\'amour et la guerre avec sa prose sèche et dépouillée, sans sentimentalisme et sans illusions. Un roman sur l\'impossibilité du bonheur dans un monde en guerre.', 1929, 'https://covers.openlibrary.org/b/title/L\'Adieu%20aux%20Armes-L.jpg', '2026-04-02 13:52:41'),
(100, 'Pour Qui Sonne le Glas', 'Ernest Hemingway', 'Roman', 'Robert Jordan, un jeune professeur américain d\'espagnol et dynamiteur volontaire dans les rangs républicains pendant la guerre civile espagnole, reçoit la mission de détruire un pont dans les montagnes de Castille pour soutenir une offensive. Il rejoint un groupe de guérilleros et tombe amoureux de Maria, une jeune femme rescapée des atrocités franquistes. Il sait que la mission est probablement vouée à l\'échec mais l\'accomplit par discipline et conviction. Les quatre-vingt heures du roman — du vendredi soir au lundi matin — condensent une vie entière d\'amour, de doute, de camaraderie et de mort. Pablo, le chef guérillero alcoolique et lâche, Pilar, sa femme courageuse et lucide, incarnent deux façons d\'affronter l\'impossibilité. Hemingway signe son roman le plus ambitieux, une méditation sur le sacrifice, la liberté, l\'amour et la mort au service d\'une cause. Le titre vient de John Donne : la mort de chacun nous diminue tous.', 1940, 'https://covers.openlibrary.org/b/title/Pour%20Qui%20Sonne%20le%20Glas-L.jpg', '2026-04-02 13:52:41'),
(101, 'Le Grand Gatsby', 'F. Scott Fitzgerald', 'Roman', 'Dans le Paris des Années Folles, Jay Gatsby organise dans son luxueux manoir de West Egg des fêtes somptueuses auxquelles toute la haute société est conviée, mais lui-même reste mystérieux et solitaire. Nick Carraway, son voisin et cousin de Daisy, découvre peu à peu le passé de Gatsby : fils de fermiers pauvres, il s\'est enrichi mystérieusement uniquement pour reconquérir Daisy Buchanan, l\'amour de sa jeunesse devenue l\'épouse du brutal Tom Buchanan. Leur réunion, orchestrée par Nick, ne peut que mal se terminer. Fitzgerald peint avec une prose poétique incomparable la désillusion du rêve américain, la superficialité des riches et l\'impossibilité de ressusciter le passé.', 1925, 'https://covers.openlibrary.org/b/title/Le%20Grand%20Gatsby-L.jpg', '2026-04-02 13:52:41');
INSERT INTO `livres` (`id`, `titre`, `auteur`, `genre`, `description`, `annee`, `image`, `date_ajout`) VALUES
(102, 'De Souris et d\'Hommes', 'John Steinbeck', 'Roman', 'George et Lennie sont deux ouvriers agricoles itinérants qui parcourent la Californie des années 1930 à la recherche de travail. George est petit et vif, Lennie est grand et fort mais simple d\'esprit. Malgré leurs différences, ils sont inséparables et partagent un rêve : posséder leur propre lopin de terre où ils seraient libres et indépendants. Engagés dans un ranch, ils se lient avec d\'autres travailleurs marginaux, dont le vieux Candy et le sage Slim. Mais la force incontrôlable de Lennie et la jalousie de la femme du patron vont provoquer une tragédie inévitable. Un roman poignant sur l\'amitié, la solitude, les rêves impossibles et la condition des laissés-pour-compte de l\'Amérique.', 1937, 'https://covers.openlibrary.org/b/title/De%20Souris%20et%20d\'Hommes-L.jpg', '2026-04-02 13:52:41'),
(103, 'Les Raisins de la Colère', 'John Steinbeck', 'Roman', 'Les Raisins de la Colère raconte l\'odyssée de la famille Joad, des fermiers de l\'Oklahoma chassés de leurs terres par la sécheresse, les tempêtes de poussière et les banques pendant la Grande Dépression des années 1930. Avec tous leurs biens entassés dans un vieux camion, ils prennent la Route 66 vers la Californie, terre promise où ils espèrent trouver du travail et une vie meilleure. Mais la réalité californienne est cruelle : exploitation des travailleurs migrants, misère des camps, violence des propriétaires terriens. Tom Joad et sa famille résistent avec dignité. Un roman épique et engagé sur la justice sociale, la solidarité humaine et la résistance face à l\'oppression.', 1939, 'https://covers.openlibrary.org/b/title/Les%20Raisins%20de%20la%20Colère-L.jpg', '2026-04-02 13:52:41'),
(104, 'Moby Dick', 'Herman Melville', 'Aventure', 'Capitaine Achab, commandant du baleinier Péquod, est obsédé par une vengeance contre Moby Dick, l\'immense baleine blanche qui lui a arraché la jambe lors d\'une précédente expédition. Malgré les avertissements de son équipage et les mauvais présages, il pousse son navire et ses hommes vers les mers les plus dangereuses du globe dans cette quête insensée. Ismaël, le narrateur, observe avec fascination et inquiétude cette obsession qui consume leur capitaine. Roman d\'aventure maritime épique, Moby Dick est aussi une profonde méditation sur l\'obsession, le destin, le bien et le mal, et la nature impénétrable de l\'univers. Un chef-d\'œuvre de la littérature américaine.', 1851, 'https://covers.openlibrary.org/b/title/Moby%20Dick-L.jpg', '2026-04-02 13:52:41'),
(105, 'Les Aventures de Tom Sawyer', 'Mark Twain', 'Roman', 'Tom Sawyer, garçon espiègle et imaginatif d\'une douzaine d\'années vivant à Saint Petersburg dans le Missouri des années 1840, est élevé par sa tante Polly après la mort de ses parents. Sa vie quotidienne est une succession d\'aventures : il se fait des amis, se bat, tombe amoureux de la petite Becky Thatcher, joue avec son inséparable ami Huckleberry Finn, fils d\'un ivrogne. Un soir, Tom et Huck assistent en cachette à un meurtre dans le cimetière : l\'Indien Joe tue le docteur Robinson et fait accuser l\'innocent Muff Potter. Tom devra trouver le courage de témoigner en sa faveur. Les aventures culminent avec Tom et Becky perdus dans une grotte et la découverte d\'un trésor caché. Mark Twain signe un roman d\'enfance d\'une nostalgie et d\'un humour irrésistibles, portrait de l\'Amérique de la frontière.', 1876, 'https://covers.openlibrary.org/b/title/Les%20Aventures%20de%20Tom%20Sawyer-L.jpg', '2026-04-02 13:52:41'),
(106, 'Les Aventures de Huckleberry Finn', 'Mark Twain', 'Roman', 'Huckleberry Finn, fils d\'un ivrogne brutal, s\'échappe de la garde de la veuve Douglas qui tentait de le civiliser et de son père qui l\'avait séquestré pour lui voler son argent. Il rencontre Jim, l\'esclave noir de Miss Watson qui fuit pour éviter d\'être vendu dans le Sud lointain, loin de sa famille. Ensemble, ils descendent le Mississippi sur un radeau dans la nuit, cherchant Cairo où Jim pourra être libre. Leurs aventures les mettent aux prises avec des escrocs — le Roi et le Duc — des vendettas familiales sanglantes et des situations dangereuses. Huck, élevé dans les préjugés raciaux de son époque, se bat intérieurement contre sa conscience qui lui dit que cacher un esclave fugitif est un péché. Il finit par choisir l\'amitié et l\'humanité contre la loi. Twain signe avec ce roman le chef-d\'œuvre de la littérature américaine, une satire sociale et morale d\'une profondeur et d\'un humour incomparables.', 1884, 'https://covers.openlibrary.org/b/title/Les%20Aventures%20de%20Huckleberry%20Finn-L.jpg', '2026-04-02 13:52:41'),
(107, 'Jane Eyre', 'Charlotte Brontë', 'Roman', 'Jane Eyre, orpheline maltraitée par sa tante et ses cousins, est envoyée dans un pensionnat strict et austère de Lowood où elle endure la faim et le froid mais développe son intelligence et sa détermination. Devenue gouvernante au manoir de Thornfield, elle tombe amoureuse de son mystérieux employeur, Mr Rochester, un homme tourmenté qui cache un terrible secret dans les profondeurs du château. Leur amour contrariée par les conventions sociales et un secret dévastateur force Jane à choisir entre passion et intégrité morale. Roman d\'apprentissage féministe avant l\'heure, Jane Eyre est une œuvre puissante sur l\'indépendance, la dignité et la quête du bonheur authentique.', 1847, 'https://covers.openlibrary.org/b/title/Jane%20Eyre-L.jpg', '2026-04-02 13:52:41'),
(108, 'Les Hauts de Hurlevent', 'Emily Brontë', 'Roman', 'Heathcliff, un enfant des rues recueilli par Mr Earnshaw, grandit à Wuthering Heights, les Hauts de Hurlevent, aux côtés de Catherine Earnshaw dont il devient l\'âme sœur. Mais Catherine épouse le riche et raffiné Edgar Linton par ambition sociale, brisant le cœur de Heathcliff qui disparaît pendant plusieurs années. À son retour, devenu mystérieusement riche, il entreprend une vengeance froide et méthodique contre les deux familles qui l\'ont humilié. Une histoire d\'amour passionnel et destructeur d\'une intensité rare, qui explore les thèmes de la jalousie, de la vengeance, de la différence sociale et de la nature sauvage à travers une structure narrative complexe et innovante.', 1847, 'https://covers.openlibrary.org/b/title/Les%20Hauts%20de%20Hurlevent-L.jpg', '2026-04-02 13:52:41'),
(109, 'Orgueil et Préjugés', 'Jane Austen', 'Roman', 'Elizabeth Bennet, deuxième des cinq filles Bennet, est une jeune femme intelligente, vive et indépendante dans l\'Angleterre du début du XIXe siècle. Lors d\'un bal, elle rencontre Mr Darcy, un homme riche et hautain qui la blesse dans son orgueil. Malgré leur antipathie mutuelle initiale, une attraction complexe se développe entre eux. Jane Austen tisse avec humour et finesse une critique acérée de la société de son époque, où le mariage est la seule issue pour les femmes sans fortune. Les préjugés de classe et l\'orgueil personnel devront être surmontés pour que l\'amour véritable triomphe. L\'un des romans les plus aimés de la littérature mondiale, d\'une modernité et d\'un wit incomparables.', 1813, 'https://covers.openlibrary.org/b/title/Orgueil%20et%20Préjugés-L.jpg', '2026-04-02 13:52:41'),
(110, 'Raison et Sentiments', 'Jane Austen', 'Roman', 'Deux sœurs aux caractères opposés cherchent l\'amour et le mariage dans l\'Angleterre du XVIIIe siècle.', 1811, 'https://covers.openlibrary.org/b/title/Raison%20et%20Sentiments-L.jpg', '2026-04-02 13:52:41'),
(111, 'Emma', 'Jane Austen', 'Roman', 'Emma Woodhouse, jeune femme riche et intelligente, s\'improvise entremetteuse avec des résultats désastreux.', 1815, 'https://covers.openlibrary.org/b/title/Emma-L.jpg', '2026-04-02 13:52:41'),
(112, 'David Copperfield', 'Charles Dickens', 'Roman', 'Les aventures de David Copperfield depuis son enfance difficile jusqu\'à son succès d\'écrivain.', 1850, 'https://covers.openlibrary.org/b/title/David%20Copperfield-L.jpg', '2026-04-02 13:52:41'),
(113, 'Oliver Twist', 'Charles Dickens', 'Roman', 'Oliver Twist naît dans un workhouse victorien et sa mère meurt en lui donnant naissance. Élevé dans la misère par la paroisse, il s\'enfuit à Londres où il tombe entre les mains de Fagin, un vieux criminel qui dirige une bande de jeunes pickpockets dont le redoutable Artful Dodger. Vendu et maltraité, Oliver cherche désespérément à s\'en sortir et à découvrir ses origines mystérieuses. Dickens dresse un portrait impitoyable de la misère sociale dans l\'Angleterre victorienne, dénonçant les conditions de vie dans les workhouses et l\'exploitation des enfants pauvres. Un roman d\'aventures et de dénonciation sociale qui a marqué les consciences à sa publication.', 1838, 'https://covers.openlibrary.org/b/title/Oliver%20Twist-L.jpg', '2026-04-02 13:52:41'),
(114, 'Un Conte de Deux Villes', 'Charles Dickens', 'Roman historique', 'En 1775 à Paris, le docteur Manette, emprisonné à la Bastille pendant dix-huit ans par une lettre de cachet signée par un aristocrate, est finalement libéré et recueilli par son ami banquier Lorry et sa fille Lucie, qu\'il n\'a jamais connue. Cinq ans plus tard à Londres, le jeune Charles Darnay, aristocrate français qui a renié son titre, épouse Lucie. Sydney Carton, avocat brillant et alcoolique qui ressemble étrangement à Darnay, l\'aime en secret. Quand la Révolution française éclate, Darnay revient à Paris pour sauver un ancien serviteur et est arrêté, condamné à mort. Carton va faire le sacrifice ultime. Dickens dresse une fresque saisissante de la Révolution française, de la Terreur et de la guillotine, avec pour toile de fond sa célèbre phrase d\'ouverture sur les contraires de l\'époque.', 1859, 'https://covers.openlibrary.org/b/title/Un%20Conte%20de%20Deux%20Villes-L.jpg', '2026-04-02 13:52:41'),
(115, 'Grandes Espérances', 'Charles Dickens', 'Roman', 'Pip, un orphelin pauvre, reçoit une fortune mystérieuse et tente de devenir un gentleman.', 1861, 'https://covers.openlibrary.org/b/title/Grandes%20Espérances-L.jpg', '2026-04-02 13:52:41'),
(116, 'L\'Île au Trésor', 'Robert Louis Stevenson', 'Aventure', 'Jim Hawkins, fils d\'aubergiste, trouve une carte au trésor dans les affaires d\'un vieux marin mourant. La carte indique l\'emplacement d\'un trésor fabuleux enterré par le pirate Flint sur une île mystérieuse. Accompagné du docteur Livesey et du chevalier Trelawney, il embarque pour cette île aux trésors. Mais une partie de l\'équipage est composée de pirates emmenés par le redoutable et fascinant Long John Silver, qui n\'ont qu\'une idée en tête : s\'emparer du trésor pour eux-mêmes. Un roman d\'aventures palpitant qui a défini le genre et créé les archétypes du roman de pirates : l\'île déserte, la carte au trésor, les pirates à la jambe de bois.', 1883, 'https://covers.openlibrary.org/b/title/L\'Île%20au%20Trésor-L.jpg', '2026-04-02 13:52:41'),
(117, 'Dracula', 'Bram Stoker', 'Horreur', 'Le comte Dracula, noble vampire transylvanien aux pouvoirs surnaturels, décide de quitter son château des Carpates pour s\'installer en Angleterre et y trouver de nouvelles victimes. Jonathan Harker, un jeune notaire anglais, est envoyé en Transylvanie pour finaliser une transaction immobilière et se retrouve prisonnier du château du comte. Pendant ce temps à Londres, des événements étranges affectent la jeune Lucy Westenra. Van Helsing, un savant néerlandais expert en vampirisme, rassemble un groupe de héros pour traquer et détruire le monstre. Roman épistolaire haletant qui a fondé le mythe du vampire moderne, Dracula est un chef-d\'œuvre du roman gothique victorien.', 1897, 'https://covers.openlibrary.org/b/title/Dracula-L.jpg', '2026-04-02 13:52:41'),
(118, 'Frankenstein', 'Mary Shelley', 'Horreur', 'Victor Frankenstein, jeune savant genevois passionné de sciences naturelles, réussit l\'exploit de donner vie à une créature assemblée à partir de morceaux de cadavres. Mais horrifié par sa création, il l\'abandonne aussitôt. La créature, rejetée par tous en raison de son apparence monstrueuse, développe une intelligence et une sensibilité profondes, mais aussi une soif de vengeance contre son créateur qui l\'a abandonné sans amour ni éducation. Elle exige de Frankenstein qu\'il lui crée une compagne. Un roman philosophique fondateur de la science-fiction qui interroge les limites de la science, la responsabilité du créateur envers sa créature et la nature de l\'humanité.', 1818, 'https://covers.openlibrary.org/b/title/Frankenstein-L.jpg', '2026-04-02 13:52:41'),
(119, 'Le Portrait de Dorian Gray', 'Oscar Wilde', 'Roman', 'Dorian Gray, un jeune homme d\'une beauté exceptionnelle, pose pour le peintre Basil Hallward qui réalise un portrait extraordinaire. Sous l\'influence du cynique et brillant Lord Henry Wotton, Dorian formule le vœu que ce soit le portrait qui vieillisse à sa place. Son vœu est exaucé de manière mystérieuse. Libre de tout vieillissement et de toute trace visible de ses péchés, Dorian se plonge dans une vie de débauche et de cruauté, tandis que son portrait devient de plus en plus hideux. Un roman philosophique sur la vanité, la corruption de l\'âme, la dualité du bien et du mal et le prix de l\'immortalité et de la beauté éternelle.', 1890, 'https://covers.openlibrary.org/b/title/Le%20Portrait%20de%20Dorian%20Gray-L.jpg', '2026-04-02 13:52:41'),
(120, 'L\'Étrange Cas du Dr Jekyll et de M. Hyde', 'Robert Louis Stevenson', 'Horreur', 'Le Dr Jekyll développe une potion qui libère son côté sombre sous les traits de M. Hyde.', 1886, 'https://covers.openlibrary.org/b/title/L\'Étrange%20Cas%20du%20Dr%20Jekyll%20et%20de%20M.%20Hyde-L.jpg', '2026-04-02 13:52:41'),
(121, 'Le Moine', 'Matthew Lewis', 'Horreur', 'Un moine espagnol tombe dans la corruption et le crime après avoir été séduit par le diable.', 1796, 'https://covers.openlibrary.org/b/title/Le%20Moine-L.jpg', '2026-04-02 13:52:41'),
(122, 'Les Âmes Mortes', 'Nicolas Gogol', 'Roman', 'Tchitchikov voyage de domaine en domaine pour acheter des serfs décédés afin de spéculer.', 1842, 'https://covers.openlibrary.org/b/title/Les%20Âmes%20Mortes-L.jpg', '2026-04-02 13:52:41'),
(123, 'Le Manteau', 'Nicolas Gogol', 'Nouvelle', 'Akaki Akakiévitch Bachmatchkine est un petit fonctionnaire de Saint-Pétersbourg d\'une insignifiance totale, dont le seul bonheur est de recopier des documents administratifs. Son vieux manteau est tellement usé qu\'il laisse passer le froid de l\'hiver russe. Pour en acheter un neuf, il économise pendant des mois sur sa maigre nourriture, vivant dans une attente fiévreuse. Le jour où il l\'obtient enfin, il est agressé et dépouillé de son manteau dans la rue. Il tente d\'obtenir justice auprès d\'un personnage important qui l\'humilie et le renvoie. Akaki meurt de chagrin et de froid. Son fantôme erre dans les rues de Saint-Pétersbourg et arrache les manteaux des passants. Nouvelle courte mais d\'une portée immense sur la bureaucratie, la déshumanisation et la condition des petites gens dans la Russie tsariste. Gogol mêle réalisme social et fantastique avec un génie incomparable.', 1842, 'https://covers.openlibrary.org/b/title/Le%20Manteau-L.jpg', '2026-04-02 13:52:41'),
(124, 'L\'Idiot', 'Fiodor Dostoïevski', 'Roman', 'Le prince Lev Nicolaïevitch Mychkine revient en Russie après plusieurs années passées en Suisse dans un sanatorium pour épileptiques. D\'une bonté et d\'une innocence absolues, incapable de mentir ou de dissimuler, il est immédiatement surnommé l\'Idiot par la société de Saint-Pétersbourg qu\'il intègre. Il est partagé entre son amour pour la belle et torturée Nastassia Filippovna et la pure Aglaïa Ivolguina. Sa bonté angélique, incomprise dans un monde corrompu, déclenche autour de lui jalousie, violence et folie. Dostoïevski voulait dépeindre un homme véritablement bon dans le monde réel. Le résultat est un roman d\'une profondeur psychologique extraordinaire.', 1869, 'https://covers.openlibrary.org/b/title/L\'Idiot-L.jpg', '2026-04-02 13:52:41'),
(125, 'Les Frères Karamazov', 'Fiodor Dostoïevski', 'Roman', 'Les frères Karamazov sont trois fils d\'un père débauché et indigne, Fiodor Karamazov. Dimitri, l\'aîné passionné et violent, est en conflit ouvert avec son père pour une question d\'héritage et de femme. Ivan, l\'intellectuel athée, développe des théories sur la liberté humaine et la non-existence de Dieu. Aliocha, le benjamin mystique, disciple du starets Zossima, essaie de réconcilier tout le monde. Quand le père est assassiné, Dimitri est accusé du meurtre. Mais qui est le véritable coupable ? Dernier et plus grand roman de Dostoïevski, Les Frères Karamazov est une somme philosophique et spirituelle sur Dieu, la liberté, la culpabilité et la rédemption.', 1880, 'https://covers.openlibrary.org/b/title/Les%20Frères%20Karamazov-L.jpg', '2026-04-02 13:52:41'),
(126, 'Les Démons', 'Fiodor Dostoïevski', 'Roman', 'Dans une ville de province russe, un groupe de jeunes nihilistes révolutionnaires gravitent autour de Stavroguine, un personnage charismatique, mystérieux et moralement corrompu qui exerce une fascination magnétique sur tous ceux qui l\'entourent. Piotr Verkhovenski, agitateur fanatique et cynique, manipule le groupe pour commettre un meurtre politique et cimenter leur solidarité dans le crime. Chatov, Kirilov le philosophe du suicide, Stépan Verkhovenski le père libéral pathétique — chaque personnage incarne une déviance idéologique que Dostoïevski analyse avec une lucidité prophétique. Inspiré par l\'affaire réelle Netchaïev, ce roman prédit avec une précision stupéfiante les mécanismes du terrorisme révolutionnaire et du totalitarisme. Un roman visionnaire sur les idéologies destructrices et la crise spirituelle de la Russie moderne.', 1872, 'https://covers.openlibrary.org/b/title/Les%20Démons-L.jpg', '2026-04-02 13:52:41'),
(127, 'L\'Adolescent', 'Fiodor Dostoïevski', 'Roman', 'Arkadi Dolgorouki, un jeune homme de dix-neuf ans, est le fils illégitime de Versilov, un aristocrate cultivé et torturé dont il cherche désespérément la reconnaissance et l\'amour. Arkadi arrive à Saint-Pétersbourg avec une idée fixe : devenir riche et puissant comme Rothschild pour se venger d\'un monde qui l\'a toujours regardé de haut à cause de sa bâtardise. Il se retrouve mêlé aux intrigues amoureuses et financières de son père, aux milieux révolutionnaires et aux scandales de la haute société. Sa relation avec Versilov, homme de contradictions fascinantes, est au cœur du roman. Moins connu que les autres grands romans de Dostoïevski, L\'Adolescent est néanmoins une œuvre puissante sur la quête d\'identité, la relation père-fils et la formation d\'un jeune homme dans la Russie du XIXe siècle.', 1875, 'https://covers.openlibrary.org/b/title/L\'Adolescent-L.jpg', '2026-04-02 13:52:41'),
(128, 'Humiliés et Offensés', 'Fiodor Dostoïevski', 'Roman', 'Un jeune écrivain tente d\'aider des personnes blessées par la vie dans le Saint-Pétersbourg du XIXe siècle.', 1861, 'https://covers.openlibrary.org/b/title/Humiliés%20et%20Offensés-L.jpg', '2026-04-02 13:52:41'),
(129, 'Le Joueur', 'Fiodor Dostoïevski', 'Roman', 'Alexeï, précepteur d\'un général russe, est obsédé par le jeu et une femme fatale.', 1866, 'https://covers.openlibrary.org/b/title/Le%20Joueur-L.jpg', '2026-04-02 13:52:41'),
(130, 'Le Procès', 'Franz Kafka', 'Roman', 'Josef K., directeur adjoint d\'une banque, est arrêté un matin sans raison apparente par deux agents d\'une autorité mystérieuse et anonyme. On ne lui dit pas de quoi il est accusé. Il tente de comprendre ce qui lui arrive, consulte des avocats, se rend dans des tribunaux labyrinthiques installés dans des greniers, rencontre des personnages absurdes et impuissants. Plus il essaie de se défendre, plus il semble s\'enfoncer dans la culpabilité. Kafka crée avec ce roman une atmosphère de cauchemar bureaucratique qui explore l\'impuissance de l\'individu face aux institutions, l\'aliénation moderne et la culpabilité existentielle. Une œuvre d\'une modernité troublante, plus pertinente que jamais.', 1925, 'https://covers.openlibrary.org/b/title/Le%20Procès-L.jpg', '2026-04-02 13:52:41'),
(131, 'Le Château', 'Franz Kafka', 'Roman', 'K. arrive dans un village dominé par un château et tente en vain d\'y entrer.', 1926, 'https://covers.openlibrary.org/b/title/Le%20Château-L.jpg', '2026-04-02 13:52:41'),
(132, 'La Métamorphose', 'Franz Kafka', 'Nouvelle', 'Gregor Samsa, représentant de commerce qui travaille dur pour rembourser les dettes de sa famille, se réveille un matin métamorphosé en énorme insecte. Incapable de travailler, de communiquer normalement et devenu une source de honte et de gêne, il observe avec une lucidité douloureuse comment sa famille réagit à sa transformation : d\'abord la consternation et la pitié, puis l\'habitude, l\'indifférence et finalement le rejet. Sa sœur Grete, qui s\'occupait de lui au début, finit par réclamer sa disparition. Une nouvelle métaphorique d\'une puissance extraordinaire sur l\'aliénation, la déshumanisation, la famille et la condition de celui qui ne peut plus être utile aux autres.', 1915, 'https://covers.openlibrary.org/b/title/La%20Métamorphose-L.jpg', '2026-04-02 13:52:41'),
(133, 'La Montagne Magique', 'Thomas Mann', 'Roman', 'Hans Castorp, jeune ingénieur hambourgeois sans grands projets, monte dans un sanatorium des Alpes suisses pour rendre visite à son cousin Joachim, malade de la tuberculose. Il devait rester trois semaines. Il reste sept ans. Le Berghof devient un microcosme de l\'Europe d\'avant 1914 où s\'affrontent des idéologies, des tempéraments et des visions du monde. Le professeur Settembrini, humaniste rationaliste et progressiste, s\'oppose à Naphta, jésuite nihiliste et autoritaire, dans des joutes philosophiques interminables. Hans, passif et curieux, absorbe tout et tombe amoureux de la mystérieuse Madame Chauchat. Le temps au Berghof est suspendu, dilaté, différent du temps du monde ordinaire. Thomas Mann fait du roman le véhicule d\'une réflexion encyclopédique sur le temps, la maladie, la mort, la politique et la culture européenne à la veille de son effondrement.', 1924, 'https://covers.openlibrary.org/b/title/La%20Montagne%20Magique-L.jpg', '2026-04-02 13:52:41'),
(134, 'Les Buddenbrook', 'Thomas Mann', 'Roman', 'Les Buddenbrook raconte la déclin d\'une grande famille de marchands hanséatiques de Lübeck sur quatre générations, de 1835 à 1877. Johann Buddenbrook, le fondateur prospère, cède la place à son fils le consul, puis à son petit-fils Tom, homme d\'affaires rigoureux mais rongé par le doute, et enfin au petit Hanno, enfant sensible et musicalement doué qui incarne la fin de la lignée. À mesure que la famille s\'élève culturellement et spirituellement — grâce à la musique, à la philosophie schopenhauérienne — elle perd sa vitalité commerciale et biologique. Thomas Mann démontre que la sensibilité artistique et l\'énergie bourgeoise sont incompatibles : l\'art tue le commerce, la culture tue la vie. Premier grand roman de Mann, publié à vingt-cinq ans, il lui vaudra le Prix Nobel de littérature en 1929. Un chef-d\'œuvre du roman réaliste allemand.', 1901, 'https://covers.openlibrary.org/b/title/Les%20Buddenbrook-L.jpg', '2026-04-02 13:52:41'),
(135, 'L\'Homme sans Qualités', 'Robert Musil', 'Roman', 'Ulrich, un homme sans qualités, observe la société austro-hongroise à la veille de la guerre.', 1930, 'https://covers.openlibrary.org/b/title/L\'Homme%20sans%20Qualités-L.jpg', '2026-04-02 13:52:41'),
(136, 'Ulysse', 'James Joyce', 'Roman', 'Leopold Bloom, un Juif irlandais vendeur d\'espaces publicitaires, parcourt Dublin le 16 juin 1904, date qui deviendra le Bloomsday célébré chaque année dans le monde entier. En parallèle, Stephen Dedalus, jeune intellectuel et alter ego de Joyce, erre lui aussi dans la ville. Leurs chemins se croisent le soir dans un bordel. Joyce révolutionne la technique romanesque avec le monologue intérieur, reproduisant le flux de conscience de ses personnages avec une précision et une liberté formelle jamais atteintes. Roman expérimental d\'une richesse extraordinaire, Ulysse est souvent considéré comme le roman le plus important du XXe siècle, une recréation moderne de l\'Odyssée d\'Homère.', 1922, 'https://covers.openlibrary.org/b/title/Ulysse-L.jpg', '2026-04-02 13:52:41'),
(137, 'Mrs Dalloway', 'Virginia Woolf', 'Roman', 'Clarrissa Dalloway prépare une soirée qu\'elle donne le soir même dans sa maison londonienne. La narration suit en parallèle Septimus Warren Smith, un ancien combattant traumatisé par la guerre qui souffre de graves troubles psychologiques. Virginia Woolf révolutionne la technique romanesque en plongeant le lecteur dans le flux de conscience de ses personnages, faisant coexister souvenirs du passé, perceptions du présent et réflexions intérieures dans une prose poétique d\'une beauté rare. En une seule journée de juin à Londres, Woolf explore les thèmes de la mémoire, de l\'identité féminine, de la folie, de la mort et du temps qui passe. Un chef-d\'œuvre du modernisme anglais.', 1925, 'https://covers.openlibrary.org/b/title/Mrs%20Dalloway-L.jpg', '2026-04-02 13:52:41'),
(138, 'Vers le Phare', 'Virginia Woolf', 'Roman', 'La famille Ramsay séjourne dans leur maison de vacances en Écosse. Leur fils James, six ans, désire ardemment visiter le phare qui se profile au loin, mais son père affirme que le temps ne le permettra pas. Dix ans plus tard, après la mort de Mrs Ramsay et la guerre, une visite au phare a finalement lieu. Entre ces deux moments, la peintre Lily Briscoe lutte pour achever son tableau. Woolf explore avec une sensibilité extraordinaire le temps, la mémoire, la mort, la création artistique et les relations humaines à travers le flux de conscience de ses personnages. Un roman d\'une beauté formelle et d\'une profondeur émotionnelle rares, considéré comme l\'un des plus grands du XXe siècle.', 1927, 'https://covers.openlibrary.org/b/title/Vers%20le%20Phare-L.jpg', '2026-04-02 13:52:41'),
(139, 'Les Vagues', 'Virginia Woolf', 'Roman', 'Six personnages racontent leur vie intérieure depuis l\'enfance jusqu\'à la vieillesse.', 1931, 'https://covers.openlibrary.org/b/title/Les%20Vagues-L.jpg', '2026-04-02 13:52:41'),
(140, 'Le Bruit et la Fureur', 'William Faulkner', 'Roman', 'La famille Compson du Mississippi vit sa déchéance sur trois générations à travers quatre voix narratives distinctes. Benjy, un adulte au développement mental d\'un enfant, raconte ses souvenirs de manière non linéaire et fragmentée. Quentin, étudiant à Harvard, est hanté par l\'honneur perdu de sa famille et l\'amour impossible pour sa sœur Caddy. Jason, le frère cynique et amer, gère les affaires familiales avec une cruauté froide. Dilsey, la servante noire, incarne la dignité et la résilience. Faulkner révolutionne la technique narrative avec ce roman expérimental sur la désintégration d\'une famille sudiste, la perte des illusions et le poids du passé américain.', 1929, 'https://covers.openlibrary.org/b/title/Le%20Bruit%20et%20la%20Fureur-L.jpg', '2026-04-02 13:52:41'),
(141, 'Tandis que j\'Agonise', 'William Faulkner', 'Roman', 'La famille Bundren vit dans les collines du Mississippi. Addie Bundren, la mère, meurt en faisant promettre à son mari Anse de l\'enterrer dans sa ville natale de Jefferson, à des kilomètres de leur ferme. Anse, les quatre fils — Cash le charpentier, Darl le visionnaire, Jewel le passionné, Vardaman l\'enfant — et la fille Dewey Dell entreprennent un voyage épique et cauchemardesque pour honorer cette promesse. Le cercueil traverse des rivières en crue, une maison en feu, des routes défoncées. Chaque membre de la famille a ses propres motivations secrètes pour ce voyage. Faulkner utilise une technique narrative révolutionnaire : quinze voix différentes se relaient pour raconter l\'histoire, chacune avec son style et sa vision propres. Un roman sur la mort, la famille, l\'obstination humaine et la décomposition — au sens propre comme au figuré.', 1930, 'https://covers.openlibrary.org/b/title/Tandis%20que%20j\'Agonise-L.jpg', '2026-04-02 13:52:41'),
(142, 'Sanctuaire', 'William Faulkner', 'Roman', 'Temple Drake, une jeune étudiante, est enlevée et violentée par des bootleggers.', 1931, 'https://covers.openlibrary.org/b/title/Sanctuaire-L.jpg', '2026-04-02 13:52:41'),
(143, 'L\'Attrape-Cœurs', 'J.D. Salinger', 'Roman', 'Holden Caulfield, seize ans, vient d\'être renvoyé de son quatrième lycée pour mauvais résultats. Au lieu de rentrer chez ses parents à New York, il erre pendant trois jours dans la ville, observant le monde des adultes avec un mélange de fascination et de dégoût profond. Il appelle les adultes des imposteurs et aspire à protéger les enfants de la corruption du monde adulte, voulant être leur attrape-cœurs dans un champ de seigle. Il retrouve sa petite sœur Phoebe, la seule personne qu\'il aime vraiment. Roman culte de la littérature américaine, L\'Attrape-Cœurs capture avec une authenticité bouleversante l\'aliénation adolescente, la peur de grandir et la recherche d\'authenticité dans un monde jugé hypocrite.', 1951, 'https://covers.openlibrary.org/b/title/L\'Attrape-Cœurs-L.jpg', '2026-04-02 13:52:41'),
(144, 'Sur la Route', 'Jack Kerouac', 'Roman', 'Sal Paradise, alter ego de Kerouac, et Dean Moriarty, personnage inspiré du vrai Neal Cassady, incarnent la génération Beat dans une série de road trips effrénés à travers l\'Amérique des années 1940. De New York à San Francisco, de Denver à La Nouvelle-Orléans, de Chicago au Mexique, ils cherchent l\'extase, la liberté, le jazz, les rencontres et l\'expérience pure de la vie. Écrit en trois semaines sur un rouleau de papier de trente mètres, le roman capture avec une énergie et une sincérité brutes l\'esprit d\'une génération en rupture avec les valeurs bourgeoises. Un manifeste de la liberté, de l\'errance et de la quête de sens dans l\'Amérique d\'après-guerre.', 1957, 'https://covers.openlibrary.org/b/title/Sur%20la%20Route-L.jpg', '2026-04-02 13:52:41'),
(145, 'Le Festin Nu', 'William S. Burroughs', 'Roman', 'Récit fragmenté et hallucinatoire de la vie d\'un junkie.', 1959, 'https://covers.openlibrary.org/b/title/Le%20Festin%20Nu-L.jpg', '2026-04-02 13:52:41'),
(146, 'Lolita', 'Vladimir Nabokov', 'Roman', 'Humbert Humbert, un intellectuel européen raffiné et pédophile, tombe éperdument amoureux de Dolores Haze, une fillette de douze ans qu\'il surnomme Lolita. Pour rester proche d\'elle, il épouse sa mère. Après la mort accidentelle de celle-ci, il emmène Lolita à travers l\'Amérique dans une fuite en avant, se comportant comme son père tout en abusant d\'elle. La jeune fille lui échappe finalement avec l\'auteur dramatique Quilty. Des années plus tard, Humbert retrouve Lolita, devenue adulte et méconnaissable. Nabokov crée un narrateur à la fois charmant et monstrueux dont la prose lyrique cache une réalité sordide. Un roman controversé et fascinant sur la manipulation, l\'obsession et la destruction d\'une enfance.', 1955, 'https://covers.openlibrary.org/b/title/Lolita-L.jpg', '2026-04-02 13:52:41'),
(147, 'Feu Pâle', 'Vladimir Nabokov', 'Roman', 'Un poème de 999 vers et un commentaire délirant composent ce roman expérimental.', 1962, 'https://covers.openlibrary.org/b/title/Feu%20Pâle-L.jpg', '2026-04-02 13:52:41'),
(148, 'Le Don', 'Vladimir Nabokov', 'Roman', 'Un jeune poète russe émigré à Berlin développe son art et son amour.', 1938, 'https://covers.openlibrary.org/b/title/Le%20Don-L.jpg', '2026-04-02 13:52:41'),
(149, 'Cent Ans de Solitude', 'Gabriel García Márquez', 'Réalisme magique', 'La famille Buendía fonde la ville de Macondo au milieu d\'une jungle luxuriante en Colombie. Sur sept générations, Márquez trace la saga de cette famille et de cette ville depuis sa fondation jusqu\'à sa destruction apocalyptique, prédit dans les manuscrits cryptés du gitan Melquíades. Les membres de la famille portent tous les mêmes prénoms, José Arcadio ou Aureliano, et semblent condamnés à répéter les mêmes erreurs et les mêmes folies génération après génération. Le réalisme magique de Márquez mêle avec une fluidité extraordinaire le quotidien et le merveilleux, le réel et le fantastique. Un roman fleuve d\'une richesse et d\'une inventivité incomparables, prix Nobel de littérature.', 1967, 'https://covers.openlibrary.org/b/title/Cent%20Ans%20de%20Solitude-L.jpg', '2026-04-02 13:52:41'),
(150, 'L\'Amour au Temps du Choléra', 'Gabriel García Márquez', 'Roman', 'Florentino Ariza attend plus de cinquante ans pour retrouver son amour de jeunesse.', 1985, 'https://covers.openlibrary.org/b/title/L\'Amour%20au%20Temps%20du%20Choléra-L.jpg', '2026-04-02 13:52:41'),
(151, 'Le Colonel n\'a Personne pour lui Écrire', 'Gabriel García Márquez', 'Nouvelle', 'Un vieux colonel attend depuis quinze ans une pension militaire qui ne vient jamais.', 1961, 'https://covers.openlibrary.org/b/title/Le%20Colonel%20n\'a%20Personne%20pour%20lui%20Écrire-L.jpg', '2026-04-02 13:52:41'),
(152, 'La Maison aux Esprits', 'Isabel Allende', 'Réalisme magique', 'Blanche Trueba, dotée du don de clairvoyance, épouse Esteban Trueba, un propriétaire terrien autoritaire au Chili. Leur fille Clara hérite des dons de voyance de sa grand-mère. La saga familiale se déroule sur plusieurs générations, de la fin du XIXe siècle jusqu\'au coup d\'État militaire de 1973 qui renverse le président Salvador Allende. Isabel Allende, nièce du président assassiné, mêle réalisme magique et histoire politique pour raconter la condition des femmes, les injustices sociales et les traumatismes de la dictature chilienne. Un roman bouleversant sur la mémoire, la résistance et la transmission entre les générations de femmes d\'une même famille.', 1982, 'https://covers.openlibrary.org/b/title/La%20Maison%20aux%20Esprits-L.jpg', '2026-04-02 13:52:41'),
(153, 'Comme l\'Eau pour le Chocolat', 'Laura Esquivel', 'Réalisme magique', 'Tita, la benjamine de la famille De la Garza au Mexique révolutionnaire du début du XXe siècle, est condamnée par la tradition à rester célibataire pour s\'occuper de sa mère jusqu\'à sa mort. Elle ne peut donc pas épouser Pedro, l\'homme qu\'elle aime, qui épouse à la place sa sœur Rosaura pour rester proche de Tita. La seule façon pour Tita d\'exprimer ses émotions est à travers la cuisine : ses larmes salent le gâteau de mariage, son désir transforme les roses en aphrodisiaque, sa tristesse rend tout le monde malade. Un roman sensuel et poétique sur l\'amour impossible, la liberté, la tradition et le pouvoir des émotions transmises à travers la nourriture.', 1989, 'https://covers.openlibrary.org/b/title/Comme%20l\'Eau%20pour%20le%20Chocolat-L.jpg', '2026-04-02 13:52:41'),
(154, 'Ficciones', 'Jorge Luis Borges', 'Nouvelles', 'Recueil de dix-sept nouvelles fantastiques qui constituent l\'une des œuvres les plus originales et influentes de la littérature du XXe siècle. Borges y explore des univers labyrinthiques et des paradoxes métaphysiques : une bibliothèque infinie contenant tous les livres possibles, un jardin aux sentiers qui bifurquent et représente tous les futurs possibles simultanément, un homme condamné à tout mémoriser, une loterie qui régit tous les aspects de la vie. Avec une érudition et une ironie incomparables, Borges invente une forme littéraire nouvelle qui mêle essai philosophique, conte fantastique et jeu intellectuel. Une influence majeure sur toute la littérature postmoderne mondiale.', 1944, 'https://covers.openlibrary.org/b/title/Ficciones-L.jpg', '2026-04-02 13:52:41'),
(155, 'Pedro Páramo', 'Juan Rulfo', 'Roman', 'Juan Preciado arrive dans le village de Comala au Mexique pour retrouver son père Pedro Páramo, un cacique brutal et puissant dont sa mère lui avait parlé avant de mourir. Mais Comala est un village fantôme peuplé uniquement de murmures et de voix de morts. Juan lui-même meurt rapidement et continue de raconter son histoire depuis sa tombe. Les voix des morts se mêlent pour reconstituer l\'histoire de Pedro Páramo, de son amour absolu pour Susana San Juan et de la destruction qu\'il a semée autour de lui. Roman court et dense, Pedro Páramo est une révolution formelle qui a profondément influencé García Márquez et toute la littérature latino-américaine du boom.', 1955, 'https://covers.openlibrary.org/b/title/Pedro%20Páramo-L.jpg', '2026-04-02 13:52:41'),
(156, 'Le Nom de la Rose', 'Umberto Eco', 'Roman historique', 'Umberto Eco mêle polar médiéval et roman philosophique dans cette enquête captivante. En l\'an 1327, le moine franciscain Guillaume de Baskerville, accompagné de son novice Adso de Melk, arrive dans une abbaye bénédictine du nord de l\'Italie pour assister à un débat théologique. Mais une série de morts mystérieuses frappe les moines, toutes liées semble-t-il à la bibliothèque labyrinthique de l\'abbaye où se cache un livre interdit. Avec ses méthodes d\'investigation proches de celles de Sherlock Holmes, Guillaume tente de résoudre l\'énigme. Un roman érudit et fascinant sur la connaissance, la censure, le rire et le pouvoir de l\'Église au Moyen Âge.', 1980, 'https://covers.openlibrary.org/b/title/Le%20Nom%20de%20la%20Rose-L.jpg', '2026-04-02 13:52:41'),
(157, 'Le Pendule de Foucault', 'Umberto Eco', 'Roman', 'Casaubon, un jeune éditeur milanais, travaille avec deux collègues Belbo et Diotallevi sur des manuscrits ésotériques pour leur maison d\'édition. Par jeu intellectuel, ils décident d\'inventer un grand complot universel en reliant toutes les théories conspirationnistes de l\'histoire — Templiers, Rose-Croix, francs-maçons, Cathares — dans un Plan cohérent. Mais le Plan prend vie. Des individus mystérieux semblent avoir eu accès à leurs théories. Belbo disparaît. Le complot fictif devient réel, ou peut-être que la réalité n\'est qu\'un complot. Eco explore avec une érudition vertigineuse et un humour savant les mécanismes de la pensée conspirationniste, le désir humain de trouver des connexions secrètes derrière le chaos du monde. Un roman labyrinthique sur la paranoïa, l\'hermétisme et la construction du sens.', 1988, 'https://covers.openlibrary.org/b/title/Le%20Pendule%20de%20Foucault-L.jpg', '2026-04-02 13:52:41'),
(158, 'Si par une Nuit d\'Hiver un Voyageur', 'Italo Calvino', 'Roman', 'Le lecteur tente de lire un roman dont les chapitres sont sans cesse interrompus.', 1979, 'https://covers.openlibrary.org/b/title/Si%20par%20une%20Nuit%20d\'Hiver%20un%20Voyageur-L.jpg', '2026-04-02 13:52:41'),
(159, 'Le Baron Perché', 'Italo Calvino', 'Roman', 'Cosimo Piovasco di Rondò, douze ans, fils d\'un baron du Royaume de Ligurie au XVIIIe siècle, refuse un soir de manger des escargots au dîner familial. En signe de protestation, il monte dans un chêne du jardin et décide de ne plus jamais remettre les pieds sur terre. Tenu à sa résolution toute sa vie, il développe un mode de vie extraordinaire dans les arbres : il chasse, lit, aime, combat et philosophe sans jamais descendre. Il rencontre des brigands, des philosophes des Lumières, et tombe amoureux de la belle Violante. Un roman fable plein d\'humour et de poésie sur la liberté individuelle, la volonté et les Lumières.', 1957, 'https://covers.openlibrary.org/b/title/Le%20Baron%20Perché-L.jpg', '2026-04-02 13:52:41'),
(160, 'Siddhartha', 'Hermann Hesse', 'Roman', 'Siddhartha, fils d\'un brahmane indien de haute caste, mène une vie confortable mais ressent un profond vide spirituel. Avec son ami Govinda, il quitte sa famille pour rejoindre les Samanas, des ascètes errants. Puis il rencontre Bouddha lui-même mais refuse de le suivre, voulant trouver sa propre vérité. Il plonge dans le monde des plaisirs avec la courtisane Kamala et devient un riche marchand. Écœuré par cette vie matérielle, il repart en pèlerinage et trouve la paix en devenant passeur sur une rivière, dont il apprend à écouter la voix. Un roman initiatique sur la quête spirituelle, la sagesse et l\'unité de toutes choses, écrit avec une prose d\'une beauté et d\'une sérénité remarquables.', 1922, 'https://covers.openlibrary.org/b/title/Siddhartha-L.jpg', '2026-04-02 13:52:41'),
(161, 'Le Loup des Steppes', 'Hermann Hesse', 'Roman', 'Harry Haller, intellectuel allemand de la cinquantaine en crise profonde, se sent étranger au monde bourgeois qui l\'entoure. Il se perçoit comme un loup des steppes, mi-homme mi-bête sauvage, incapable de s\'intégrer à la société. Sa rencontre avec la mystérieuse Hermine, puis avec Maria et le musicien Pablo, va l\'entraîner dans une descente dans ses propres profondeurs à travers le Théâtre Magique. Une exploration psychédélique et jungienne des multiples personnalités qui composent un être humain. Hesse, lui-même en crise lors de l\'écriture du roman, signe une œuvre autobiographique sur la dualité de la nature humaine et la quête d\'un équilibre entre instinct et raison.', 1927, 'https://covers.openlibrary.org/b/title/Le%20Loup%20des%20Steppes-L.jpg', '2026-04-02 13:52:41'),
(162, 'Narcisse et Goldmund', 'Hermann Hesse', 'Roman', 'Narcisse et Goldmund sont deux amis aux tempéraments radicalement opposés dans l\'Allemagne médiévale. Narcisse est un moine érudit et ascète, voué à la contemplation intellectuelle et spirituelle. Goldmund, son disciple, est un artiste sensuel attiré par la beauté du monde, les femmes et l\'errance. Après avoir quitté le monastère, Goldmund erre pendant des années à travers l\'Europe médiévale ravagée par la peste, vivant d\'amours fugaces et d\'aventures, sculptant des œuvres magnifiques. Leur amitié traverse le temps et les séparations. Hesse explore à travers ces deux figures la dualité fondamentale de la nature humaine entre esprit et matière, contemplation et action.', 1930, 'https://covers.openlibrary.org/b/title/Narcisse%20et%20Goldmund-L.jpg', '2026-04-02 13:52:41'),
(163, 'L\'Alchimiste', 'Paulo Coelho', 'Roman', 'Santiago est un jeune berger andalou qui parcourt les plaines d\'Espagne avec ses moutons. Il fait un rêve récurrent d\'un trésor caché près des pyramides d\'Égypte. Une vieille gitane et un mystérieux vieillard qui se présente comme le roi de Salem l\'encouragent à suivre sa Légende Personnelle — son destin unique et particulier. Il vend son troupeau et traverse l\'Espagne, puis l\'Afrique du Nord, travaille pour un marchand de cristaux, traverse le désert avec une caravane, s\'arrête dans une oasis où il tombe amoureux de Fatima et rencontre un alchimiste qui lui enseigne à lire les signes du destin. Une fable philosophique universelle sur le courage de suivre ses rêves, l\'écoute de son cœur et le sens de la vie.', 1988, 'https://covers.openlibrary.org/b/title/L\'Alchimiste-L.jpg', '2026-04-02 13:52:41'),
(164, 'Veronika Decide de Mourir', 'Paulo Coelho', 'Roman', 'Veronika a vingt-quatre ans, est belle, a du travail et des amis à Ljubljana en Slovénie. Mais elle décide de mourir, non par malheur particulier, mais parce qu\'elle ne voit pas l\'intérêt de continuer une vie qui ne lui apporte rien de nouveau. Elle avale des somnifères mais survit et se retrouve dans un asile psychiatrique, Villete. Les médecins lui annoncent qu\'elle a irrémédiablement endommagé son cœur et n\'a plus que quelques jours à vivre. Cette condamnation paradoxale va l\'amener à vivre enfin pleinement, à explorer la folie des autres internés et à découvrir ce qu\'elle voulait vraiment de la vie. Un roman sur la liberté, le conformisme et le courage de vivre différemment.', 1998, 'https://covers.openlibrary.org/b/title/Veronika%20Decide%20de%20Mourir-L.jpg', '2026-04-02 13:52:41'),
(165, 'La Valse Lente des Tortues', 'Katherine Pancol', 'Roman', 'Joséphine Cortès, historienne médiéviste brillante mais naïve, voit sa vie s\'effondrer quand son mari Philippe la quitte pour sa meilleure amie Iris, femme superficielle mais séduisante. Joséphine se retrouve seule avec ses deux filles dans un appartement modeste, sans argent. Par hasard, elle écrit un roman historique médiéval qui devient un best-seller mondial sous le nom de plume d\'Iris. Mais le succès appartient à Iris qui en tire toute la gloire sociale. Joséphine doit gérer cette injustice tout en continuant à écrire pour survivre. Pancol poursuit avec ce deuxième tome la saga de Joséphine, qui s\'affirme progressivement dans une société qui préfère les apparences à la substance. Un roman populaire et attachant sur l\'estime de soi, la jalousie féminine et le droit d\'exister pour ce qu\'on est vraiment.', 2008, 'https://covers.openlibrary.org/b/title/La%20Valse%20Lente%20des%20Tortues-L.jpg', '2026-04-02 13:52:41'),
(166, 'Les Yeux Jaunes des Crocodiles', 'Katherine Pancol', 'Roman', 'Deux sœurs aux destins opposés évoluent dans le Paris contemporain.', 2006, 'https://covers.openlibrary.org/b/title/Les%20Yeux%20Jaunes%20des%20Crocodiles-L.jpg', '2026-04-02 13:52:41'),
(167, 'Le Quatrième Mur', 'Sorj Chalandon', 'Roman', 'Georges tente de monter Antigone à Beyrouth pendant la guerre civile libanaise.', 2013, 'https://covers.openlibrary.org/b/title/Le%20Quatrième%20Mur-L.jpg', '2026-04-02 13:52:41'),
(168, 'Au Revoir là-Haut', 'Pierre Lemaitre', 'Roman historique', 'Édouard et Albert se retrouvent dans un trou d\'obus le 2 novembre 1918, à quelques jours de l\'Armistice. Albert sauve la vie d\'Édouard mais celui-ci perd la moitié du visage. Revenus à Paris défigurés et traumatisés, ces deux survivants sont abandonnés par une société qui ne veut pas voir ses morts et ses mutilés. Pour survivre, ils montent une escroquerie aux monuments aux morts : vendre à des communes et des familles des monuments funéraires qui ne seront jamais livrés. L\'arnaque est grandiose et poétique — Édouard crée des projets farfelus et magnifiques. En parallèle, un officier corrompu et lâche, Pradelle, s\'enrichit scandaleusement en vendant des concessions de cimetières militaires. Lemaitre dresse un portrait amer et flamboyant de la France de l\'après-guerre qui préfère oublier ses soldats. Prix Goncourt 2013.', 2013, 'https://covers.openlibrary.org/b/title/Au%20Revoir%20là-Haut-L.jpg', '2026-04-02 13:52:41'),
(169, 'Chanson Douce', 'Leïla Slimani', 'Roman', 'Une nounou parfaite tue les enfants dont elle s\'occupe dans une famille parisienne.', 2016, 'https://covers.openlibrary.org/b/title/Chanson%20Douce-L.jpg', '2026-04-02 13:52:41'),
(170, 'Réparer les Vivants', 'Maylis de Kerangal', 'Roman', 'La transplantation cardiaque d\'un jeune surfeur racontée en une seule journée.', 2014, 'https://covers.openlibrary.org/b/title/Réparer%20les%20Vivants-L.jpg', '2026-04-02 13:52:41'),
(171, 'Leurs Enfants après Eux', 'Nicolas Mathieu', 'Roman', 'L\'été 1992 dans une vallée industrielle de l\'Est de la France et ses jeunes sans avenir.', 2018, 'https://covers.openlibrary.org/b/title/Leurs%20Enfants%20après%20Eux-L.jpg', '2026-04-02 13:52:41'),
(172, 'La Vérité sur l\'Affaire Harry Quebert', 'Joël Dicker', 'Policier', 'Un écrivain enquête pour innocenter son mentor accusé du meurtre d\'une adolescente.', 2012, 'https://covers.openlibrary.org/b/title/La%20Vérité%20sur%20l\'Affaire%20Harry%20Quebert-L.jpg', '2026-04-02 13:52:41'),
(173, 'Millenium : Les Hommes qui n\'Aimaient pas les Femmes', 'Stieg Larsson', 'Policier', 'Un journaliste et une hackeuse enquêtent sur la disparition d\'une jeune fille quarante ans plus tôt.', 2005, 'https://covers.openlibrary.org/b/title/Millenium%20:%20Les%20Hommes%20qui%20n\'Aimaient%20pas%20les%20Femmes-L.jpg', '2026-04-02 13:52:41'),
(174, 'Da Vinci Code', 'Dan Brown', 'Thriller', 'Robert Langdon, professeur de symbologie à Harvard, est réveillé en pleine nuit à Paris par la police : le conservateur du Louvre Jacques Saunière a été retrouvé assassiné dans la Grande Galerie, son corps mis en scène selon un rituel symbolique complexe. Avec la cryptologue Sophie Neveu, petite-fille de la victime, Langdon déchiffre une série de codes et de symboles laissés par le mourant. La piste les conduit vers une vérité explosive que l\'Église catholique aurait dissimulée depuis deux mille ans : Jésus était marié à Marie-Madeleine et leur lignée a été protégée par un ordre secret. L\'Opus Dei et une autre organisation mystérieuse s\'affrontent pour contrôler cette vérité. Brown construit un thriller haletant mêlant histoire de l\'art, symbolisme, histoire des religions et action non-stop. Le roman le plus vendu du XXIe siècle, sujet de nombreuses controverses historiques et théologiques.', 2003, 'https://covers.openlibrary.org/b/title/Da%20Vinci%20Code-L.jpg', '2026-04-02 13:52:41'),
(175, 'Inferno', 'Dan Brown', 'Thriller', 'Robert Langdon se réveille dans un hôpital de Florence sans aucun souvenir des deux derniers jours. Une femme armée tente de l\'assassiner. Il s\'enfuit avec la docteure Sienna Brooks et découvre qu\'il transporte des indices menant à un complot biologique apocalyptique. Bertrand Zobrist, un milliardaire transhumaniste convaincu que la surpopulation va détruire l\'humanité, a créé un virus capable de décimer la moitié de la population mondiale, inspiré par L\'Enfer de Dante. Langdon déchiffre des références à la Divine Comédie à travers Florence, Venise et Istanbul pour retrouver le virus avant sa dissémination. Brown plonge le lecteur dans les splendeurs artistiques de la Renaissance italienne tout en maintenant un suspense haletant. Un thriller qui pose des questions éthiques vertigineuses sur la surpopulation et les limites du progrès scientifique.', 2013, 'https://covers.openlibrary.org/b/title/Inferno-L.jpg', '2026-04-02 13:52:41');
INSERT INTO `livres` (`id`, `titre`, `auteur`, `genre`, `description`, `annee`, `image`, `date_ajout`) VALUES
(176, 'Origine', 'Dan Brown', 'Thriller', 'Edmond Kirsch, futurologue de génie et milliardaire excentrique, convoque à Bilbao une présentation mondiale pour révéler ce qu\'il appelle la plus grande découverte de l\'histoire de l\'humanité : il a résolu les deux questions fondamentales de l\'existence, d\'où venons-nous et où allons-nous. Avant même de pouvoir dévoiler sa découverte, il est assassiné en direct devant des millions de téléspectateurs. Robert Langdon, présent dans la salle, s\'enfuit avec Ambra Vidal, directrice du musée Guggenheim et future épouse du roi d\'Espagne. Ensemble ils tentent de retrouver la découverte d\'Edmond avant que ses ennemis ne l\'effacent définitivement. La piste passe par la poésie de William Blake. Brown s\'interroge sur le conflit entre science et religion et sur l\'avenir de l\'humanité à l\'ère de l\'intelligence artificielle et de l\'évolution technologique.', 2017, 'https://covers.openlibrary.org/b/title/Origine-L.jpg', '2026-04-02 13:52:41'),
(177, 'La Fille du Train', 'Paula Hawkins', 'Thriller', 'Rachel Watson, divorcée et alcoolique, prend chaque matin le même train de banlieue pour aller à Londres. Elle observe par la fenêtre une maison et le couple qui y vit, qu\'elle a surnommés Jess et Jason, et à qui elle a inventé une vie parfaite. Un matin, elle voit quelque chose de troublant depuis le train. Quelques jours plus tard, Jess — en réalité Megan Hipwell — disparaît. Rachel, qui ne se souvient pas de tout ce qu\'elle a fait lors de sa dernière soirée d\'ivresse, devient malgré elle impliquée dans l\'enquête. Le roman se déroule selon trois points de vue féminins alternés : Rachel, Megan et Anna, la nouvelle femme de l\'ex-mari de Rachel. Un thriller psychologique maîtrisé qui explore la mémoire défaillante, les violences conjugales et le danger de croire ce qu\'on veut croire des apparences.', 2015, 'https://covers.openlibrary.org/b/title/La%20Fille%20du%20Train-L.jpg', '2026-04-02 13:52:41'),
(178, 'Gone Girl', 'Gillian Flynn', 'Thriller', 'Le jour de leur cinquième anniversaire de mariage, Amy Dunne disparaît de leur maison du Missouri. Son mari Nick, ancien journaliste new-yorkais reconverti en barman dans cette ville de province où il a suivi Amy, devient immédiatement le suspect numéro un aux yeux de la police et des médias. Le roman alterne entre le point de vue de Nick au présent et le journal intime d\'Amy depuis leur rencontre. Mais les deux récits se contredisent et cachent chacun leurs parts d\'ombre. Flynn déconstruit brillamment le mythe du couple parfait et du mariage idéal, révélant les mensonges et les manipulations qui peuvent empoisonner une relation. Le retournement de situation à mi-roman est l\'un des plus audacieux et des plus perturbants du thriller contemporain. Une réflexion acide sur le mariage, les médias et la construction des apparences sociales.', 2012, 'https://covers.openlibrary.org/b/title/Gone%20Girl-L.jpg', '2026-04-02 13:52:41'),
(179, 'Les Fourmis', 'Bernard Werber', 'Science-Fiction', 'Un homme hérite d\'une maison dont la cave cache une civilisation de fourmis.', 1991, 'https://covers.openlibrary.org/b/title/Les%20Fourmis-L.jpg', '2026-04-02 13:52:41'),
(180, 'Le Jour des Fourmis', 'Bernard Werber', 'Science-Fiction', 'La guerre entre fourmis et humains continue dans ce deuxième tome.', 1992, 'https://covers.openlibrary.org/b/title/Le%20Jour%20des%20Fourmis-L.jpg', '2026-04-02 13:52:41'),
(181, 'Nos Étoiles Contraires', 'John Green', 'Roman', 'Hazel Grace Lancaster, seize ans, est atteinte d\'un cancer des poumons en rémission grâce à un médicament expérimental. Elle traîne sa bouteille d\'oxygène et lit et relit un roman, An Imperial Affliction, dont la fin ouverte la hante. Sa mère l\'oblige à aller à un groupe de soutien pour jeunes cancéreux où elle rencontre Augustus Waters, dix-sept ans, en rémission d\'un ostéosarcome lui ayant coûté une jambe. Augustus est beau, drôle, et tombe immédiatement amoureux de Hazel. Ils partagent leur passion pour la littérature et s\'embarquent pour Amsterdam rencontrer l\'auteur mystérieux du roman fétiche de Hazel. Mais la maladie est toujours là. John Green réussit le tour de force d\'écrire un roman sur l\'amour et la mort sans jamais tomber dans le mélo, avec une intelligence et un humour qui rendent les personnages inoubliables.', 2012, 'https://covers.openlibrary.org/b/title/Nos%20Étoiles%20Contraires-L.jpg', '2026-04-02 13:52:41'),
(182, 'Divergente', 'Veronica Roth', 'Dystopie', 'Tris Prior vit dans une société future où Chicago est divisée en cinq factions, chacune incarnant une vertu : Abnégation, Audacieux, Érudits, Fraternels et Sincères. À seize ans, chaque adolescent doit choisir définitivement sa faction lors d\'une cérémonie. Les tests de Tris révèlent qu\'elle est Divergente, c\'est-à-dire qu\'elle possède les aptitudes de plusieurs factions, ce qui la rend dangereuse aux yeux du pouvoir. Elle choisit de rejoindre les Audacieux et découvre les dessous sombres de ce système politique. Une dystopie haletante sur l\'identité, le courage et la rébellion contre un système oppressif qui cherche à catégoriser et contrôler les individus.', 2011, 'https://covers.openlibrary.org/b/title/Divergente-L.jpg', '2026-04-02 13:52:41'),
(183, 'Hunger Games', 'Suzanne Collins', 'Dystopie', 'Dans un futur dystopique où l\'Amérique du Nord est devenue Panem, le Capitole oppresseur impose chaque année aux douze districts pauvres les Hunger Games : une émission de téléréalité mortelle où un garçon et une fille de chaque district sont tirés au sort et doivent s\'entre-tuer dans une arène jusqu\'au dernier survivant. Katniss Everdeen, seize ans, experte en chasse à l\'arc qui nourrit sa famille depuis la mort de son père, se porte volontaire pour remplacer sa petite sœur Prim tirée au sort. Avec Peeta, le garçon de son district, elle entre dans l\'arène. Mais Katniss ne se contentera pas de survivre — elle va défier les règles du jeu et allumer la flamme d\'une révolution.', 2008, 'https://covers.openlibrary.org/b/title/Hunger%20Games-L.jpg', '2026-04-02 13:52:41'),
(184, 'Le Labyrinthe', 'James Dashner', 'Dystopie', 'Thomas se réveille dans une clairière entourée de hauts murs de pierre sans aucun souvenir de son passé, à l\'exception de son prénom. Il découvre qu\'il est dans le Bloc, une communauté de garçons adolescents amnésiques qui vivent au centre d\'un gigantesque labyrinthe qui change de configuration chaque nuit. Des créatures mécaniques et mortelles, les Griffeurs, peuplent le labyrinthe. Les Coureurs s\'aventurent chaque jour dans le labyrinthe pour en cartographier les couloirs. L\'arrivée de Thomas et d\'une fille, Teresa, la première fille jamais envoyée dans le Bloc, déclenche des changements qui vont précipiter les événements. Une dystopie haletante sur la survie, la mémoire et la découverte de la vérité.', 2009, 'https://covers.openlibrary.org/b/title/Le%20Labyrinthe-L.jpg', '2026-04-02 13:52:41'),
(185, 'Twilight', 'Stephenie Meyer', 'Fantasy', 'Bella Swan, une adolescente introvertie et maladroite, quitte sa mère en Arizona pour aller vivre avec son père policier à Forks, une petite ville perpétuellement pluvieuse de l\'État de Washington. Au lycée, elle est immédiatement fascinée par Edward Cullen, un élève à la beauté surnaturelle qui semble la fuir. Elle découvre peu à peu qu\'Edward est un vampire centenaire qui lutte contre sa soif de sang humain. Malgré le danger évident, une passion intense et dévorante naît entre eux, compliquée par l\'arrivée de vampires nomades qui font de Bella leur proie. Premier tome d\'une saga romantique fantastique qui a captivé des millions de lecteurs avec son histoire d\'amour impossible.', 2005, 'https://covers.openlibrary.org/b/title/Twilight-L.jpg', '2026-04-02 13:52:41'),
(186, 'Eragon', 'Christopher Paolini', 'Fantasy', 'Eragon découvre un œuf de dragon et devient le dernier des Dragonniers.', 2003, 'https://covers.openlibrary.org/b/title/Eragon-L.jpg', '2026-04-02 13:52:41'),
(187, 'Le Trône de Fer', 'George R.R. Martin', 'Fantasy', 'Les Sept Couronnes de Westeros, un continent médiéval fantastique d\'une richesse et d\'une complexité sans égal, sont le théâtre d\'une lutte impitoyable pour le pouvoir entre les grandes maisons nobles. Quand le roi Robert Baratheon demande à son ami Eddard Stark, Seigneur de Winterfell, de devenir la Main du Roi à Port-Réal, Ned quitte le Nord glacé avec ses filles Sansa et Arya. Il découvre que le trône cache des secrets terribles et des complots mortels. La reine Cersei Lannister et son frère jumeau Jaime manœuvrent pour protéger leur pouvoir. Au-delà du Mur qui protège le royaume, des créatures oubliées se réveillent. Et de l\'autre côté de la mer, Daenerys Targaryen, héritière dépossédée du trône, prépare sa reconquête. Martin brise tous les codes de la fantasy héroïque : les héros meurent, les méchants survivent, la politique est plus meurtrière que les dragons. Une révolution du genre.', 1996, 'https://covers.openlibrary.org/b/title/Le%20Trône%20de%20Fer-L.jpg', '2026-04-02 13:52:41'),
(188, 'Ready Player One', 'Ernest Cline', 'Science-Fiction', 'Dans l\'univers futuriste de l\'OASIS, un monde virtuel massivement multijoueur créé par le génie excentrique James Halliday, le créateur a caché avant sa mort un œuf de Pâques virtuel. Celui qui le trouvera héritera de sa fortune colossale et du contrôle de l\'OASIS. Wade Watts, un adolescent pauvre qui vit dans les bidonvilles verticaux de Columbus dans l\'Ohio, se consacre entièrement à cette quête. Après des années de recherche, il découvre le premier indice. Mais la puissante corporation IOI veut aussi s\'emparer de l\'œuf pour des raisons bien moins idéalistes. Une aventure débordante de références à la culture pop des années 80 et une réflexion sur la réalité virtuelle.', 2011, 'https://covers.openlibrary.org/b/title/Ready%20Player%20One-L.jpg', '2026-04-02 13:52:41'),
(189, 'Ender\'s Game', 'Orson Scott Card', 'Science-Fiction', 'Ender Wiggin, un enfant prodige, est entraîné pour commander la flotte terrienne contre des aliens.', 1985, 'https://covers.openlibrary.org/b/title/Ender\'s%20Game-L.jpg', '2026-04-02 13:52:41'),
(190, 'Seul sur Mars', 'Andy Weir', 'Science-Fiction', 'Mark Watney, botaniste et ingénieur de la mission Mars Ares 3, est laissé pour mort sur Mars par ses coéquipiers lors d\'une violente tempête de sable. Seul sur la planète rouge avec des provisions pour quelques semaines, il doit survivre jusqu\'à la prochaine mission Mars dans quatre ans. Avec un sang-froid et un humour remarquables, il utilise ses connaissances scientifiques pour faire pousser des pommes de terre dans le sol martien, pirater les communications de la NASA et élaborer un plan de sauvetage. La NASA, de son côté, mobilise toutes ses ressources pour le ramener vivant. Un roman scientifiquement rigoureux, haletant et plein d\'humour sur la débrouillardise humaine et l\'esprit de survie.', 2011, 'https://covers.openlibrary.org/b/title/Seul%20sur%20Mars-L.jpg', '2026-04-02 13:52:41'),
(191, 'Interstellar', 'Greg Keyes', 'Science-Fiction', 'L\'adaptation du film de Christopher Nolan sur un voyage à travers les étoiles pour sauver l\'humanité.', 2014, 'https://covers.openlibrary.org/b/title/Interstellar-L.jpg', '2026-04-02 13:52:41'),
(192, 'Le Guide du Voyageur Galactique', 'Douglas Adams', 'Science-Fiction', 'Arthur Dent, un Anglais ordinaire, se réveille un jeudi matin pour découvrir que sa maison va être démolie pour construire une rocade. Avant qu\'il ait pu protester, la Terre entière est démolie par une flotte vogonne pour construire une autoroute hyperspatiale. Son ami Ford Prefect, qui s\'avère être un extraterrestre et rédacteur pour le Guide du Voyageur Galactique, le sauve in extremis. S\'ensuit un voyage à travers la galaxie plein de créatures absurdes, de planètes improbables et de philosophie loufoque. La réponse à la Grande Question sur la Vie, l\'Univers et Tout le Reste est 42. Une comédie de science-fiction brillante et hilarante, référence absolue de l\'humour britannique.', 1979, 'https://covers.openlibrary.org/b/title/Le%20Guide%20du%20Voyageur%20Galactique-L.jpg', '2026-04-02 13:52:41'),
(193, 'Chroniques Martiennes', 'Ray Bradbury', 'Science-Fiction', 'La colonisation de Mars par les humains et ses conséquences sur les Martiens.', 1950, 'https://covers.openlibrary.org/b/title/Chroniques%20Martiennes-L.jpg', '2026-04-02 13:52:41'),
(194, 'I, Robot', 'Isaac Asimov', 'Science-Fiction', 'Recueil de nouvelles explorant les Trois Lois de la Robotique et leurs implications.', 1950, 'https://covers.openlibrary.org/b/title/I,%20Robot-L.jpg', '2026-04-02 13:52:41'),
(195, 'Le Cycle de Fondation', 'Isaac Asimov', 'Science-Fiction', 'Hari Seldon crée la science de la psychohistoire pour guider l\'humanité après la chute de l\'Empire.', 1952, 'https://covers.openlibrary.org/b/title/Le%20Cycle%20de%20Fondation-L.jpg', '2026-04-02 13:52:41');
